import { useEffect, useState, lazy, Suspense, useCallback } from "react"
import { flushSync } from "react-dom"
import { GlobalDialogs } from "./components/GlobalDialogs"
import { ViewRouter } from "./components/ViewRouter"
import { Layout } from "./components/layout/Layout"
import { ToastContainer } from "./components/ui/ToastContainer"
import { DevBanner } from "./components/DevBanner"
import { SectionErrorBoundary } from "./components/ErrorBoundary"
import { logger } from "./lib/logger"
import { useLibraryStore, countActiveFilterCriteria } from "./store/libraryStore"
import { useReaderStore } from "./store/readerStore"
import { useUIStore } from "./store/uiStore"
import { useConversionStore } from "./store/conversionStore"
import { listen } from '@tauri-apps/api/event'
import { useOnboardingStore } from "./store/onboardingStore"
import { usePreferencesStore } from "./store/preferencesStore"
import { useKeyboardShortcuts } from "./hooks/useKeyboardShortcuts"
import { useDialogManager } from "./hooks/useDialogManager"
import { useBookActions } from "./hooks/useBookActions"
import { useLibraryFilter } from "./hooks/useLibraryFilter"
import { api } from "./lib/tauri"
import { useDiscordRPCUpdater } from "./hooks/useDiscordRPCUpdater"
import { useOnlineSearchStore } from "./store/onlineSearchStore"
import { AndroidSplashScreen } from "./components/ui/AndroidSplashScreen"
import { SwipeGestureHandler } from "./components/layout/SwipeGestureHandler"

const ReaderLayout = lazy(() => import("./components/reader/ReaderLayout").then(m => ({ default: m.ReaderLayout })))
const OnboardingWizard = lazy(() => import("./components/onboarding/OnboardingWizard").then(m => ({ default: m.OnboardingWizard })))
const MigrationDialog = lazy(() => import("./components/onboarding/MigrationDialog").then(m => ({ default: m.MigrationDialog })))
const OnlineMangaReader = lazy(() => import("./components/online/OnlineMangaReader").then(m => ({ default: m.OnlineMangaReader })))

const LoadingSpinner = ({ className = "h-screen" }: { className?: string }) => (
  <div className={`flex items-center justify-center ${className}`}>
    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary" />
  </div>
)

function App() {
  const [splashFinished, setSplashFinished] = useState(false)

  // ── Onboarding ──
  const onboardingComplete = useOnboardingStore(s => s.onboardingComplete)
  const isOnboardingHydrated = useOnboardingStore(s => s.isHydrated)
  const isOnboardingInitializing = useOnboardingStore(s => s.isInitializing)
  const initializeOnboarding = useOnboardingStore(s => s.initialize)
  const isPreferencesLoaded = usePreferencesStore(s => s.isLoaded)

  // ── Discord RPC ──
  useDiscordRPCUpdater()

  // ── Navigation ──
  const currentView = useUIStore(s => s.currentView)
  const currentDomain = useUIStore(s => s.currentDomain)
  const setCurrentView = useUIStore(s => s.setCurrentView)
  const setCurrentDomain = useUIStore(s => s.setCurrentDomain)
  const resetToHome = useUIStore(s => s.resetToHome)

  const preferredContentType = usePreferencesStore(s => s.preferences?.preferredContentType)

  // Enforce preferredContentType restriction
  useEffect(() => {
    if (preferredContentType === 'books') {
      if (currentDomain !== 'books') setCurrentDomain('books')
      if (currentView === 'online-manga') setCurrentView('home')
    } else if (preferredContentType === 'manga') {
      if (currentDomain !== 'manga_comics') setCurrentDomain('manga_comics')
      if (currentView === 'online-books' || currentView === 'annotations') setCurrentView('home')
    }
  }, [preferredContentType, currentDomain, currentView, setCurrentDomain, setCurrentView])

  const legacyLibraryMigrationStatus = usePreferencesStore(s => s.preferences?.legacyLibraryMigrationStatus)
  const [showMigrationDialog, setShowMigrationDialog] = useState(false)

  useEffect(() => {
    if (onboardingComplete && legacyLibraryMigrationStatus === 'unmigrated') {
      setShowMigrationDialog(true)
    }
  }, [onboardingComplete, legacyLibraryMigrationStatus])

  const handleNavigate = (view: typeof currentView) => {
    setCurrentView(view)
  }

  const handleDomainChange = (domain: typeof currentDomain) => {
    setCurrentDomain(domain)
  }

  // ── Library ──
  const loadInitialBooks = useLibraryStore(s => s.loadInitialBooks)
  const clearSelection = useLibraryStore(s => s.clearSelection)
  const activeFilters = useLibraryStore(s => s.activeFilters)
  const isReaderOpen = useReaderStore(s => s.isReaderOpen)

  // ── Search ──
  const [searchQuery, setSearchQuery] = useState("")
  const onlineBooksQuery = useOnlineSearchStore(s => s.queries['online-books'])
  const onlineMangaQuery = useOnlineSearchStore(s => s.queries['online-manga'])
  const torboxQuery = useOnlineSearchStore(s => s.queries.torbox)
  const setOnlineQuery = useOnlineSearchStore(s => s.setQuery)

  // ── Extracted hooks ──
  const { displayBooks, books } = useLibraryFilter(searchQuery)
  const { selectedBookId, handleOpenBook, handleCloseReader, handleDownloadBook, handleAutoGroupManga, autoConvert, resumeReading } = useBookActions(books)
  const dialogs = useDialogManager()

  // ── Initialization ──
  useEffect(() => { void initializeOnboarding() }, [initializeOnboarding])

  useEffect(() => {
    loadInitialBooks()
    api.getFavoriteBookIds().then(ids => {
      useLibraryStore.getState().setFavoriteBookIds(ids)
    }).catch(logger.error)
  }, [loadInitialBooks])

  useEffect(() => {
    let unlisten: (() => void) | undefined
    useConversionStore.getState().initEventListeners().then(fn => { unlisten = fn })
    return () => { unlisten?.() }
  }, [])

  useEffect(() => {
    let unlisten: (() => void) | undefined
    listen('library-updated', () => {
      api.getBooks().then(books => {
        useLibraryStore.getState().setBooks(books)
      }).catch(logger.error)
    }).then(fn => { unlisten = fn })
    return () => { unlisten?.() }
  }, [])

  // ── Search routing ──
  const handleSearchChange = (query: string) => {
    if (currentView === 'online-books') { setOnlineQuery('online-books', query); return }
    if (currentView === 'online-manga') { setOnlineQuery('online-manga', query); return }
    if (currentView === 'torbox-discover' || currentView === 'torbox-books' || currentView === 'torbox-manga') {
      setOnlineQuery('torbox', query)
      return
    }
    setSearchQuery(query)
  }

  const activeTopbarSearchQuery =
    currentView === 'online-books' ? onlineBooksQuery
    : currentView === 'online-manga' ? onlineMangaQuery
    : currentView === 'torbox-discover' || currentView === 'torbox-books' || currentView === 'torbox-manga' ? torboxQuery
    : searchQuery

  // ── Keyboard shortcuts ──
  useKeyboardShortcuts({
    'cmd+i': () => {
      const lib = useLibraryStore.getState()
      const selected = lib.selectedBook ?? (
        lib.selectedBookIds.size ? lib.books.find(b => lib.selectedBookIds.has(b.id!)) : null
      )
      if (selected?.id) dialogs.openDetailsDialog(selected.id)
    },
    'cmd+shift+m': () => dialogs.openBatchMetadataDialog(),
    'cmd+shift+f': () => dialogs.setAdvancedFilterOpen(true),
    '?': () => dialogs.setShortcutsDialogOpen(true),
    'ctrl+/': () => dialogs.setShortcutsDialogOpen(true),
  })

  // ── Book action handlers (thin wrappers that connect dialogs to actions) ──
  const handleEditBook = useCallback((bookId: number) => dialogs.openEditDialog(bookId), [dialogs])

  const handleDeleteBook = useCallback((bookId: number) => {
    const book = books.find(b => b.id === bookId)
    dialogs.openDeleteDialog(bookId, book?.title || "this book")
  }, [books, dialogs])

  const handleDeleteBooks = useCallback((bookIds: number[]) => dialogs.openDeleteMultipleDialog(bookIds), [dialogs])
  const handleViewDetails = useCallback((bookId: number) => dialogs.openDetailsDialog(bookId), [dialogs])

  // ── Render ──
  const isAppReady = isOnboardingHydrated && !isOnboardingInitializing;

  const renderContent = () => {
    if (isReaderOpen && selectedBookId) {
      return (
        <>
          <SectionErrorBoundary label="Reader">
            <Suspense fallback={<LoadingSpinner />}>
              <ReaderLayout bookId={selectedBookId} onClose={handleCloseReader} />
            </Suspense>
          </SectionErrorBoundary>
          <ToastContainer />
        </>
      )
    }

    if (currentView === 'online-manga-reader') {
      return (
        <>
          <SectionErrorBoundary label="Online Manga Reader">
            <Suspense fallback={<LoadingSpinner />}>
              <OnlineMangaReader />
            </Suspense>
          </SectionErrorBoundary>
          <ToastContainer />
        </>
      )
    }

    if (!isOnboardingHydrated || isOnboardingInitializing || !isPreferencesLoaded) {
      return <LoadingSpinner />
    }

    if (!onboardingComplete) {
      return (
        <Suspense fallback={<LoadingSpinner />}>
          <OnboardingWizard />
        </Suspense>
      )
    }

    return (
      <>
        <DevBanner />
        <Layout
          onOpenSettings={() => dialogs.setSettingsDialogOpen(true)}
          onOpenShortcuts={() => dialogs.setShortcutsDialogOpen(true)}
        onEditMetadata={handleEditBook}
        onFetchMetadata={dialogs.openBatchMetadataDialog}
        onDeleteBook={handleDeleteBook}
        onDeleteBooks={handleDeleteBooks}
        onDownloadBook={handleDownloadBook}
        onViewDetails={handleViewDetails}
        onOpenRSSFeeds={() => handleNavigate('rss-feeds')}
        onOpenRSSArticles={() => handleNavigate('rss-articles')}
        onGoHome={() => resetToHome()}
        onAutoGroupManga={handleAutoGroupManga}
        onOpenAdvancedFilter={() => dialogs.setAdvancedFilterOpen(true)}
        activeFilterCount={countActiveFilterCriteria(activeFilters)}
        searchQuery={activeTopbarSearchQuery}
        onSearchChange={handleSearchChange}
        currentView={currentView}
        onNavigateToView={handleNavigate}
        onBackToLibrary={() => handleNavigate('library')}
        currentDomain={currentDomain}
        onDomainChange={handleDomainChange}
      >
        <ViewRouter
          currentView={currentView}
          currentDomain={currentDomain}
          displayBooks={displayBooks}
          handleNavigate={handleNavigate}
          handleOpenBook={handleOpenBook}
          handleViewDetails={handleViewDetails}
          handleEditBook={handleEditBook}
          handleDeleteBook={handleDeleteBook}
          searchQuery={activeTopbarSearchQuery}
          onSearchChange={handleSearchChange}
          onOpenAdvancedFilter={() => dialogs.setAdvancedFilterOpen(true)}
          dialogs={dialogs}
        />
      </Layout>

      {/* Global Dialogs */}
      <GlobalDialogs
        books={books}
        dialogs={dialogs}
        autoConvert={autoConvert}
        resumeReading={resumeReading}
        handleOpenBook={handleOpenBook}
        handleViewDetails={handleViewDetails}
        handleEditBook={handleEditBook}
        handleDeleteBook={handleDeleteBook}
        clearSelection={clearSelection}
        loadInitialBooks={loadInitialBooks}
      />
        <Suspense fallback={null}>
          <MigrationDialog 
            open={showMigrationDialog} 
            onOpenChange={setShowMigrationDialog} 
          />
        </Suspense>
      </>
    )
  }

  return (
    <>
      {!splashFinished && (
        <AndroidSplashScreen
          isReady={isAppReady}
          onAnimationEnd={() => setSplashFinished(true)}
        />
      )}
      <SwipeGestureHandler>
        {renderContent()}
      </SwipeGestureHandler>
    </>
  )
}

export default App

import { lazy, Suspense } from "react"
import { ToastContainer } from "./ui/ToastContainer"
import { useLibraryStore } from "@/store/libraryStore"
import { api } from "@/lib/tauri"
import { Book } from "@/lib/tauri"

// Lazy load dialogs
const EditMetadataDialog = lazy(() => import("./library/EditMetadataDialog").then(m => ({ default: m.EditMetadataDialog })))
const DeleteBookDialog = lazy(() => import("./library/DeleteBookDialog").then(m => ({ default: m.DeleteBookDialog })))
const SettingsDialog = lazy(() => import("./settings/SettingsDialog").then(m => ({ default: m.SettingsDialog })))
const BookDetailsDialog = lazy(() => import("./library/BookDetailsDialog").then(m => ({ default: m.BookDetailsDialog })))
const AutoConvertDialog = lazy(() => import("./conversion/AutoConvertDialog").then(m => ({ default: m.AutoConvertDialog })))
const ConversionJobTracker = lazy(() => import("./conversion/ConversionJobTracker"))
const MetadataSearchDialog = lazy(() => import("./library/MetadataSearchDialog").then(m => ({ default: m.MetadataSearchDialog })))
const SeriesView = lazy(() => import("./library/SeriesView").then(m => ({ default: m.SeriesView })))
const AdvancedFilterDialog = lazy(() => import("./library/AdvancedFilterDialog").then(m => ({ default: m.AdvancedFilterDialog })))
const ShortcutsDialog = lazy(() => import("./dialogs/ShortcutsDialog").then(m => ({ default: m.ShortcutsDialog })))
const CommandPalette = lazy(() => import("./CommandPalette").then(m => ({ default: m.CommandPalette })))
const ResumeReadingDialog = lazy(() => import("./reader/ResumeReadingDialog").then(m => ({ default: m.ResumeReadingDialog })))

export interface GlobalDialogsProps {
  books: Book[]
  dialogs: any
  autoConvert: any
  resumeReading: any
  handleOpenBook: (id: number, location?: string) => void
  handleViewDetails: (id: number) => void
  handleEditBook: (id: number) => void
  handleDeleteBook: (id: number) => void
  clearSelection: () => void
  loadInitialBooks: () => void
}

export function GlobalDialogs({
  books,
  dialogs,
  autoConvert,
  resumeReading,
  handleOpenBook,
  handleViewDetails,
  handleEditBook,
  handleDeleteBook,
  clearSelection,
  loadInitialBooks
}: GlobalDialogsProps) {
  return (
    <>
      <Suspense fallback={null}><ConversionJobTracker /></Suspense>
      <ToastContainer />

      {dialogs.dialogBookId !== null && (
        <Suspense fallback={null}>
          <EditMetadataDialog open={dialogs.editDialogOpen} onOpenChange={dialogs.setEditDialogOpen} bookId={dialogs.dialogBookId} />
        </Suspense>
      )}

      <Suspense fallback={null}>
        <DeleteBookDialog
          open={dialogs.deleteDialogOpen}
          onOpenChange={(open) => { dialogs.setDeleteDialogOpen(open); if (!open) clearSelection() }}
          bookIds={dialogs.deleteBookIds}
          bookTitle={dialogs.dialogBookTitle}
        />
      </Suspense>

      <Suspense fallback={null}>
        <MetadataSearchDialog
          open={dialogs.batchMetadataDialogOpen}
          onOpenChange={(open) => {
            dialogs.setBatchMetadataDialogOpen(open)
            if (!open) { dialogs.setBatchMetadataBookIds([]); loadInitialBooks() }
          }}
          bookIds={dialogs.batchMetadataBookIds}
          onMetadataSelected={() => loadInitialBooks()}
        />
      </Suspense>

      {dialogs.dialogBookId !== null && (
        <Suspense fallback={null}>
          <BookDetailsDialog
            open={dialogs.detailsDialogOpen}
            onOpenChange={dialogs.setDetailsDialogOpen}
            bookId={dialogs.dialogBookId}
            onEdit={() => { dialogs.setDetailsDialogOpen(false); dialogs.setEditDialogOpen(true) }}
            onDelete={() => {
              const book = books.find(b => b.id === dialogs.dialogBookId)
              dialogs.openDeleteDialog(dialogs.dialogBookId!, book?.title || "this book")
              dialogs.setDetailsDialogOpen(false)
            }}
            onRead={() => { dialogs.setDetailsDialogOpen(false); handleOpenBook(dialogs.dialogBookId!) }}
          />
        </Suspense>
      )}

      <Suspense fallback={null}>
        <SettingsDialog open={dialogs.settingsDialogOpen} onOpenChange={dialogs.setSettingsDialogOpen} />
      </Suspense>

      {autoConvert.pendingBook && (
        <Suspense fallback={null}>
          <AutoConvertDialog
            isOpen={autoConvert.showDialog}
            onOpenChange={autoConvert.onDialogOpenChange}
            bookTitle={autoConvert.pendingBook.title}
            currentFormat={autoConvert.pendingBook.file_format}
            onConfirm={autoConvert.onConfirm}
            isConverting={autoConvert.isConverting}
          />
        </Suspense>
      )}

      {resumeReading.pendingResume && (
        <ResumeReadingDialog
          isOpen={resumeReading.showDialog}
          onOpenChange={resumeReading.onDialogOpenChange}
          bookTitle={resumeReading.pendingResume.bookTitle}
          progressPercent={resumeReading.pendingResume.progress.progressPercent}
          locationLabel={resumeReading.buildLocationLabel(resumeReading.pendingResume.progress)}
          onResume={resumeReading.onResume}
          onStartOver={resumeReading.onStartOver}
        />
      )}

      {dialogs.selectedSeries && (
        <Suspense fallback={null}>
          <SeriesView
            series={dialogs.selectedSeries}
            isOpen={dialogs.seriesViewOpen}
            onClose={() => dialogs.setSeriesViewOpen(false)}
            onSelectBook={() => {}}
            onOpenBook={handleOpenBook}
            onViewDetailsBook={handleViewDetails}
            onEditBook={handleEditBook}
            onDeleteBook={handleDeleteBook}

            onFavoriteBook={async (id) => {
              await api.toggleBookFavorite(id)
              useLibraryStore.getState().toggleFavorite(id)
            }}
            selectedBookIds={new Set()}
            favoritedBookIds={useLibraryStore.getState().favoriteBookIds}
          />
        </Suspense>
      )}

      <Suspense fallback={null}>
        <AdvancedFilterDialog open={dialogs.advancedFilterOpen} onOpenChange={dialogs.setAdvancedFilterOpen} />
      </Suspense>

      <ShortcutsDialog open={dialogs.shortcutsDialogOpen} onOpenChange={dialogs.setShortcutsDialogOpen} />

      <CommandPalette 
        books={books}
        onOpenBook={handleOpenBook}
        onImportFiles={() => {}}
        onSettings={() => dialogs.setSettingsDialogOpen(true)}
        onFetchMetadata={() => {}}
        onFindDuplicates={() => {}}
      />
    </>
  )
}

import { useState, useEffect } from "react"
import { motion } from "framer-motion"
import { Trash2, RefreshCw, XCircle, CheckSquare, Square } from "lucide-react"
import { api, BookSummary } from "../lib/tauri"
import { Button } from "./ui/button"
import { useToast } from "../store/toastStore"
import { useLibraryStore } from "../store/libraryStore"
import { logger } from "../lib/logger"
import { convertFileSrc } from '@tauri-apps/api/core'
const formatTimeAgo = (dateStr: string) => {
  const diff = Date.now() - new Date(dateStr).getTime()
  const days = Math.floor(diff / (1000 * 60 * 60 * 24))
  if (days === 0) return 'today'
  if (days === 1) return '1 day ago'
  return `${days} days ago`
}

export function RecycleBinView() {
  const [trashedBooks, setTrashedBooks] = useState<BookSummary[]>([])
  const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set())
  const [loading, setLoading] = useState(true)
  const [isActioning, setIsActioning] = useState(false)
  const { toast } = useToast()
  const loadBooks = useLibraryStore(s => s.loadInitialBooks)

  const fetchTrashedBooks = async () => {
    try {
      setLoading(true)
      setSelectedIds(new Set())
      const result = await api.searchBooks({ in_trash: true })
      setTrashedBooks(result.books)
    } catch (err) {
      logger.error("Failed to fetch trashed books", err)
      toast({
        title: "Error",
        description: "Failed to load recycle bin.",
        variant: "error",
      })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchTrashedBooks()
  }, [])

  const handleRestore = async (id: number) => {
    try {
      setIsActioning(true)
      await api.restoreBook(id)
      toast({ title: "Book Restored", description: "The book has been returned to your library." })
      await fetchTrashedBooks()
      await loadBooks()
    } catch (err) {
      logger.error("Failed to restore book", err)
      toast({ title: "Error", description: "Failed to restore book.", variant: "error" })
    } finally {
      setIsActioning(false)
    }
  }

  const handleRestoreSelected = async () => {
    if (selectedIds.size === 0) return
    try {
      setIsActioning(true)
      for (const id of selectedIds) {
        await api.restoreBook(id)
      }
      toast({ title: "Books Restored", description: `${selectedIds.size} books have been returned to your library.` })
      await fetchTrashedBooks()
      await loadBooks()
    } catch (err) {
      logger.error("Failed to restore books", err)
      toast({ title: "Error", description: "Failed to restore some books.", variant: "error" })
    } finally {
      setIsActioning(false)
    }
  }

  const handlePermanentDelete = async (id: number) => {
    try {
      setIsActioning(true)
      await api.permanentDeleteBook(id)
      toast({ title: "Book Deleted", description: "The book has been permanently deleted." })
      await fetchTrashedBooks()
    } catch (err) {
      logger.error("Failed to delete book", err)
      toast({ title: "Error", description: "Failed to permanently delete book.", variant: "error" })
    } finally {
      setIsActioning(false)
    }
  }

  const handleDeleteSelected = async () => {
    if (selectedIds.size === 0) return
    if (!window.confirm(`Are you sure you want to permanently delete ${selectedIds.size} items?`)) return
    try {
      setIsActioning(true)
      for (const id of selectedIds) {
        await api.permanentDeleteBook(id)
      }
      toast({ title: "Books Deleted", description: `${selectedIds.size} books have been permanently deleted.` })
      await fetchTrashedBooks()
    } catch (err) {
      logger.error("Failed to delete books", err)
      toast({ title: "Error", description: "Failed to delete some books.", variant: "error" })
    } finally {
      setIsActioning(false)
    }
  }

  const handleEmptyTrash = async () => {
    if (!window.confirm("Are you sure you want to empty the recycle bin? This action cannot be undone.")) return

    try {
      setIsActioning(true)
      await api.emptyTrash()
      toast({ title: "Recycle Bin Emptied", description: "All items have been permanently deleted." })
      await fetchTrashedBooks()
    } catch (err) {
      logger.error("Failed to empty trash", err)
      toast({ title: "Error", description: "Failed to empty recycle bin.", variant: "error" })
    } finally {
      setIsActioning(false)
    }
  }

  const handleSelectAll = () => {
    if (selectedIds.size === trashedBooks.length && trashedBooks.length > 0) {
      setSelectedIds(new Set())
    } else {
      setSelectedIds(new Set(trashedBooks.map(b => b.id).filter((id): id is number => id !== undefined)))
    }
  }

  const toggleSelection = (id: number) => {
    const newSelection = new Set(selectedIds)
    if (newSelection.has(id)) {
      newSelection.delete(id)
    } else {
      newSelection.add(id)
    }
    setSelectedIds(newSelection)
  }

  return (
    <div className="h-full flex flex-col p-4 md:p-6 space-y-4 md:space-y-6">
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="p-2 bg-destructive/10 text-destructive rounded-lg shrink-0">
            <Trash2 className="h-6 w-6" />
          </div>
          <div>
            <h1 className="text-xl md:text-2xl font-bold text-foreground">Recycle Bin</h1>
            <p className="text-xs md:text-sm text-muted-foreground hidden sm:block">
              Items in the recycle bin will be automatically deleted after 7 days.
            </p>
          </div>
        </div>
        <div className="flex flex-wrap sm:flex-nowrap items-center gap-2 w-full md:w-auto">
          {selectedIds.size > 0 && (
            <>
              <Button 
                variant="secondary" 
                onClick={handleRestoreSelected}
                disabled={isActioning}
                className="gap-1.5 flex-1 md:flex-none h-9 md:h-10 text-[11px] md:text-sm px-2 md:px-4"
              >
                <RefreshCw className="h-3.5 w-3.5 md:h-4 md:w-4" />
                <span className="truncate">Restore ({selectedIds.size})</span>
              </Button>
              <Button 
                variant="destructive" 
                onClick={handleDeleteSelected}
                disabled={isActioning}
                className="gap-1.5 flex-1 md:flex-none h-9 md:h-10 text-[11px] md:text-sm px-2 md:px-4"
              >
                <XCircle className="h-3.5 w-3.5 md:h-4 md:w-4" />
                <span className="truncate">Delete ({selectedIds.size})</span>
              </Button>
            </>
          )}
          <Button 
            variant="outline" 
            onClick={handleSelectAll} 
            disabled={trashedBooks.length === 0 || isActioning || loading}
            className="gap-1.5 flex-1 md:flex-none h-9 md:h-10 text-[11px] md:text-sm px-2 md:px-4"
          >
            {selectedIds.size === trashedBooks.length && trashedBooks.length > 0 ? (
              <CheckSquare className="h-3.5 w-3.5 md:h-4 md:w-4" />
            ) : (
              <Square className="h-3.5 w-3.5 md:h-4 md:w-4" />
            )}
            <span className="truncate hidden sm:inline">Select All</span>
            <span className="truncate sm:hidden">All</span>
          </Button>
          <Button 
            variant="destructive" 
            onClick={handleEmptyTrash} 
            disabled={trashedBooks.length === 0 || isActioning || loading}
            className="gap-1.5 flex-1 md:flex-none h-9 md:h-10 text-[11px] md:text-sm px-2 md:px-4"
          >
            <Trash2 className="h-3.5 w-3.5 md:h-4 md:w-4" />
            <span className="truncate hidden sm:inline">Empty Recycle Bin</span>
            <span className="truncate sm:hidden">Empty</span>
          </Button>
        </div>
      </div>

