                  <AnimatePresence>
                    {searchResults.map((result) => {
                      const isExpanded = activeModalResult?.id === result.id;
                      const isLoading = isFetchingTorrents === result.id;

                      return (
                        <motion.div 
                          layout
                          initial={{ opacity: 0, scale: 0.95 }}
                          animate={{ opacity: 1, scale: 1 }}
                          exit={{ opacity: 0, scale: 0.95 }}
                          key={result.id} 
                          className={`group flex flex-col overflow-hidden rounded-xl bg-card border shadow-sm transition-all ${isExpanded ? 'col-span-full sm:col-span-full md:col-span-full lg:col-span-full xl:col-span-full border-primary shadow-md' : 'border-border/50 hover:border-primary/50 hover:shadow-md cursor-pointer'}`}
                        >
                          <div 
                            className={`flex ${isExpanded ? 'flex-col md:flex-row gap-4 md:gap-6 p-4 md:p-6 items-start bg-muted/10 relative' : 'flex-col h-full'}`}
                            onClick={() => {
                              if (!isExpanded) fetchTorrentsForMetadata(result);
                            }}
                          >
                            <div className={`relative overflow-hidden bg-muted flex-shrink-0 ${isExpanded ? 'w-28 md:w-48 rounded-lg shadow-lg aspect-[2/3]' : 'w-full aspect-[2/3]'}`}>
                              {result.coverUrl ? (
                                <img src={result.coverUrl} alt={result.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" loading="lazy" />
                              ) : (
                                <div className="flex h-full w-full flex-col items-center justify-center gap-2 text-muted-foreground/40">
                                  <Search className="h-8 w-8 opacity-50" />
                                </div>
                              )}
                              {typeof result.rating === 'number' && !isExpanded && (
                                <div className="absolute top-2 right-2 bg-background/90 text-amber-500 text-[10px] font-bold px-1.5 py-0.5 rounded shadow-sm backdrop-blur-md">★ {(result.rating / 10).toFixed(1)}</div>
                              )}
                              {isLoading && (
                                <div className="absolute inset-0 bg-background/50 backdrop-blur-sm flex items-center justify-center z-10">
                                  <Loader2 className="w-8 h-8 animate-spin text-primary" />
                                </div>
                              )}
                            </div>

                            <div className={`flex flex-col min-w-0 ${isExpanded ? 'flex-1 pr-6 md:pr-0' : 'p-3'}`}>
                              <h3 className={`font-semibold text-foreground transition-colors group-hover:text-primary leading-snug ${isExpanded ? 'text-lg md:text-xl md:pr-8' : 'text-sm line-clamp-2'}`}>{result.title}</h3>
                              <p className={`mt-1 text-muted-foreground truncate ${isExpanded ? 'text-sm' : 'text-xs'}`}>
                                {result.year && <span>{result.year}</span>}
                                {result.year && result.author && <span className="mx-1.5 opacity-50">•</span>}
                                {result.author && <span>{result.author}</span>}
                              </p>
                              {isExpanded && result.description && <p className="mt-4 text-sm text-muted-foreground/80 leading-relaxed max-h-40 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-border scrollbar-track-transparent" dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(result.description) }} />}
                              {!isExpanded && (
                                <div className="flex flex-wrap gap-1 mt-3">
                                  {result.tags.slice(0, 2).map((tag, i) => (
                                    <Badge key={i} variant="secondary" className="px-1.5 py-0 text-[9px] bg-primary/10 text-primary border-0">{tag}</Badge>
                                  ))}
                                </div>
                              )}
                            </div>

                            {isExpanded && (
                              <Button size="icon" variant="ghost" className="absolute top-2 right-2 md:top-4 md:right-4 rounded-full bg-background/50 backdrop-blur-sm border shadow-sm z-20" onClick={(e) => { e.stopPropagation(); setActiveModalResult(null); }}>
                                <X className="w-4 h-4 md:w-5 md:h-5" />
                              </Button>
                            )}
                          </div>

                          <AnimatePresence>
                            {isExpanded && activeModalResult && (
                              <motion.div 
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: 'auto', opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                className="border-t border-border/50 bg-background/50 relative z-10"
                              >
                                <div className="p-4 md:p-6 max-h-[50vh] md:max-h-[60vh] overflow-y-auto scrollbar-thin scrollbar-thumb-border scrollbar-track-transparent">
                                  <div className="flex items-center justify-between mb-4">
                                    <h4 className="text-sm font-semibold tracking-tight">
                                      Available Torrents {isFetchingTorrents === activeModalResult.id ? '' : `(${activeModalResult.sources.length})`}
                                    </h4>
                                  </div>

                                  <div className="flex flex-col sm:flex-row items-center gap-2 mb-6">
                                    <div className="relative flex-1 w-full">
                                      <input 
                                        type="text" 
                                        placeholder="Refine search query..." 
                                        value={refineQuery}
                                        onChange={e => setRefineQuery(e.target.value)}
                                        onKeyDown={e => { if (e.key === 'Enter') fetchTorrentsForMetadata(result, refineQuery) }}
                                        className="w-full bg-background border border-border rounded-md px-4 py-2 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-primary transition-shadow"
                                      />
                                    </div>
                                    <Button 
                                      size="sm" 
                                      className="h-9 px-4 font-semibold w-full sm:w-auto"
                                      onClick={() => fetchTorrentsForMetadata(result, refineQuery)}
                                      disabled={isFetchingTorrents === activeModalResult.id}
                                    >
                                      Search
                                    </Button>
                                  </div>

                                  {isFetchingTorrents !== activeModalResult.id && activeModalResult.sources.length > 0 && (
                                    <div className="mb-4 relative">
                                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                      <input 
                                        type="text" 
                                        placeholder="Filter links..." 
                                        value={linkSearchFilter}
                                        onChange={e => setLinkSearchFilter(e.target.value)}
                                        className="w-full bg-background border border-border rounded-md pl-9 pr-4 py-2 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-primary transition-shadow"
                                      />
                                    </div>
                                  )}

                                  {isFetchingTorrents === activeModalResult.id ? (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                                      {Array.from({ length: 4 }).map((_, i) => (
                                        <div key={i} className="bg-card border border-border/50 rounded-xl p-4 flex flex-col gap-3 h-[116px]">
                                          <div className="flex flex-col gap-1.5 animate-pulse">
                                            <div className="h-4 bg-muted rounded w-3/4"></div>
                                            <div className="flex items-center gap-2 mt-1">
                                              <div className="h-4 w-12 bg-muted rounded"></div>
                                              <div className="h-4 w-16 bg-muted rounded"></div>
                                            </div>
                                          </div>
                                          <div className="pt-2 mt-auto animate-pulse">
                                            <div className="w-full h-9 bg-muted rounded-lg"></div>
                                          </div>
                                        </div>
                                      ))}
                                    </div>
                                  ) : activeModalResult.sources.length === 0 ? (
                                    <div className="text-center py-10">
                                      <AlertCircle className="mx-auto h-10 w-10 text-muted-foreground opacity-50 mb-3" />
                                      <p className="text-muted-foreground">No torrents found for this series.</p>
                                    </div>
                                  ) : (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                                      {activeModalResult.sources
                                        .filter(s => s.label.toLowerCase().includes(linkSearchFilter.toLowerCase()))
                                        .map((source) => {
                                        const busyId = `${activeModalResult.id}:${source.id}`
                                        const busy = sourceBusy[busyId] === true

                                        const getBadgeColor = (type: string) => {
                                          const t = type.toUpperCase()
                                          if (t === 'CBZ' || t === 'CBR') return 'bg-blue-500/10 text-blue-500 hover:bg-blue-500/20'
                                          if (t === 'EPUB') return 'bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500/20'
                                          if (t === 'PDF') return 'bg-red-500/10 text-red-500 hover:bg-red-500/20'
                                          if (t === 'ZIP' || t === 'RAR') return 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20'
                                          return 'bg-secondary text-secondary-foreground'
                                        }

                                        return (
                                          <div key={source.id} className="bg-card border border-border/50 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-border">
                                            <div className="flex flex-col gap-1.5">
                                              <h3 className="text-sm font-medium text-foreground truncate" title={source.label}>{source.label}</h3>
                                              <div className="flex items-center gap-2 text-xs font-medium text-muted-foreground">
                                                <Badge variant="outline" className={`text-[10px] px-1.5 py-0 uppercase border-0 ${getBadgeColor(source.fileType || '')}`}>
                                                  {source.fileType || 'UNKNOWN'}
                                                </Badge>
                                                {typeof source.sizeBytes === 'number' && <span>{formatBytes(source.sizeBytes)}</span>}
                                                {typeof source.seeders === 'number' && (
                                                  <span className="text-primary font-bold">{source.seeders} seeders</span>
                                                )}
                                              </div>
                                            </div>

                                            <div className="pt-2 mt-auto">
                                              {source.linkKind === 'direct' || source.linkKind === 'anna' || source.linkKind === 'external' ? (
                                                <Button
                                                  variant="secondary"
                                                  className="w-full h-9 rounded-lg text-xs font-semibold"
                                                  onClick={() => {
                                                    try {
                                                      const url = new URL(source.magnetLink);
                                                      if (url.protocol === 'http:' || url.protocol === 'https:' || url.protocol === 'magnet:') {
                                                        const openedWindow = window.open(source.magnetLink, '_blank', 'noopener,noreferrer')
                                                        if (!openedWindow) window.location.assign(source.magnetLink)
                                                      } else {
                                                        console.error('Blocked unsafe link protocol:', url.protocol);
                                                      }
                                                    } catch (e) {
                                                      console.error('Invalid link format', e);
                                                    }
                                                  }}
                                                >
                                                  <Link className="w-3.5 h-3.5 mr-2 opacity-70" />
                                                  Direct Download
                                                </Button>
                                              ) : (
                                                <Button
                                                  className="w-full h-9 rounded-lg text-xs font-semibold"
                                                  disabled={busy}
                                                  onClick={async () => {
                                                    setSourceBusy((prev) => ({ ...prev, [busyId]: true }))
                                                    try {
                                                      await enqueueJob({
                                                        title: activeModalResult.title,
                                                        sourceLink: source.magnetLink,
                                                        kind: searchType === 'books' ? 'books' : 'manga'
                                                      })
                                                      success('Added to Cloud', 'Job is now queued.')
                                                    } catch (e) {
                                                      error('Queue failed', getErrorMessage(e, 'Could not add to Torbox'))
                                                    } finally {
                                                      setSourceBusy((prev) => { const n = { ...prev }; delete n[busyId]; return n; })
                                                    }
                                                  }}
                                                >
                                                  {busy ? <Loader2 className="mr-2 h-3.5 w-3.5 animate-spin" /> : <DownloadCloud className="mr-2 h-3.5 w-3.5" />}
                                                  Add to Cloud
                                                </Button>
                                              )}
                                            </div>
                                          </div>
                                        )
                                      })}
                                    </div>
                                  )}
                                </div>
                              </motion.div>
                            )}
                          </AnimatePresence>
                        </motion.div>
                      )
                    })}
                  </AnimatePresence>

                  {!isSearching && searchResults.length === 0 && searchQuery.trim() && !searchError && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="col-span-full flex flex-col items-center justify-center rounded-3xl border border-dashed border-border py-20 bg-muted/5">
                      <Search className="h-10 w-10 text-muted-foreground/30 mb-4" />
                      <p className="text-base font-medium text-muted-foreground/80">No matching metadata found.</p>
                    </motion.div>
                  )}

                  {!isSearching && searchResults.length === 0 && !searchQuery.trim() && (
                    <div className="col-span-full">
                      <TrendingExplore type={searchType === 'all' ? 'manga' : searchType} />
                    </div>
                  )}
                </div>

                <div className="mt-auto pt-6 border-t border-border/50 pb-2">
                  <div className="max-w-3xl mx-auto flex flex-col lg:flex-row items-start lg:items-center justify-between gap-3 lg:gap-4">
                    <div className="flex items-center gap-3 w-full lg:w-auto">
                      <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-muted">
                        <Link className="h-4 w-4 text-muted-foreground" />
                      </div>
                      <div className="min-w-0 flex-1">
                        <h4 className="text-sm font-semibold tracking-tight text-foreground/80 truncate">Manual Magnet Add</h4>
                        <p className="text-[11px] text-muted-foreground truncate">Inject a magnet link if search is unavailable</p>
                      </div>
                    </div>

                    <div className="flex w-full lg:w-auto items-center gap-2 lg:gap-3">
                      <Input value={manualTitle} onChange={(event) => setManualTitle(event.target.value)} placeholder="Title" className="h-9 flex-[0.7] lg:w-32 text-xs font-medium bg-background border-border/40 focus:border-primary/40 rounded-full min-w-0" />
                      <Input value={manualMagnet} onChange={(event) => setManualMagnet(event.target.value)} placeholder="magnet:?xt..." className="h-9 flex-1 lg:w-48 text-xs font-medium bg-background border-border/40 focus:border-primary/40 font-mono rounded-full min-w-0" />
                      <Button size="sm" variant="secondary" className="h-9 rounded-full px-3 lg:px-4 font-semibold shadow-sm shrink-0" onClick={() => void addManualLink()}>Inject</Button>
                    </div>
                  </div>
                </div>
              </Tabs.Content>
            )}

            {activeTab === 'books' && (
              <Tabs.Content value="books" className="h-full rounded-2xl border border-border/50 bg-card/40 p-5 backdrop-blur-xl shadow-sm outline-none overflow-y-auto scrollbar-thin scrollbar-thumb-border scrollbar-track-transparent">
                <div className="mb-4 flex items-center justify-between">
                  <h2 className="text-lg font-bold tracking-tight text-foreground/90">Books Queue</h2>
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={clearStoreCompleted}>Clear Completed</Button>
                    <Badge variant="secondary" className="bg-white/10 text-foreground">{booksJobs.length} active tasks</Badge>
                  </div>
                </div>
                {renderQueueRows(booksJobs, 'No books are currently in your queue.')}
              </Tabs.Content>
            )}

            {activeTab === 'manga' && (
              <Tabs.Content value="manga" className="h-full rounded-2xl border border-border/50 bg-card/40 p-5 backdrop-blur-xl shadow-sm outline-none overflow-y-auto scrollbar-thin scrollbar-thumb-border scrollbar-track-transparent">
                <div className="mb-4 flex items-center justify-between">
                  <h2 className="text-lg font-bold tracking-tight text-foreground/90">Manga Queue</h2>
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={clearStoreCompleted}>Clear Completed</Button>
                    <Badge variant="secondary" className="bg-white/10 text-foreground">{mangaJobs.length} active tasks</Badge>
                  </div>
                </div>
                {renderQueueRows(mangaJobs, 'No manga are currently in your queue.')}
              </Tabs.Content>
            )}
          </motion.div>
        </AnimatePresence>
      </Tabs.Root>
      {/* Modal removed to use inline accordion */}
    </div>
  )
}

import { lazy, Suspense } from "react"
import { LibraryGrid } from "./library/LibraryGrid"
import { SectionErrorBoundary } from "./ErrorBoundary"
import { Book } from "@/lib/tauri"
import { DomainView } from "@/store/uiStore"

const HomePage = lazy(() => import("./home/HomePage").then(m => ({ default: m.HomePage })))
const RSSFeedManager = lazy(() => import("./rss/RSSFeedManager"))
const RSSArticleList = lazy(() => import("./rss/RSSArticleList"))
const AnnotationsView = lazy(() => import("./annotations/AnnotationsView").then(m => ({ default: m.AnnotationsView })))
const StatisticsView = lazy(() => import("./statistics/StatisticsView").then(m => ({ default: m.StatisticsView })))
const OnlineBooksView = lazy(() => import("./online/OnlineBooksView").then(m => ({ default: m.OnlineBooksView })))
const OnlineMangaView = lazy(() => import("./online/OnlineMangaView").then(m => ({ default: m.OnlineMangaView })))
const OnlineMangaReader = lazy(() => import("./online/OnlineMangaReader").then(m => ({ default: m.OnlineMangaReader })))
const TorboxControlCenter = lazy(() => import("./TorboxControlCenter"))
const RecycleBinView = lazy(() => import("./RecycleBinView").then(m => ({ default: m.RecycleBinView })))

const LoadingSpinner = ({ className = "h-screen" }: { className?: string }) => (
  <div className={`flex items-center justify-center ${className}`}>
    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary" />
  </div>
)

import { CurrentView } from "@/store/uiStore"

export interface ViewRouterProps {
  currentView: CurrentView
  currentDomain: DomainView
  displayBooks: Book[]
  handleNavigate: (view: CurrentView) => void
  handleOpenBook: (id: number, location?: string) => void
  handleViewDetails: (id: number) => void
  handleEditBook: (id: number) => void
  handleDeleteBook: (id: number) => void
  searchQuery: string
  onSearchChange: (query: string) => void
  onOpenAdvancedFilter: () => void

  dialogs: any
}

export function ViewRouter({
  currentView,
  currentDomain,
  displayBooks,
  handleNavigate,
  handleOpenBook,
  handleViewDetails,
  handleEditBook,
  handleDeleteBook,
  searchQuery,
  onSearchChange,
  onOpenAdvancedFilter,

  dialogs
}: ViewRouterProps) {
  return (
    <>
        {currentView === 'home' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}>
            <HomePage 
              onOpenBook={handleOpenBook} 
              onViewRSS={() => handleNavigate('rss-articles')} 
              searchQuery={searchQuery}
              onSearchChange={onSearchChange}
              onOpenAdvancedFilter={onOpenAdvancedFilter}
              onOpenSettings={() => dialogs.setSettingsDialogOpen(true)}
            />
          </Suspense>
        )}

        {currentView === 'rss-feeds' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}>
            <RSSFeedManager onClose={() => handleNavigate('library')} />
          </Suspense>
        )}

        {currentView === 'rss-articles' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}>
            <RSSArticleList onClose={() => handleNavigate('library')} />
          </Suspense>
        )}

        {currentView === 'library' && (
          <SectionErrorBoundary label="Library">
            <LibraryGrid
              books={displayBooks}
              currentDomain={currentDomain}
              onBookClick={handleOpenBook}
              onViewDetails={handleViewDetails}
              onEditBook={handleEditBook}
              onDeleteBook={handleDeleteBook}
              searchQuery={searchQuery}
              onSearchChange={onSearchChange}
              onOpenAdvancedFilter={onOpenAdvancedFilter}

              onViewSeries={dialogs.openSeriesView}
            />
          </SectionErrorBoundary>
        )}

        {currentView === 'annotations' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}>
            <AnnotationsView 
              onClose={() => handleNavigate('library')} 
              onOpenBook={handleOpenBook}
            />
          </Suspense>
        )}

        {currentView === 'statistics' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}>
            <StatisticsView onClose={() => handleNavigate('library')} />
          </Suspense>
        )}

        {currentView === 'online-books' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><OnlineBooksView /></Suspense>
        )}

        {currentView === 'online-manga' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><OnlineMangaView /></Suspense>
        )}


        {currentView === 'torbox-discover' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><TorboxControlCenter initialTab="discover" /></Suspense>
        )}

        {currentView === 'torbox-books' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><TorboxControlCenter initialTab="books" /></Suspense>
        )}

        {currentView === 'torbox-manga' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><TorboxControlCenter initialTab="manga" /></Suspense>
        )}

        {currentView === 'recycle-bin' && (
          <Suspense fallback={<LoadingSpinner className="py-24" />}><RecycleBinView /></Suspense>
        )}
    </>
  )
}

import { logger } from '@/lib/logger';
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { api, AnnotationSearchResult, AnnotationCategory } from '@/lib/tauri';
import { useToastStore } from '@/store/toastStore';
import { Highlighter, StickyNote, Bookmark, BookmarkPlus, X, LayoutGrid, List, Library, Share2, ExternalLink, BookOpen, Quote } from 'lucide-react';
import { formatDate } from '@/lib/utils';
import { AnnotationExportDialog } from '../reader/AnnotationExportDialog';
import { QuoteCardDialog } from './QuoteCardDialog';
import ReactMarkdown from 'react-markdown';

interface AnnotationsViewProps {
  onClose: () => void;
  onOpenBook?: (bookId: number, location?: string) => void;
}

export function AnnotationsView({ onClose, onOpenBook }: AnnotationsViewProps) {
  const [annotations, setAnnotations] = useState<AnnotationSearchResult[]>([]);
  const [categories, setCategories] = useState<AnnotationCategory[]>([]);
  const [loading, setLoading] = useState(true);

  // Filters & Toggles
  const [searchQuery, setSearchQuery] = useState('');
  const [typeFilter, setTypeFilter] = useState<string>('all');
  const [categoryFilter, setCategoryFilter] = useState<number | 'all'>('all');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');

  // Sidebar State
  const [selectedBookId, setSelectedBookId] = useState<number | 'all'>('all');

  const [exportDialogOpen, setExportDialogOpen] = useState(false);
  const [quoteCardData, setQuoteCardData] = useState<AnnotationSearchResult | null>(null);

  const fetchAnnotations = useCallback(async () => {
    setLoading(true);
    try {
      const typeParam = typeFilter === 'all' ? undefined : typeFilter;
      const catParam = categoryFilter === 'all' ? undefined : categoryFilter;

      let results: AnnotationSearchResult[];
      if (searchQuery.trim()) {
        results = await api.searchAnnotationsGlobal(searchQuery.trim(), undefined, typeParam, catParam, 1000, 0);
      } else {
        results = await api.getAllAnnotations(undefined, typeParam, catParam, 1000, 0);
      }
      setAnnotations(results);
    } catch (error) {
      useToastStore.getState().addToast({
        title: 'Failed to fetch annotations',
        description: String(error),
        variant: 'error',
      });
    } finally {
      setLoading(false);
    }
  }, [searchQuery, typeFilter, categoryFilter]);

  const fetchCategories = useCallback(async () => {
    try {
      const cats = await api.getAnnotationCategories();
      setCategories(cats);
    } catch (err) {
      logger.error('Failed to fetch categories:', err);
    }
  }, []);

  useEffect(() => {
    fetchCategories();
  }, [fetchCategories]);

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchAnnotations();
    }, 300);
    return () => clearTimeout(timer);
  }, [fetchAnnotations]);

  const getAnnotationIcon = (type: string) => {
    switch (type) {
      case 'highlight':
        return <Highlighter className="w-5 h-5 text-yellow-500" />;
      case 'note':
        return <StickyNote className="w-5 h-5 text-blue-500" />;
      case 'bookmark':
        return <Bookmark className="w-5 h-5 text-blue-500" />;
      case 'vocabulary':
        return <BookmarkPlus className="w-5 h-5 text-purple-500" />;
      default:
        return <Highlighter className="w-5 h-5 text-muted-foreground" />;
    }
  };

  // Unique Books for Sidebar
  const uniqueBooks = useMemo(() => {
    const map = new Map<number, { title: string; author: string; count: number }>();
    annotations.forEach(a => {
      if (!map.has(a.annotation.bookId)) {
        map.set(a.annotation.bookId, { title: a.book_title, author: a.book_author || 'Unknown', count: 0 });
      }
      map.get(a.annotation.bookId)!.count++;
    });
    return Array.from(map.entries()).map(([id, data]) => ({ id, ...data })).sort((a, b) => a.title.localeCompare(b.title));
  }, [annotations]);

  // Filtered Annotations for Main Pane
  const displayedAnnotations = useMemo(() => {
    if (selectedBookId === 'all') return annotations;
    return annotations.filter(a => a.annotation.bookId === selectedBookId);
  }, [annotations, selectedBookId]);

  // Grouped Annotations (only used when 'all' is selected)
  const groupedAnnotations = useMemo(() => {
    if (selectedBookId !== 'all') return null;
    const map = new Map<number, { title: string; author: string; items: AnnotationSearchResult[] }>();
    for (const a of displayedAnnotations) {
      if (!map.has(a.annotation.bookId)) {
        map.set(a.annotation.bookId, { title: a.book_title, author: a.book_author || 'Unknown', items: [] });
      }
      map.get(a.annotation.bookId)!.items.push(a);
    }
    return Array.from(map.entries());
  }, [displayedAnnotations, selectedBookId]);

  const renderAnnotationCard = (result: AnnotationSearchResult) => {
    let isVocabulary = false;
    let vocabData: any = null;
    if (result.annotation.noteContent) {
      try {
        vocabData = JSON.parse(result.annotation.noteContent);
        if (vocabData && (vocabData.type === 'define' || vocabData.type === 'translate')) {
          isVocabulary = true;
        }
      } catch {
        // Not JSON, just a regular note
      }
    }

    const tintColor = result.annotation.color || '#3b82f6';

    return (
      <div 
        key={result.annotation.id} 
        className="break-inside-avoid mb-8 relative group transition-all duration-500 hover:-translate-y-1"
      >
        {/* Premium Minimalist Card Background */}
        <div className="absolute inset-0 bg-muted/20 hover:bg-muted/40 border border-transparent group-hover:border-border/50 rounded-[1.25rem] transition-all duration-500 z-0 backdrop-blur-sm" />

        {/* Subtle Accent Glow */}
        <div className="absolute inset-0 opacity-0 group-hover:opacity-[0.04] transition-opacity duration-700 pointer-events-none rounded-[1.5rem] z-0" style={{ backgroundImage: `radial-gradient(circle at top right, ${tintColor}, transparent 70%)` }} />

        <div className="p-4 md:p-6 flex flex-col h-full relative z-10">
          {/* Header */}
          <div className="flex items-start justify-between mb-4 md:mb-5">
            <div className="flex items-center gap-3.5">
              <div className="shrink-0 text-muted-foreground/40 group-hover:text-primary/80 transition-colors duration-500">
                {isVocabulary ? (
                  <BookmarkPlus className="w-5 h-5" />
                ) : (
                  getAnnotationIcon(result.annotation.annotationType)
                )}
              </div>
              <div className="flex flex-wrap items-center gap-x-2 text-xs text-muted-foreground/60">
                <span className="font-bold tracking-[0.1em] uppercase text-[10px]">{formatDate(result.annotation.createdAt || '')}</span>
                {result.annotation.chapterTitle && (
                  <>
                    <span className="w-1 h-1 rounded-full bg-border" />
                    <span className="truncate max-w-[120px] sm:max-w-[200px] font-medium font-serif italic text-[12px] md:text-[13px]" title={result.annotation.chapterTitle}>
                      {result.annotation.chapterTitle}
                    </span>
                  </>
                )}
              </div>
            </div>

            {/* Quick Actions (Hover) */}
            <div className="opacity-0 group-hover:opacity-100 transition-all duration-500 flex items-center gap-1.5 -mt-1.5 -mr-1.5 translate-x-2 group-hover:translate-x-0">
              {result.annotation.selectedText && (
                <button 
                  onClick={() => setQuoteCardData(result)}
                  className="p-2 hover:bg-primary/10 rounded-full text-muted-foreground hover:text-primary transition-all duration-300 hover:shadow-[0_0_15px_rgba(var(--primary),0.2)]"
                  title="Create Quote Card"
                >
                  <Share2 size={14} />
                </button>
              )}
              {onOpenBook && (
                <button 
                  onClick={() => onOpenBook(result.annotation.bookId, result.annotation.location)}
                  className="p-2 hover:bg-primary/10 rounded-full text-muted-foreground hover:text-primary transition-all duration-300 hover:shadow-[0_0_15px_rgba(var(--primary),0.2)]"
                  title="Jump to location"
                >
                  <ExternalLink size={14} />
                </button>
              )}
            </div>
          </div>

          {/* Category Tag */}
          {result.annotation.categoryId && categories.find(c => c.id === result.annotation.categoryId) && (
            <div className="mb-4">
              <span className="text-[10px] uppercase tracking-[0.15em] px-2.5 py-1 rounded-md font-bold shadow-sm backdrop-blur-md border" style={{ 
                backgroundColor: `${categories.find(c => c.id === result.annotation.categoryId)?.color}15`, 
                color: categories.find(c => c.id === result.annotation.categoryId)?.color,
                borderColor: `${categories.find(c => c.id === result.annotation.categoryId)?.color}30`
              }}>
                {categories.find(c => c.id === result.annotation.categoryId)?.name}
              </span>
            </div>
          )}

          {/* Content */}
          <div className="flex-1 space-y-6">
            {result.annotation.selectedText && (
              <div className="relative pl-7 py-1 group/quote">
                {/* Decorative background quote mark */}
                <Quote className="absolute left-0 top-0 w-5 h-5 text-muted-foreground/30 -rotate-12 transition-transform duration-700 group-hover:-rotate-0" />

                {/* Glowing vertical accent line */}
                <div className="absolute left-0 top-0 bottom-0 w-[3px] rounded-full transition-all duration-500 group-hover/quote:w-[4px]" style={{ 
                  background: `linear-gradient(to bottom, ${tintColor}, ${tintColor}10)`,
                  boxShadow: `0 0 12px ${tintColor}30`
                }} />

                <span className="text-foreground/95 text-[16px] md:text-[18px] leading-[1.6] font-serif font-medium tracking-tight relative z-10 block">
                  {result.annotation.selectedText}
                </span>
              </div>
            )}

            {result.annotation.noteContent && !isVocabulary && (
              <div className="pt-4 mt-2 border-t border-border/40 relative z-10">
                <div className="text-[14px] prose prose-sm dark:prose-invert max-w-none text-muted-foreground/90 font-serif italic">
                  <ReactMarkdown>{result.annotation.noteContent}</ReactMarkdown>
                </div>
              </div>
            )}

            {isVocabulary && vocabData && (
              <div className="mt-4 pl-1 relative z-10">
                <div className="text-sm flex flex-col gap-5">
                  {vocabData.type === 'define' && vocabData.data?.meanings?.length && (
                    <div className="space-y-6">
                      {vocabData.data.phonetic && (
                        <div className="flex items-center gap-2.5 text-muted-foreground/50 border-b border-border/30 pb-4">
                          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-primary/50"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14"></path></svg>
                          <span className="text-[15px] font-medium tracking-widest font-serif italic">{vocabData.data.phonetic}</span>
                        </div>
                      )}
                      <div className="space-y-5">
                        {vocabData.data.meanings.slice(0, 2).map((m: any, i: number) => (
                          <div key={i} className="flex flex-col gap-2 relative pl-4">
                            <div className="absolute left-0 top-1.5 w-1.5 h-1.5 rounded-full bg-primary/40" />
                            <span className="font-bold text-[9px] text-primary/80 uppercase tracking-[0.25em]">{m.part_of_speech}</span>
                            <div className="text-foreground/80 text-[15px] leading-relaxed font-medium">{m.definitions[0]?.definition}</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                  {vocabData.type === 'translate' && vocabData.data?.translated_text && (
                    <div className="space-y-2 mt-3 pt-4 border-t border-border/20">
                      <div className="text-foreground/95 text-[18px] font-serif font-semibold tracking-tight">{vocabData.data.translated_text}</div>
                      <div className="text-[9px] text-muted-foreground/40 uppercase tracking-[0.2em] font-bold">Translated via {vocabData.data.provider}</div>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  const tabs = [
    { id: 'all', label: 'All Notes' },
    { id: 'highlight', label: 'Highlights' },
    { id: 'note', label: 'Notes' }
  ];

  return (
    <div className="flex h-full bg-background text-foreground overflow-hidden">

      {/* Left Sidebar - Books */}
      <div className="w-72 flex-none border-r border-border bg-muted/10 flex flex-col overflow-hidden hidden md:flex">
        <div className="p-4 border-b border-border">
          <h2 className="font-semibold text-lg flex items-center gap-2">
            <Library size={18} />
            Library
          </h2>
        </div>
        <div className="flex-1 overflow-y-auto p-2 space-y-1">
          <button
            onClick={() => setSelectedBookId('all')}
            className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-between ${
              selectedBookId === 'all' 
                ? 'bg-primary text-primary-foreground' 
                : 'hover:bg-muted text-foreground'
            }`}
          >
            <div className="flex items-center gap-2">
              <BookOpen size={16} />
              <span>All Books</span>
            </div>
            <span className={`text-xs px-2 py-0.5 rounded-full ${selectedBookId === 'all' ? 'bg-primary-foreground/20' : 'bg-muted-foreground/20'}`}>
              {annotations.length}
            </span>
          </button>

          <div className="pt-4 pb-1 px-3">
            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Books</span>
          </div>

          {uniqueBooks.map(book => (
            <button
              key={book.id}
              onClick={() => setSelectedBookId(book.id)}
              className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-colors flex items-start gap-2 ${
                selectedBookId === book.id 
                  ? 'bg-muted border border-border/50 text-foreground font-medium' 
                  : 'hover:bg-muted/50 text-muted-foreground hover:text-foreground'
              }`}
            >
              <div className="flex-1 min-w-0">
                <div className="truncate">{book.title}</div>
                <div className="text-xs opacity-70 truncate mt-0.5">{book.author}</div>
              </div>
              <span className="text-xs px-2 py-0.5 bg-background rounded-full border border-border/50 shrink-0">
                {book.count}
              </span>
            </button>
          ))}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col overflow-hidden min-w-0">

        {/* Header & Tabs */}
        <div className="flex-none pt-[max(env(safe-area-inset-top,1rem),1rem)] md:pt-6 px-4 md:px-6 border-b border-border/40 bg-background/80 backdrop-blur-xl z-20 sticky top-0">
          <div className="flex flex-col gap-3 mb-3">
            {/* Top Row: Dropdown, Actions, Close */}
            <div className="flex items-center justify-between gap-2">
              <div className="flex-1 min-w-0 md:hidden">
                <select
                  value={selectedBookId}
                  onChange={(e) => setSelectedBookId(e.target.value === 'all' ? 'all' : Number(e.target.value))}
                  className="w-full bg-transparent text-xl font-bold truncate focus:outline-none appearance-none"
                >
                  <option value="all">All Annotations</option>
                  {uniqueBooks.map(b => (
                    <option key={b.id} value={b.id}>{b.title}</option>
                  ))}
                </select>
              </div>
              <h1 className="text-xl md:text-2xl font-bold tracking-tight hidden md:block">
                {selectedBookId === 'all' ? 'All Annotations' : uniqueBooks.find(b => b.id === selectedBookId)?.title}
              </h1>

              <div className="flex items-center gap-1 shrink-0 text-muted-foreground">
                <button onClick={() => setExportDialogOpen(true)} className="p-2 hover:bg-muted rounded-full transition-colors" title="Export"><Share2 size={18} /></button>
                <button onClick={onClose} className="p-2 hover:bg-muted rounded-full transition-colors md:hidden" title="Close"><X size={20} /></button>
              </div>
            </div>

            {/* Search Bar */}
            <div className="relative w-full">
              <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
              <input type="text" placeholder="Search annotations..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-9 pr-4 py-2 bg-muted/30 hover:bg-muted/50 border border-border/50 rounded-xl focus:outline-none focus:ring-1 focus:ring-primary transition-all text-sm text-foreground placeholder:text-muted-foreground" />
            </div>

            {/* Tabs & Categories Row */}
            <div className="flex items-center justify-between gap-4 overflow-x-auto no-scrollbar">
              <div className="flex gap-4 shrink-0">
