import React, { useRef, useState } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { X, Download } from 'lucide-react';
import { toPng } from 'html-to-image';
import { AnnotationSearchResult } from '@/lib/tauri';
import { useToastStore } from '@/store/toastStore';

interface QuoteCardDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  annotationData: AnnotationSearchResult | null;
}

export function QuoteCardDialog({ open, onOpenChange, annotationData }: QuoteCardDialogProps) {
  const cardRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  if (!annotationData) return null;
  const { annotation, book_title, book_author } = annotationData;

  const handleDownload = async () => {
    if (!cardRef.current) return;
    try {
      setIsExporting(true);
      const dataUrl = await toPng(cardRef.current, {
        quality: 1,
        pixelRatio: 3,
        backgroundColor: 'transparent',
      });
      const link = document.createElement('a');
      link.download = `quote-${book_title.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}.png`;
      link.href = dataUrl;
      link.click();

      useToastStore.getState().addToast({
        title: 'Quote card saved',
        description: 'The image has been downloaded successfully.',
        variant: 'success',
      });
      onOpenChange(false);
    } catch (error) {
      console.error('Failed to generate image:', error);
      useToastStore.getState().addToast({
        title: 'Export failed',
        description: 'Failed to generate quote card image.',
        variant: 'error',
      });
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 transition-opacity" />
        <Dialog.Content aria-describedby={undefined} className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50 w-full max-w-lg shadow-2xl focus:outline-none">
          <div className="bg-background border border-border rounded-xl flex flex-col overflow-hidden shadow-2xl">
            <div className="flex items-center justify-between px-4 py-3 border-b border-border bg-muted/50">
              <Dialog.Title className="text-sm font-semibold">Share Quote</Dialog.Title>
              <Dialog.Close className="p-1 hover:bg-muted rounded text-muted-foreground transition-colors">
                <X size={16} />
              </Dialog.Close>
            </div>

            <div className="p-8 bg-zinc-100 dark:bg-[#09090b] flex items-center justify-center relative overflow-hidden">
              <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,rgba(var(--primary),0.15),transparent_70%)] pointer-events-none" />

              {/* Card to be exported */}
              <div 
                ref={cardRef} 
                className="relative bg-white dark:bg-[#121214] rounded-2xl shadow-2xl overflow-hidden w-full max-w-md p-8 ring-1 ring-black/5 dark:ring-white/10"
              >
                {/* Colored Top Accent Bar */}
                <div 
                  className="absolute top-0 left-0 right-0 h-1.5 opacity-90"
                  style={{ background: `linear-gradient(90deg, ${annotation.color || 'hsl(var(--primary))'} 0%, transparent 100%)` }} 
                />

                {/* Decorative background quote mark */}
                <div className="absolute top-2 right-6 text-[100px] text-zinc-100 dark:text-zinc-800/30 font-serif leading-none select-none pointer-events-none">
                  "
                </div>

                <div className="relative z-10">
                  <div className="text-lg md:text-xl font-serif text-zinc-900 dark:text-zinc-50 leading-relaxed mb-6 whitespace-pre-wrap font-medium tracking-tight">
                    {annotation.selectedText}
                  </div>

                  {(() => {
                    const isVocabulary = annotation.annotationType === 'vocabulary' || 
                      (annotation.noteContent && annotation.noteContent.includes('{"type":"define"'));

                    if (isVocabulary && annotation.noteContent) {
                      try {
                        const vocabData = JSON.parse(annotation.noteContent);
                        return (
                          <div className="mb-6 space-y-4">
                            {vocabData.data?.phonetic && (
                              <div className="text-sm font-serif italic text-zinc-500 dark:text-zinc-400">
                                {vocabData.data.phonetic}
                              </div>
                            )}
                            {vocabData.data?.meanings?.slice(0, 2).map((m: any, i: number) => (
                              <div key={i} className="flex flex-col gap-1">
                                <span className="font-bold text-[9px] text-[var(--primary)] uppercase tracking-[0.25em]">{m.part_of_speech}</span>
                                <div className="text-zinc-700 dark:text-zinc-300 text-[14px] leading-relaxed font-medium">{m.definitions[0]?.definition}</div>
                              </div>
                            ))}
                          </div>
                        );
                      } catch (e) {
                        return (
                          <div className="mb-6 p-4 bg-zinc-50 dark:bg-zinc-800/30 rounded-xl border border-zinc-100 dark:border-zinc-800/50 text-sm text-zinc-600 dark:text-zinc-400">
                            {annotation.noteContent}
                          </div>
                        );
                      }
                    } else if (annotation.noteContent) {
                      return (
                        <div className="mb-6 p-4 bg-zinc-50 dark:bg-zinc-800/30 rounded-xl border border-zinc-100 dark:border-zinc-800/50 text-sm text-zinc-600 dark:text-zinc-400 leading-relaxed shadow-inner">
                          {annotation.noteContent}
                        </div>
                      );
                    }
                    return null;
                  })()}

                  <div className="flex items-center justify-between border-t border-zinc-200 dark:border-zinc-800/60 pt-5 mt-6">
                    <div className="pr-4">
                      <div className="font-semibold text-sm text-zinc-900 dark:text-zinc-100 tracking-tight">
                        {book_title}
                      </div>
                      <div className="text-[11px] text-zinc-500 dark:text-zinc-400 mt-1 font-medium uppercase tracking-wider">
                        {book_author || 'Unknown Author'}
                      </div>
                    </div>
                    <div className="shrink-0 text-[10px] font-bold tracking-[0.2em] text-zinc-400 dark:text-zinc-500 uppercase flex flex-col items-end">
                      <span>Shiori</span>
                      <span className="text-[8px] font-medium opacity-50 tracking-[0.3em] mt-0.5">Reader</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-4 bg-background border-t border-border flex justify-end">
              <button
                onClick={handleDownload}
                disabled={isExporting}
                className="flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground hover:bg-primary/90 rounded-md font-medium text-sm transition-colors disabled:opacity-50"
              >
                {isExporting ? (
                  <div className="w-4 h-4 rounded-full border-2 border-white/20 border-t-white animate-spin" />
                ) : (
                  <Download size={16} />
                )}
                {isExporting ? 'Generating...' : 'Save Image'}
              </button>
            </div>
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

import { useState, useEffect } from 'react'
import { convertFileSrc } from '@tauri-apps/api/core'
import { requestCoverUrl } from '@/lib/coverCache'

/** Normalize Windows backslash paths for the asset:// protocol */
function toAssetUrl(filePath: string): string {
  // HTTP(S) URLs (e.g. online manga cover CDN links) — use directly
  if (filePath.startsWith('http://') || filePath.startsWith('https://')) {
    return filePath
  }
  return convertFileSrc(filePath.replace(/\\/g, '/'))
}

/**
 * useCoverImage — resolves a cover URL for a book.
 *
 * If `initialCoverSrc` is provided (a raw file path from the Book object),
 * it is converted immediately with no IPC call.
 *
 * Otherwise, delegates to the module-level coverCache micro-batcher which
 * groups IDs from the same render cycle into a single batch IPC call.
 */
export function useCoverImage(bookId?: number, initialCoverSrc?: string | null) {
  const [coverUrl, setCoverUrl] = useState<string | null>(
    initialCoverSrc ? toAssetUrl(initialCoverSrc) : null
  )
  const [loading, setLoading] = useState(!initialCoverSrc && !!bookId)
  const [error, setError] = useState(false)

  useEffect(() => {
    // If an initial path was provided, use it directly — no IPC needed
    if (initialCoverSrc) {
      setCoverUrl(toAssetUrl(initialCoverSrc))
      setLoading(false)
      setError(false)
      return
    }

    if (!bookId) {
      setLoading(false)
      return
    }

    let mounted = true
    setLoading(true)
    setError(false)

    requestCoverUrl(bookId).then((url) => {
      if (!mounted) return
      if (url) {
        setCoverUrl(url)
        setError(false)
      } else {
        setError(true)
      }
      setLoading(false)
    })

    return () => { mounted = false }
  }, [bookId, initialCoverSrc])

  return { coverUrl, loading, error }
}

import { useState, useEffect } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { RefreshCw, QrCode, MonitorSmartphone, Wifi } from 'lucide-react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import { useToast } from '@/store/toastStore';

interface CompanionInstance {
  name: string;
  ip: string;
  port: number;
}

export function CompanionDiscovery() {
  const [activeTab, setActiveTab] = useState<'auto' | 'manual' | 'qr'>('auto');
  const [discovered, setDiscovered] = useState<CompanionInstance[]>([]);
  const [isScanning, setIsScanning] = useState(false);

  const [manualIp, setManualIp] = useState('');
  const [manualPort, setManualPort] = useState('8080');

  const toast = useToast();

  const scanForCompanions = async () => {
    setIsScanning(true);
    try {
      const instances = await invoke<CompanionInstance[]>('scan_for_companions');
      setDiscovered(instances);
    } catch (e) {
      console.error("Discovery failed", e);
      toast.error("Failed to scan for desktop companions.");
    } finally {
      setIsScanning(false);
    }
  };

  const connectToInstance = (ip: string, port: number) => {
    // In a real app, you would save this to settings, initialize a websocket, or test the API
    console.log(`Connecting to ${ip}:${port}`);
    toast.success(`Connected to ${ip}:${port}`);
    // Save to preferences/store
  };

  useEffect(() => {
    if (activeTab === 'auto') {
      scanForCompanions();
    }
  }, [activeTab]);

  useEffect(() => {
    let scanner: Html5QrcodeScanner | null = null;
    if (activeTab === 'qr') {
      scanner = new Html5QrcodeScanner(
        "qr-reader",
        { fps: 10, qrbox: { width: 250, height: 250 } },
        false
      );
      scanner.render((decodedText) => {
        // Expected format: shiori://companion?ip=192.168.1.100&port=8080
        try {
          if (decodedText.startsWith('shiori://companion')) {
            const url = new URL(decodedText);
            const ip = url.searchParams.get('ip');
            const port = parseInt(url.searchParams.get('port') || '8080', 10);
            if (ip) {
              connectToInstance(ip, port);
              if (scanner) scanner.clear();
              setActiveTab('auto'); // switch back
            }
          }
        } catch (e) {
          console.error("Invalid QR code payload", e);
        }
      }, (error) => {
        // Ignore errors from missing frames
      });
    }

    return () => {
      if (scanner) {
        scanner.clear().catch(console.error);
      }
    };
  }, [activeTab]);

  return (
    <div className="w-full max-w-md mx-auto bg-background border rounded-xl overflow-hidden shadow-sm">
      <div className="p-4 border-b bg-muted/30">
        <h2 className="text-lg font-semibold flex items-center gap-2">
          <MonitorSmartphone className="w-5 h-5" /> Pair with Desktop
        </h2>
        <p className="text-sm text-muted-foreground mt-1">
          Connect your mobile app to your desktop Shiori library.
        </p>
      </div>

      <div className="flex border-b">
        <button 
          className={`flex-1 p-3 text-sm font-medium ${activeTab === 'auto' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}
          onClick={() => setActiveTab('auto')}
        >
          Auto Scan
        </button>
        <button 
          className={`flex-1 p-3 text-sm font-medium ${activeTab === 'qr' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}
          onClick={() => setActiveTab('qr')}
        >
          Scan QR
        </button>
        <button 
          className={`flex-1 p-3 text-sm font-medium ${activeTab === 'manual' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}
          onClick={() => setActiveTab('manual')}
        >
          Manual
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'auto' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center mb-4">
              <span className="text-sm text-muted-foreground">Discovered instances:</span>
              <Button size="sm" variant="outline" onClick={scanForCompanions} disabled={isScanning}>
                <RefreshCw className={`w-4 h-4 mr-2 ${isScanning ? 'animate-spin' : ''}`} />
                Rescan
              </Button>
            </div>

            {discovered.length === 0 ? (
              <div className="text-center p-8 bg-muted/20 rounded-lg border border-dashed">
                <Wifi className="w-8 h-8 mx-auto text-muted-foreground mb-3 opacity-50" />
                <p className="text-sm text-muted-foreground">No desktop instances found on the local network.</p>
                <p className="text-xs text-muted-foreground mt-2">Make sure "Companion Discovery" is enabled in Desktop Settings.</p>
              </div>
            ) : (
              <div className="space-y-3">
                {discovered.map((instance, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 border rounded-lg hover:bg-muted/50 transition-colors">
                    <div>
                      <div className="font-medium text-sm">{instance.name.replace('._shiori._tcp.local.', '')}</div>
                      <div className="text-xs text-muted-foreground font-mono">{instance.ip}:{instance.port}</div>
                    </div>
                    <Button size="sm" onClick={() => connectToInstance(instance.ip, instance.port)}>
                      Connect
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'qr' && (
          <div className="space-y-4 text-center">
            <p className="text-sm text-muted-foreground mb-4">
              Scan the QR code displayed in your Desktop App's Settings.
            </p>
            <div className="overflow-hidden rounded-lg border bg-black/5" id="qr-reader" style={{ width: '100%', minHeight: '250px' }}></div>
          </div>
        )}

        {activeTab === 'manual' && (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-sm font-medium">Desktop IP Address</label>
              <Input 
                placeholder="192.168.1.x" 
                value={manualIp}
                onChange={e => setManualIp(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Port</label>
              <Input 
                placeholder="8080" 
                value={manualPort}
                onChange={e => setManualPort(e.target.value)}
              />
            </div>
            <Button 
              className="w-full mt-4" 
              onClick={() => connectToInstance(manualIp, parseInt(manualPort, 10))}
              disabled={!manualIp || !manualPort}
            >
              Connect
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { X, BookOpen, Loader2 } from 'lucide-react';
import { Button } from '../ui/button';

interface AutoConvertDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  bookTitle: string;
  currentFormat: string;
  onConfirm: () => void;
  isConverting: boolean;
}

const FORMAT_LABELS: Record<string, string> = {
  mobi: 'MOBI',
  azw3: 'AZW3',
  pdf: 'PDF',
  txt: 'TXT',
  docx: 'DOCX',
  fb2: 'FB2',
  html: 'HTML',
};

export const AutoConvertDialog: React.FC<AutoConvertDialogProps> = ({
  isOpen,
  onOpenChange,
  bookTitle,
  currentFormat,
  onConfirm,
  isConverting,
}) => {
  const formatLabel = FORMAT_LABELS[currentFormat.toLowerCase()] ?? currentFormat.toUpperCase();
  const [fakeProgress, setFakeProgress] = useState(0);

  useEffect(() => {
    let unlisten: (() => void) | undefined;

    if (isOpen) {
      import('@tauri-apps/api/event').then(({ listen }) => {
        listen('conversion:progress', (event: any) => {
          const payload = event.payload;
          if (payload && payload.id === 'direct' && typeof payload.progress === 'number') {
            setFakeProgress(payload.progress);
          }
        }).then(fn => {
          unlisten = fn;
        });
      });
    }

    return () => {
      if (unlisten) unlisten();
    };
  }, [isOpen]);

  // Reset progress when conversion starts
  useEffect(() => {
    if (isConverting) {
      setFakeProgress(0);
    } else {
      setFakeProgress(100);
    }
  }, [isConverting]);

  // Reset when dialog opens
  useEffect(() => {
    if (isOpen && !isConverting) {
      setFakeProgress(0);
    }
  }, [isOpen, isConverting]);

  return (
    <Dialog.Root open={isOpen} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-black/50 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content
          className="dialog-content fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background border border-border rounded-xl shadow-lg w-[90vw] max-w-md z-50 duration-200 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%] data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%]"
          aria-describedby="auto-convert-description"
        >
          {/* Header */}
          <div className="flex items-center justify-between p-6 border-b border-border bg-muted/20">
            <Dialog.Title className="text-lg font-semibold text-foreground flex items-center gap-3">
              <div className="p-2 bg-primary/10 rounded-lg">
                <BookOpen className="h-5 w-5 text-primary" />
              </div>
              Convert to EPUB
            </Dialog.Title>
            <Dialog.Close asChild>
              <button 
                className="inline-flex items-center justify-center rounded-md p-2 text-muted-foreground hover:bg-accent hover:text-foreground transition-colors disabled:opacity-50" 
                title="Close"
                disabled={isConverting}
              >
                <X className="h-4 w-4" />
              </button>
            </Dialog.Close>
          </div>

          {/* Content */}
          <div className="p-6">
            <p className="text-sm text-foreground mb-4">
              Are you sure you want to convert <span className="font-semibold">"{bookTitle}"</span>?
            </p>
            <p 
              id="auto-convert-description"
              className="text-sm text-muted-foreground mb-6"
            >
              The original {formatLabel} file will be permanently deleted after successful conversion. This action is irreversible.
            </p>

            {/* Progress Section */}
