              <Trash2 className="w-4 h-4 mr-2" />
              Delete
            </ContextMenu.Item>
          </ContextMenu.Content>
        </ContextMenu.Portal>
      </ContextMenu.Root>

      {isManga && (
        <SeriesAssignmentDialog
          open={assignOpen}
          onOpenChange={setAssignOpen}
          bookId={book.id!}
          bookTitle={book.title}
        />
      )}
    </>
  )
})

