import { useState } from 'react'
import { BookOpen, Star, ArrowUp, ArrowDown, MoreVertical, Edit, Trash2, Download, RefreshCw, Share2, Info } from 'lucide-react'
import { cn, formatFileSize, formatDate } from '@/lib/utils'
import type { Book } from '@/lib/tauri'
import { Badge } from '@/components/ui/badge'
import { convertFileSrc } from '@tauri-apps/api/core'

function resolveCoverSrc(path: string): string {
  if (path.startsWith('http://') || path.startsWith('https://')) return path
  return convertFileSrc(path.replace(/\\/g, '/'))
}
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'

type SortField = 'title' | 'author' | 'rating' | 'date' | 'size' | 'format'
type SortDirection = 'asc' | 'desc'

interface TableViewProps {
  books: Book[]
  selectedBooks: Set<number>
  onSelectBook: (id: number) => void
  onOpenBook: (id: number) => void
  onViewDetails?: (id: number) => void
  onEditBook: (id: number) => void
  onDeleteBook: (id: number) => void
  onDownloadBook: (id: number) => void
}

function SortIcon({ field, sortField, sortDirection }: { field: SortField; sortField: SortField; sortDirection: 'asc' | 'desc' }) {
  if (sortField !== field) return null
  return sortDirection === 'asc' ? (
    <ArrowUp className="w-3.5 h-3.5" />
  ) : (
    <ArrowDown className="w-3.5 h-3.5" />
  )
}

export const ModernTableView = ({
  books,
  selectedBooks,
  onSelectBook,
  onOpenBook,
  onViewDetails,
  onEditBook,
  onDeleteBook,
  onDownloadBook,
}: TableViewProps) => {
  const [sortField, setSortField] = useState<SortField>('title')
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc')

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc')
    } else {
      setSortField(field)
      setSortDirection('asc')
    }
  }

  const sortedBooks = [...books].sort((a, b) => {
    let comparison = 0

    switch (sortField) {
      case 'title':
        comparison = a.title.localeCompare(b.title)
        break
      case 'author': {
        const aAuthor = a.authors?.[0]?.name || ''
        const bAuthor = b.authors?.[0]?.name || ''
        comparison = aAuthor.localeCompare(bAuthor)
        break
      }
      case 'rating':
        comparison = (a.rating || 0) - (b.rating || 0)
        break
      case 'date':
        comparison = new Date(a.added_date).getTime() - new Date(b.added_date).getTime()
        break
      case 'size':
        comparison = (a.file_size || 0) - (b.file_size || 0)
        break
      case 'format':
        comparison = a.file_format.localeCompare(b.file_format)
        break
    }

    return sortDirection === 'asc' ? comparison : -comparison
  })

  const handleSelectAll = () => {
    if (selectedBooks.size === books.length) {
      books.forEach(book => onSelectBook(book.id!))
    } else {
      books.forEach(book => {
        if (!selectedBooks.has(book.id!)) {
          onSelectBook(book.id!)
        }
      })
    }
  }

  if (books.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 text-center">
        <BookOpen className="w-16 h-16 text-muted-foreground/30 mb-4" />
        <h3 className="text-lg font-semibold mb-2">No books found</h3>
        <p className="text-sm text-muted-foreground max-w-sm">
          Try adjusting your filters or import some books to get started.
        </p>
      </div>
    )
  }

  return (
    <div className="border rounded-lg overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-muted/50 border-b">
            <tr>
              {/* Select All Checkbox */}
              <th className="w-12 p-3">
                <div
                  onClick={handleSelectAll}
                  className={cn(
                    'w-5 h-5 rounded-md border-2 flex items-center justify-center mx-auto',
                    'transition-all cursor-pointer',
                    selectedBooks.size === books.length && books.length > 0
                      ? 'border-primary bg-primary'
                      : 'border-border hover:border-primary'
                  )}
                >
                  {selectedBooks.size === books.length && books.length > 0 && (
                    <svg className="w-3 h-3 text-primary-foreground" viewBox="0 0 12 12">
                      <path
                        fill="currentColor"
                        d="M10 3L4.5 8.5L2 6"
                        stroke="currentColor"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  )}
                </div>
              </th>

              {/* Cover */}
              <th className="w-16 p-3"></th>

              {/* Title */}
              <th className="text-left p-3">
                <button
                  onClick={() => handleSort('title')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Title
                  <SortIcon field="title" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Author */}
              <th className="text-left p-3">
                <button
                  onClick={() => handleSort('author')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Author
                  <SortIcon field="author" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Series */}
              <th className="text-left p-3 hidden xl:table-cell">
                <span className="font-semibold text-sm">Series</span>
              </th>

              {/* Rating */}
              <th className="text-left p-3 hidden lg:table-cell">
                <button
                  onClick={() => handleSort('rating')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Rating
                  <SortIcon field="rating" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Format */}
              <th className="text-left p-3 hidden md:table-cell">
                <button
                  onClick={() => handleSort('format')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Format
                  <SortIcon field="format" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Size */}
              <th className="text-left p-3 hidden lg:table-cell">
                <button
                  onClick={() => handleSort('size')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Size
                  <SortIcon field="size" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Date Added */}
              <th className="text-left p-3 hidden xl:table-cell">
                <button
                  onClick={() => handleSort('date')}
                  className="flex items-center gap-2 font-semibold text-sm hover:text-primary transition-colors"
                >
                  Added
                  <SortIcon field="date" sortField={sortField} sortDirection={sortDirection} />
                </button>
              </th>

              {/* Actions */}
              <th className="w-12 p-3"></th>
            </tr>
          </thead>

          <tbody>
            {sortedBooks.map((book) => {
              const isSelected = selectedBooks.has(book.id!)

              return (
                <tr
                  key={book.id}
                  onClick={() => onOpenBook(book.id!)}
                  className={cn(
                    'group border-b hover:bg-accent/50 transition-colors cursor-pointer',
                    isSelected && 'bg-accent'
                  )}
                >
                  {/* Checkbox */}
                  <td className="p-3">
                    <div
                      onClick={(e) => {
                        e.stopPropagation()
                        onSelectBook(book.id!)
                      }}
                      className={cn(
                        'w-5 h-5 rounded-md border-2 flex items-center justify-center mx-auto',
                        'transition-all cursor-pointer',
                        isSelected
                          ? 'border-primary bg-primary'
                          : 'border-border hover:border-primary'
                      )}
                    >
                      {isSelected && (
                        <svg className="w-3 h-3 text-primary-foreground" viewBox="0 0 12 12">
                          <path
                            fill="currentColor"
                            d="M10 3L4.5 8.5L2 6"
                            stroke="currentColor"
                            strokeWidth="2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                          />
                        </svg>
                      )}
                    </div>
                  </td>

                  {/* Cover */}
                  <td className="p-3">
                    <div className="w-10 h-14 bg-muted rounded overflow-hidden">
                       {book.cover_path ? (
                         <img
                           src={resolveCoverSrc(book.cover_path)}
                           alt={book.title}
                           loading="lazy"
                           decoding="async"
                            className="w-full h-full object-cover bg-muted"
                         />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-muted to-muted/50">
                          <BookOpen className="w-5 h-5 text-muted-foreground/30" />
                        </div>
                      )}
                    </div>
                  </td>

                  {/* Title */}
                  <td className="p-3">
                    <div className="max-w-xs">
                      <p className="font-medium text-sm truncate">{book.title}</p>
                      {book.tags && book.tags.length > 0 && (
                        <div className="flex gap-1 mt-1">
                          {book.tags.slice(0, 2).map((tag, idx) => (
                            <Badge key={idx} variant="secondary" className="text-xs">
                              {tag.name}
                            </Badge>
                          ))}
                          {book.tags.length > 2 && (
                            <Badge variant="outline" className="text-xs">
                              +{book.tags.length - 2}
                            </Badge>
                          )}
                        </div>
                      )}
                    </div>
                  </td>

                  {/* Author */}
                  <td className="p-3">
                    <p className="text-sm text-muted-foreground truncate max-w-xs">
                      {book.authors?.map(a => a.name).join(', ') || 'Unknown'}
                    </p>
                  </td>

                  {/* Series */}
                  <td className="p-3 hidden xl:table-cell">
                    <p className="text-sm text-muted-foreground truncate max-w-xs">
                      {book.series || '—'}
                    </p>
                  </td>

                  {/* Rating */}
                  <td className="p-3 hidden lg:table-cell">
                    {book.rating && book.rating > 0 ? (
                      <div className="flex items-center gap-1">
                        <Star className="w-3.5 h-3.5 fill-yellow-400 text-yellow-400" />
                        <span className="text-sm">{book.rating}</span>
                      </div>
                    ) : (
                      <span className="text-sm text-muted-foreground">—</span>
                    )}
                  </td>

                  {/* Format */}
                  <td className="p-3 hidden md:table-cell">
                    <Badge variant="outline" className="text-xs uppercase">
                      {book.file_format}
                    </Badge>
                  </td>

                  {/* Size */}
                  <td className="p-3 hidden lg:table-cell">
                    <span className="text-sm text-muted-foreground">
                      {book.file_size ? formatFileSize(book.file_size) : '—'}
                    </span>
                  </td>

                  {/* Date Added */}
                  <td className="p-3 hidden xl:table-cell">
                    <span className="text-sm text-muted-foreground">
                      {formatDate(book.added_date)}
                    </span>
                  </td>

                  {/* Actions */}
                  <td className="p-3">
                    <DropdownMenu>
                      <DropdownMenuTrigger
                        onClick={(e) => e.stopPropagation()}
                        className="p-1.5 rounded hover:bg-accent transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <MoreVertical className="w-4 h-4" />
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            onViewDetails?.(book.id!)
                          }}
                        >
                          <Info className="w-4 h-4 mr-2" />
                          View Details
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            onOpenBook(book.id!)
                          }}
                        >
                          <BookOpen className="w-4 h-4 mr-2" />
                          Open
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            onEditBook(book.id!)
                          }}
                        >
                          <Edit className="w-4 h-4 mr-2" />
                          Edit Metadata
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            onDownloadBook(book.id!)
                          }}
                        >
                          <Download className="w-4 h-4 mr-2" />
                          Download
                        </DropdownMenuItem>

                        <DropdownMenuSeparator />
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            onDeleteBook(book.id!)
                          }}
                          className="text-destructive focus:text-destructive"
                        >
                          <Trash2 className="w-4 h-4 mr-2" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>
    </div>
  )
}

/**
 * SeriesCard — Shiori v3.0
 *
 * Displays a manga/comic series as a stacked 3D card with:
 * - 3-layer depth effect (two offset background layers behind the cover)
 * - 2:3 aspect ratio cover with lazy loading
 * - Volume count badge with Layers icon
 * - Series title + author metadata strip
 * - Hover animations matching PremiumBookCard
 * - Entrance animation via CSS class
 */

import { useState, useEffect, useRef, memo } from "react";
import { Layers } from "lucide-react";
import { cn } from "@/lib/utils";
import { useCoverImage } from "../common/hooks/useCoverImage";
import type { SeriesCardProps } from "./types";
import { IconBookOpen } from "@/components/icons/ShioriIcons";
import * as ContextMenu from "@radix-ui/react-context-menu";
import { Edit2, SplitSquareHorizontal, Trash2 } from "lucide-react";
import { SeriesManagementDialog } from "./SeriesManagementDialog";
import { api } from "@/lib/tauri";
import { useLibraryStore } from "@/store/libraryStore";
import { useToast } from "@/store/toastStore";

// ─── Shimmer Skeleton ─────────────────────────
const CoverSkeleton = () => (
  <div className="absolute inset-0 shimmer rounded-t-[inherit]" />
);

// ─── Main Card ────────────────────────────────
export const SeriesCard = memo(function SeriesCard({
  series,
  isSelected,
  onSelect,
  onOpen,
  animationDelay = 0,
  scrollRoot,
}: SeriesCardProps) {
  const [imgLoaded, setImgLoaded] = useState(false);
  const [imgError, setImgError] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  const [managementOpen, setManagementOpen] = useState(false);
  const [managementTab, setManagementTab] = useState<
    "edit" | "volumes" | "merge"
  >("edit");
  const toast = useToast();

  const handleEditSeries = () => {
    setManagementTab("edit");
    setManagementOpen(true);
  };

  const handleManageVolumes = () => {
    setManagementTab("volumes");
    setManagementOpen(true);
  };

  const handleDeleteSeries = async () => {
    try {
      const list = await api.getMangaSeriesList(1000, 0);
      const targetSeries = list.find(s => s.title.toLowerCase() === series.title.toLowerCase());

      if (targetSeries && targetSeries.id !== undefined) {
          await api.deleteMangaSeries(targetSeries.id);
      }

      const bookIds = series.books.map(b => b.id).filter((id): id is number => id !== undefined);
      if (bookIds.length > 0) {
          await api.deleteBooks(bookIds);
      }

      toast.success("Series deleted");
      await useLibraryStore.getState().loadInitialBooks();
    } catch (err) {
        toast.error("Error", "Failed to delete series");
    }
  };

  const handleUngroupAll = async () => {
    try {
      for (const book of series.books) {
        if (book.id) {
          await api.removeBookFromSeries(book.id);
        }
      }
      toast.success("Ungrouped", "All volumes removed from series.");
      await useLibraryStore.getState().loadInitialBooks();
    } catch (err) {
      toast.error("Error", "Failed to ungroup volumes");
    }
  };

  // Use the first book's cover as the series cover
  const firstBook = series.books[0];
  const { coverUrl, loading: coverLoading } = useCoverImage(
    visible ? firstBook?.id : undefined,
    firstBook?.cover_path
  );

  useEffect(() => {
    const el = cardRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { root: scrollRoot ?? null, threshold: 0.05 },
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [scrollRoot]);

  const handleClick = (e: React.MouseEvent) => {
    if ((e.shiftKey || e.ctrlKey || e.metaKey) && onSelect) {
      onSelect(series.id);
    } else {
      onOpen?.(series);
    }
  };

  return (
    <>
      <ContextMenu.Root>
        <ContextMenu.Trigger asChild>
          <div
            ref={cardRef}
            onClick={handleClick}
            style={{ animationDelay: `${animationDelay}ms` }}
            className={cn(
              "group relative flex flex-col cursor-pointer select-none",
              !visible && "opacity-0",
              visible && "animate-card-in",
            )}
          >
            {/* ── Stacked Depth Effect Container ── */}
            <div className="relative">
              {/* Layer 3 (back-most) — offset right and down */}
              <div
                className={cn(
                  "absolute inset-0 rounded-md",
                  "bg-muted border border-border/40",
                  "translate-x-2 translate-y-2",
                  "transition-transform duration-[150ms]",
                  "group-hover:translate-x-2.5 group-hover:translate-y-2.5",
                )}
              />

              {/* Layer 2 (middle) — offset slightly */}
              <div
                className={cn(
                  "absolute inset-0 rounded-md",
                  "bg-muted/80 border border-border/50",
                  "translate-x-1 translate-y-1",
                  "transition-transform duration-[150ms]",
                  "group-hover:translate-x-1.5 group-hover:translate-y-1.5",
                )}
              />

              {/* Layer 1 (front cover) — the actual card */}
              <div
                className={cn(
                  "relative rounded-md overflow-hidden",
                  "bg-card border border-border",
                  "transition-all duration-[150ms]",
                  isSelected
                    ? "ring-2 ring-primary border-primary shadow-md"
                    : "hover:border-border/80 hover:shadow-md hover:-translate-y-px",
                  "border-[var(--manga-accent)]/20",
                )}
              >
                {/* ── Cover Area (2:3 ratio) ── */}
                <div className="relative aspect-[2/3] bg-muted overflow-hidden">
                  {/* Skeleton */}
                  {(coverLoading || !imgLoaded) && !imgError && (
                    <CoverSkeleton />
                  )}

                  {/* Cover image */}
                  {coverUrl && !imgError && (
                    <img
                      src={coverUrl}
                      alt={series.title}
                      loading="lazy"
                      decoding="async"
                      onLoad={() => setImgLoaded(true)}
                      onError={() => setImgError(true)}
                      className={cn(
                        "absolute inset-0 w-full h-full object-cover bg-muted",
                        "transition-opacity duration-300",
                        imgLoaded ? "opacity-100" : "opacity-0",
                      )}
                    />
                  )}

                  {/* Fallback (no cover) */}
                  {(!coverUrl || imgError) && !imgLoaded && !coverLoading && (
                    <div
                      className={cn(
                        "absolute inset-0 flex flex-col items-center justify-center gap-2",
                        "bg-gradient-to-br from-muted to-muted/60",
                      )}
                    >
                      <IconBookOpen
                        size={32}
                        className="text-muted-foreground/25"
                      />
                      <p className="text-[9px] text-muted-foreground/40 text-center px-2 line-clamp-2 font-medium">
                        {series.title}
                      </p>
                    </div>
                  )}

                  {/* Hover overlay with "View Series" */}
                  <div
                    className={cn(
                      "absolute inset-0 flex items-center justify-center",
                      "bg-black/50 backdrop-blur-[2px]",
                      "opacity-0 group-hover:opacity-100",
                      "transition-opacity duration-[150ms]",
                      "rounded-t-[inherit]",
                    )}
                  >
                    <div
                      className={cn(
                        "flex items-center gap-1.5 px-3 py-1.5 rounded-lg",
                        "bg-background/90 backdrop-blur-sm",
                        "border border-border/60",
                        "text-foreground/80 text-xs font-medium",
                        "shadow-sm",
                      )}
                    >
                      <Layers className="w-3.5 h-3.5" />
                      View Series
                    </div>
                  </div>

                  {/* Volume count badge */}
                  <div
                    className={cn(
                      "absolute bottom-1.5 right-1.5 z-10",
                      "flex items-center gap-1 px-1.5 py-0.5 rounded",
                      "bg-[var(--manga-accent)] text-white",
                      "text-[9px] font-bold tracking-wide",
                    )}
                  >
                    <Layers className="w-2.5 h-2.5" />
                    {series.bookCount}
                  </div>
                </div>
              </div>
            </div>

            {/* ── Info Strip ── */}
            <div className="flex flex-col px-2 pt-2 pb-2.5 gap-0.5">
              <h3
                className="text-[11px] font-semibold leading-tight line-clamp-2 text-foreground"
                title={series.title}
              >
                {series.title}
              </h3>
              <p
                className="text-[10px] text-muted-foreground truncate"
                title={Array.from(series.authors).join(", ")}
              >
                {Array.from(series.authors).join(", ") || "Unknown Author"}
              </p>
            </div>
          </div>
        </ContextMenu.Trigger>
        <ContextMenu.Portal>
          <ContextMenu.Content className="min-w-[160px] bg-background border border-border rounded-md shadow-md p-1 z-50 text-sm">
            <ContextMenu.Item
              className="flex items-center px-2 py-1.5 rounded cursor-pointer hover:bg-muted outline-none"
              onClick={handleEditSeries}
            >
              <Edit2 className="w-4 h-4 mr-2" />
              Edit Series
            </ContextMenu.Item>
            <ContextMenu.Item
              className="flex items-center px-2 py-1.5 rounded cursor-pointer hover:bg-muted outline-none"
              onClick={handleManageVolumes}
            >
              <SplitSquareHorizontal className="w-4 h-4 mr-2" />
              Manage Volumes
            </ContextMenu.Item>
            <ContextMenu.Separator className="h-px bg-border my-1" />
            <ContextMenu.Item
              className="flex items-center px-2 py-1.5 rounded cursor-pointer hover:bg-destructive/10 text-destructive outline-none"
              onClick={handleUngroupAll}
            >
              <SplitSquareHorizontal className="w-4 h-4 mr-2" />
              Ungroup All
            </ContextMenu.Item>
            <ContextMenu.Item
              className="flex items-center px-2 py-1.5 rounded cursor-pointer hover:bg-destructive/10 text-destructive outline-none"
              onClick={handleDeleteSeries}
            >
              <Trash2 className="w-4 h-4 mr-2" />
              Delete Series
            </ContextMenu.Item>
          </ContextMenu.Content>
        </ContextMenu.Portal>
      </ContextMenu.Root>
      <SeriesManagementDialog
        open={managementOpen}
        onOpenChange={setManagementOpen}
        seriesTitle={series.title}
        ephemeralCover={series.firstCover}
        ephemeralBooks={series.books}
        initialTab={managementTab}
        onUpdated={() => useLibraryStore.getState().loadInitialBooks()}
      />
    </>
  );
});

import { convertFileSrc } from "@tauri-apps/api/core";
import { useState, useEffect } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import * as Tabs from '@radix-ui/react-tabs';
import { X, Save, ImagePlus, Split, Merge, Search } from 'lucide-react';
import { api, type MangaSeries, type Book } from '../../lib/tauri';
import { logger } from '@/lib/logger';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { MetadataSearchDialog } from './MetadataSearchDialog';

import { useToast } from '@/store/toastStore';

interface SeriesManagementDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  seriesId?: number;
  seriesTitle?: string;
  ephemeralCover?: string;
  ephemeralBooks?: Book[];
  initialTab?: 'edit' | 'volumes' | 'merge';
  onUpdated?: () => void;
}

export const SeriesManagementDialog = ({
  open,
  onOpenChange,
  seriesId,
  seriesTitle,
  ephemeralCover,
  ephemeralBooks,
  initialTab = 'edit',
  onUpdated
}: SeriesManagementDialogProps) => {
  const [loading, setLoading] = useState(true);
  const [volumes, setVolumes] = useState<Book[]>([]);
  const [allSeries, setAllSeries] = useState<MangaSeries[]>([]);
  const [resolvedSeriesId, setResolvedSeriesId] = useState<number | null>(seriesId ?? null);

  // Edit State
  const [title, setTitle] = useState('');
  const [sortTitle, setSortTitle] = useState('');
  const [status, setStatus] = useState('ongoing');
  const [coverPath, setCoverPath] = useState('');

  // Merge State
  const [targetSeriesId, setTargetSeriesId] = useState<number | null>(null);
  const [confirmMergeOpen, setConfirmMergeOpen] = useState(false);
  const [mergeTargetForConfirm, setMergeTargetForConfirm] = useState<number | null>(null);

  // Metadata Dialog State
  const [metadataDialogOpen, setMetadataDialogOpen] = useState(false);

  const toast = useToast();

  const getErrorMessage = (err: unknown) => {
    if (err instanceof Error) return err.message;
    if (typeof err === 'string') return err;
    if (err && typeof err === 'object') {
      const maybe = err as { userMessage?: string; message?: string; technicalDetails?: string };
      return maybe.userMessage || maybe.message || maybe.technicalDetails || JSON.stringify(err);
    }
    return String(err);
  };

  useEffect(() => {
    if (open) {
      loadData();
    }
  }, [open, seriesId, seriesTitle]);

  const loadData = async () => {
    try {
      setLoading(true);
      // Fetch series from all series list (we'll fetch limit 1000 for now to find it)
      const list = await api.getMangaSeriesList(1000, 0);
      setAllSeries(list);

      let targetSeries = null;
      if (seriesId) {
        targetSeries = list.find(s => s.id === seriesId);
      } else if (seriesTitle) {
        targetSeries = list.find(s => s.title.toLowerCase() === seriesTitle.toLowerCase());
      }

      if (targetSeries && targetSeries.id !== undefined) {
        setResolvedSeriesId(targetSeries.id);
        setTitle(targetSeries.title || '');
        setSortTitle(targetSeries.sort_title || '');
        setStatus(targetSeries.status || 'ongoing');
        setCoverPath(targetSeries.cover_path || '');

        const volRecords = await api.getSeriesVolumes(targetSeries.id);
        const bookPromises = volRecords.map(v => api.getBook(v.book_id));
        const loadedBooks = await Promise.all(bookPromises);
        setVolumes(loadedBooks.filter(b => b != null));
      } else {
        setResolvedSeriesId(null);
        setTitle(seriesTitle || '');
        setSortTitle(seriesTitle?.toLowerCase() || '');
        setStatus('ongoing');
        setCoverPath(ephemeralCover || '');
        if (ephemeralBooks) {
          setVolumes(ephemeralBooks);
        } else {
          setVolumes([]);
        }
      }
     } catch (err) {
       logger.error("Failed to load series data:", err);
       toast.error(`Failed to load series data: ${getErrorMessage(err)}`);
     } finally {
       setLoading(false);
     }
  };

  const handleSave = async () => {
    try {
      let targetId = resolvedSeriesId;

      // If the series doesn't exist in the database yet (ephemeral), create it first
      if (!targetId) {
        targetId = await api.createMangaSeries(title || seriesTitle || '');
        // Assign any ephemeral books to this newly created series
        if (ephemeralBooks) {
          for (const book of ephemeralBooks) {
            if (book.id) {
              await api.assignBookToSeries(book.id, title || seriesTitle || '', book.series_index);
            }
          }
        }
      }

      await api.updateMangaSeries(targetId, {
        title,
        sort_title: sortTitle,
        status,
        cover_path: coverPath
      });

       onUpdated?.();
       onOpenChange(false);
     } catch (err) {
       logger.error("Failed to update series:", err);
       toast.error(`Failed to update series: ${getErrorMessage(err)}`);
     }
  };

  const handlePickCover = async () => {
    try {
      const selected = await api.openFileDialog();
      if (selected && selected.length > 0) {
        setCoverPath(selected[0]);
      }
     } catch (err) {
       logger.error("Failed to pick cover:", err);
       toast.error(`Failed to pick cover: ${getErrorMessage(err)}`);
     }
  };

  const handleRemoveVolume = async (bookId: number) => {
    try {
      await api.removeBookFromSeries(bookId);

      const removed = volumes.find(v => v.id === bookId);
      setVolumes(volumes.filter(v => v.id !== bookId));
      onUpdated?.();

      if (removed && title) {
        toast.success('Volume removed', {
          action: {
            label: 'Undo',
            onClick: async () => {
              try {
                await api.assignBookToSeries(bookId, title, removed.series_index);
                await loadData();
                onUpdated?.();
              } catch (undoErr) {
                logger.error("Failed to undo volume removal:", undoErr);
                toast.error(`Failed to undo: ${getErrorMessage(undoErr)}`);
              }
            }
          }
        });
      } else {
        toast.success('Volume removed');
      }
     } catch (err) {
       logger.error("Failed to remove volume:", err);
       toast.error(`Failed to remove volume: ${getErrorMessage(err)}`);
     }
  };

  const handleMergeClick = () => {
    if (!targetSeriesId) return;
    setMergeTargetForConfirm(targetSeriesId);
    setConfirmMergeOpen(true);
  };

  const handleMergeConfirm = async () => {
    if (!mergeTargetForConfirm || !resolvedSeriesId) return;
    try {
      await api.mergeMangaSeries([resolvedSeriesId], mergeTargetForConfirm);
      toast.success('Series merged successfully');
      onUpdated?.();
      setConfirmMergeOpen(false);
      onOpenChange(false);
     } catch (err) {
       logger.error("Failed to merge series:", err);
       toast.error(`Failed to merge series: ${getErrorMessage(err)}`);
     }
  };

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-black/60 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content aria-describedby={undefined} className="dialog-content fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background border border-border rounded-xl shadow-2xl w-[90vw] max-w-2xl max-h-[85vh] flex flex-col z-50 overflow-hidden data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95">
          <div className="flex items-center justify-between px-6 py-4 border-b border-border bg-muted/30">
            <Dialog.Title className="text-lg font-semibold text-foreground tracking-tight">
              Manage Series
            </Dialog.Title>
             <Dialog.Close asChild>
               <button className="text-muted-foreground hover:text-foreground hover:bg-muted p-1.5 rounded-md transition-colors" title="Close">
                 <X className="h-5 w-5" />
               </button>
             </Dialog.Close>
          </div>

          {loading ? (
            <div className="flex-1 flex items-center justify-center p-12">
              <div className="w-8 h-8 border-2 border-primary border-t-transparent rounded-full animate-spin" />
            </div>
          ) : (
            <Tabs.Root defaultValue={initialTab} className="flex flex-col flex-1 overflow-hidden">
              <Tabs.List className="flex px-6 border-b border-border bg-muted/10">
                <Tabs.Trigger value="edit" className="px-4 py-3 text-sm font-medium text-muted-foreground data-[state=active]:text-foreground data-[state=active]:border-b-2 data-[state=active]:border-primary transition-colors">
                  Edit Details
                </Tabs.Trigger>
                <Tabs.Trigger value="volumes" className="px-4 py-3 text-sm font-medium text-muted-foreground data-[state=active]:text-foreground data-[state=active]:border-b-2 data-[state=active]:border-primary transition-colors">
                  Volumes ({volumes.length})
                </Tabs.Trigger>
                <Tabs.Trigger value="merge" className="px-4 py-3 text-sm font-medium text-muted-foreground data-[state=active]:text-foreground data-[state=active]:border-b-2 data-[state=active]:border-primary transition-colors">
                  Merge / Split
                </Tabs.Trigger>
              </Tabs.List>

              <div className="flex-1 overflow-y-auto p-6 bg-background">
                <Tabs.Content value="edit" className="space-y-6 outline-none">
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 sm:gap-8">
                    <div className="col-span-1 flex flex-col gap-3">
                      <div className="aspect-[2/3] sm:aspect-[2/3] bg-muted rounded-lg overflow-hidden border border-border relative flex items-center justify-center group">
                        {coverPath ? (
                          <img src={convertFileSrc(coverPath)} className="absolute inset-0 w-full h-full object-cover bg-muted" alt="Cover" />
                        ) : (
                          <div className="text-muted-foreground text-center p-4">
                            <ImagePlus className="w-8 h-8 mx-auto mb-2 opacity-50" />
                            <span className="text-xs">No Custom Cover</span>
                          </div>
                        )}
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <Button variant="secondary" size="sm" onClick={handlePickCover}>Choose File</Button>
                        </div>
                      </div>
                      {coverPath && (
                        <Button variant="outline" size="sm" className="w-full text-destructive hover:text-destructive" onClick={() => setCoverPath('')}>
                          Clear Custom Cover
                        </Button>
                      )}
                    </div>

                    <div className="sm:col-span-2 space-y-4">
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Series Title</label>
                        <Input value={title} onChange={e => setTitle(e.target.value)} placeholder="e.g. One Piece" className="bg-muted/50 focus:bg-background" />
                      </div>

                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Sort Title (Optional)</label>
                        <Input value={sortTitle} onChange={e => setSortTitle(e.target.value)} placeholder="e.g. one piece" className="bg-muted/50 focus:bg-background" />
                      </div>

                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Status</label>
                        <select 
                          value={status} 
                          onChange={e => setStatus(e.target.value)}
                          className="w-full px-3 py-2 text-sm bg-muted/50 border border-border rounded-md text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 dark:[color-scheme:dark] [&>option]:bg-popover [&>option]:text-popover-foreground"
                        >
                          <option value="ongoing">Ongoing</option>
                          <option value="completed">Completed</option>
                          <option value="hiatus">On Hiatus</option>
                          <option value="cancelled">Cancelled</option>
                        </select>
                      </div>
                    </div>
                  </div>

                  <div className="flex justify-end gap-3 pt-4 border-t border-border">
                    <Button 
                      variant="outline" 
                      onClick={() => setMetadataDialogOpen(true)} 
                      className="gap-2"
                      disabled={!resolvedSeriesId || !title.trim()}
                    >
                      <Search className="w-4 h-4" />
                      Find Metadata (AniList)
                    </Button>
                    <Button onClick={handleSave} className="gap-2">
                      <Save className="w-4 h-4" />
                      Save Changes
                    </Button>
                  </div>
                </Tabs.Content>

                <Tabs.Content value="volumes" className="space-y-4 outline-none">
                  {volumes.length === 0 ? (
                    <div className="text-center py-12 text-muted-foreground border-2 border-dashed border-border/50 rounded-xl">
                      No volumes found in this series.
                    </div>
                  ) : (
                    <div className="space-y-2">
                      {volumes.map(vol => (
                        <div key={vol.id} className="flex items-center justify-between p-3 rounded-lg border border-border bg-muted/20 hover:bg-muted/50 transition-colors">
                          <div className="flex items-center gap-3 overflow-hidden">
                            <div className="w-8 h-12 bg-muted rounded overflow-hidden flex-shrink-0">
                              {/* Thumbnail placeholder */}
                            </div>
                            <div className="truncate">
                              <div className="font-medium text-sm truncate" title={vol.title}>{vol.title}</div>
                              <div className="text-xs text-muted-foreground">Vol. {vol.series_index || '?'}</div>
                            </div>
                          </div>
                          <Button variant="ghost" size="sm" className="text-destructive hover:text-destructive hover:bg-destructive/10" onClick={() => handleRemoveVolume(vol.id!)}>
                            <Split className="w-4 h-4 mr-2" />
                            Ungroup
                          </Button>
                        </div>
                      ))}
                    </div>
                  )}
                </Tabs.Content>

                <Tabs.Content value="merge" className="space-y-6 outline-none">
                  <div className="p-4 rounded-xl bg-primary/10 border border-primary/20 text-sm text-primary">
                    Merging will move all volumes from this series into the selected target series, and then delete this series.
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Select Target Series</label>
                    <select 
                      value={targetSeriesId || ''} 
                      onChange={e => setTargetSeriesId(Number(e.target.value))}
                      className="w-full px-3 py-2.5 text-sm bg-muted/50 border border-border rounded-md text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 dark:[color-scheme:dark] [&>option]:bg-popover [&>option]:text-popover-foreground"
                    >
                      <option value="">-- Select a series --</option>
                      {allSeries.filter(s => s.id !== resolvedSeriesId).map(s => (
                        <option key={s.id} value={s.id}>{s.title} ({s.status})</option>
                      ))}
                    </select>
                  </div>

                  <div className="flex justify-end pt-4">
                    <Button 
                      variant="destructive" 
                      disabled={!targetSeriesId} 
                      onClick={handleMergeClick}
                      className="gap-2"
                    >
                      <Merge className="w-4 h-4" />
                      Merge into Target
                    </Button>
                  </div>
                </Tabs.Content>
              </div>
            </Tabs.Root>
          )}
        </Dialog.Content>
      </Dialog.Portal>

      {resolvedSeriesId && (
        <MetadataSearchDialog
          open={metadataDialogOpen}
          onOpenChange={setMetadataDialogOpen}
          bookIds={volumes.map(v => v.id!).filter(Boolean)}
          bookTitle={title}
          isManga={true}
          isbn={null}
          seriesId={resolvedSeriesId}
          onMetadataSelected={async () => {
            await loadData();
            onUpdated?.();
          }}
        />
      )}

      <Dialog.Root open={confirmMergeOpen} onOpenChange={setConfirmMergeOpen}>
        <Dialog.Portal>
          <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
          <Dialog.Content aria-describedby={undefined} className="dialog-content fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background border border-border rounded-xl shadow-2xl w-[90vw] max-w-md p-6 z-[60] data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95">
            <Dialog.Title className="text-lg font-semibold text-foreground mb-4">
              Confirm Series Merge
            </Dialog.Title>
            <div className="space-y-4 text-sm text-muted-foreground">
              <p>
                Move <strong>{volumes.length}</strong> volumes from <strong>{title}</strong> to <strong>{allSeries.find(s => s.id === mergeTargetForConfirm)?.title || 'Target'}</strong> and delete <strong>{title}</strong>. Cannot be undone.
              </p>
            </div>
            <div className="flex justify-end gap-3 mt-6">
              <Button variant="ghost" onClick={() => setConfirmMergeOpen(false)}>
                Cancel
              </Button>
              <Button variant="destructive" onClick={handleMergeConfirm}>
                Merge
              </Button>
            </div>
          </Dialog.Content>
        </Dialog.Portal>
      </Dialog.Root>
    </Dialog.Root>
  );
};

