import { memo, useState, useMemo, useRef, useEffect } from 'react'
import * as Dialog from '@radix-ui/react-dialog'
import * as DropdownMenu from '@radix-ui/react-dropdown-menu'
import {
  X, BookOpen, Layers, Search, SortDesc, SortAsc,
  Clock, CheckCircle2, Edit2, DownloadCloud, Trash2, List, LayoutGrid, Check, Play, MoreVertical
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { logger } from '@/lib/logger'
import { ScrollArea } from '@/components/ui/scroll-area'
import { PremiumBookCard } from './ModernBookCard'
import { useCoverImage } from '../common/hooks/useCoverImage'
import type { SeriesViewProps } from './types'
import { MetadataSearchDialog } from './MetadataSearchDialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { api, type Book } from '@/lib/tauri'
import { useToast } from '@/store/toastStore'

function getBookReadStatus(book: Book) {
  return book.reading_status || 'planning';
}

const SeriesHeader = memo(function SeriesHeader({
  series,
  onFindMetadata,
  onMarkAllRead,
  onDelete,
  onOpenBook,
}: {
  series: SeriesViewProps['series']
  onFindMetadata: () => void
  onMarkAllRead: () => void
  onDelete: () => void
  onOpenBook: (id: number) => void
}) {
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  if (!series) return null;
  const firstBook = series.books[0];
  const { coverUrl } = useCoverImage(firstBook?.id, firstBook?.cover_path)

  const totalPages = useMemo(() => series.books.reduce((acc, b) => acc + (b.page_count || 0), 0), [series.books]);

  // Find next unread book
  const sortedBooks = useMemo(() => [...series.books].sort((a, b) => (a.series_index ?? 0) - (b.series_index ?? 0)), [series.books]);
  const nextUnreadBook = useMemo(() => sortedBooks.find(b => getBookReadStatus(b) !== 'completed'), [sortedBooks]);
  const readBooks = series.books.length - sortedBooks.filter(b => getBookReadStatus(b) !== 'completed').length;
  const progressPercent = series.books.length > 0 ? Math.round((readBooks / series.books.length) * 100) : 0;

  const status = 'Ongoing';

  return (
    <div className="relative overflow-hidden shrink-0 border-b border-border bg-card">
      {/* Blurred Hero Background */}
      {coverUrl && (
        <>
          <div 
            className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-30 blur-3xl scale-110 saturate-150 transform-gpu dark:opacity-40"
            style={{ backgroundImage: `url(${coverUrl})` }}
          />
          <div className="absolute inset-0 bg-gradient-to-t from-background via-background/80 to-transparent" />
          <div className="absolute inset-0 bg-gradient-to-r from-background/90 via-background/40 to-transparent" />
        </>
      )}

      <div className="relative z-10 p-4 pt-14 md:p-8 flex flex-col gap-5 md:gap-8">

        {/* Top Section: Cover & Info */}
        <div className="flex flex-row gap-4 md:gap-8 items-start md:items-end w-full">
          {/* Cover */}
          <div className="w-24 h-36 md:w-48 md:h-72 rounded-lg overflow-hidden shadow-2xl border border-white/10 flex-shrink-0 bg-muted/50 transform transition-transform hover:scale-105 duration-300">
            {coverUrl ? (
              <img src={coverUrl} alt={series.title} className="w-full h-full object-cover" />
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center text-muted-foreground/30 bg-muted">
                <BookOpen className="w-8 h-8 md:w-12 md:h-12 mb-2" />
              </div>
            )}
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0 flex flex-col justify-start md:justify-end py-1 md:py-2 w-full text-left">
            <div className="flex flex-wrap items-center gap-2 mb-2 md:mb-3">
              <span className="px-2 py-0.5 md:px-2.5 md:py-1 rounded text-[10px] md:text-xs font-bold tracking-wider bg-primary text-primary-foreground shadow-sm uppercase">
                {status}
              </span>
              <span className="text-[10px] md:text-sm text-foreground/90 font-medium flex items-center gap-1 backdrop-blur-md bg-background/30 px-2 py-0.5 md:px-2.5 md:py-1 rounded border border-border/20">
                <Layers className="w-3 h-3 md:w-4 md:h-4" />
                {series.bookCount} {series.bookCount === 1 ? 'Vol' : 'Vols'}
              </span>
              {totalPages > 0 && (
                <span className="hidden md:flex text-sm text-foreground/90 font-medium items-center gap-1 backdrop-blur-md bg-background/30 px-2.5 py-1 rounded border border-border/20">
                  <BookOpen className="w-4 h-4" />
                  {totalPages.toLocaleString()} Pages
                </span>
              )}
            </div>

            <Dialog.Title className="text-xl sm:text-2xl md:text-5xl font-black text-foreground line-clamp-2 md:line-clamp-none md:truncate tracking-tight mb-1 md:mb-2 drop-shadow-md leading-tight break-words whitespace-normal">
              {series.title}
            </Dialog.Title>
            <p className="text-xs md:text-xl text-foreground/80 truncate font-medium drop-shadow-sm">
              {Array.from(series.authors).join(', ') || 'Unknown Author'}
            </p>
          </div>
        </div>

        {/* Actions Section */}
        <div className="flex flex-col md:flex-row items-center gap-4 md:gap-6 w-full mt-1 md:mt-2">
          {/* Primary & Secondary Buttons Group */}
          <div className="flex items-center gap-2 w-full md:w-auto">
            <Button 
              size="lg" 
              onClick={() => {
                if (nextUnreadBook?.id) onOpenBook(nextUnreadBook.id);
                else if (sortedBooks[0]?.id) onOpenBook(sortedBooks[0].id);
              }} 
              className="flex-1 md:flex-none md:w-48 gap-2 font-bold text-sm md:text-base shadow-lg shadow-primary/20 transition-all hover:scale-105 h-11 md:h-12"
            >
              <Play className="w-4 h-4 md:w-5 md:h-5 fill-current" /> 
              {nextUnreadBook ? `Continue Vol. ${nextUnreadBook.series_index || ''}` : 'Read Again'}
            </Button>

            <Button variant="secondary" size="lg" onClick={onMarkAllRead} className="w-12 h-11 md:h-12 md:w-12 shrink-0 px-0 bg-background/40 hover:bg-background/60 text-foreground border-border/20 backdrop-blur-md shadow-sm transition-colors" title="Mark All Read">
              <CheckCircle2 className="w-5 h-5" />
            </Button>

            <DropdownMenu.Root>
              <DropdownMenu.Trigger asChild>
                <Button variant="secondary" size="lg" className="w-12 h-11 md:h-12 md:w-12 shrink-0 px-0 bg-background/40 hover:bg-background/60 text-foreground border-border/20 backdrop-blur-md shadow-sm transition-colors">
                  <MoreVertical className="w-5 h-5" />
                </Button>
              </DropdownMenu.Trigger>
              <DropdownMenu.Portal>
                <DropdownMenu.Content align="end" className="w-48 bg-card border border-border/50 rounded-lg shadow-xl p-1 z-[100] animate-in fade-in zoom-in-95 data-[side=bottom]:slide-in-from-top-2">
                  <DropdownMenu.Item onSelect={onFindMetadata} className="flex items-center gap-2 px-3 py-2 text-sm text-foreground cursor-pointer outline-none hover:bg-accent hover:text-accent-foreground rounded-md transition-colors">
                    <Edit2 className="w-4 h-4" /> Edit Metadata
                  </DropdownMenu.Item>
                  <DropdownMenu.Separator className="h-px bg-border/50 my-1" />
                  {!showDeleteConfirm ? (
                    <DropdownMenu.Item onSelect={(e) => { e.preventDefault(); setShowDeleteConfirm(true); }} className="flex items-center gap-2 px-3 py-2 text-sm text-destructive cursor-pointer outline-none hover:bg-destructive/10 rounded-md transition-colors font-medium">
                      <Trash2 className="w-4 h-4" /> Ungroup Series
                    </DropdownMenu.Item>
                  ) : (
                    <div className="flex items-center justify-between p-2 bg-destructive/10 rounded-md">
                      <span className="text-xs text-destructive font-bold px-1">Sure?</span>
                      <div className="flex gap-1">
                        <Button variant="destructive" size="sm" onClick={onDelete} className="h-6 text-[10px] px-2 py-0">Yes</Button>
                        <Button variant="ghost" size="sm" onClick={() => setShowDeleteConfirm(false)} className="h-6 text-[10px] px-2 py-0 hover:bg-destructive/20 text-destructive">No</Button>
                      </div>
                    </div>
                  )}
                </DropdownMenu.Content>
              </DropdownMenu.Portal>
            </DropdownMenu.Root>
          </div>

          {/* Reading Progress */}
          <div className="flex-1 flex flex-col w-full max-w-none md:max-w-sm ml-0 md:ml-auto">
            <div className="flex items-center justify-between mb-1.5">
              <span className="text-[10px] md:text-xs font-bold text-foreground/80 uppercase tracking-wider drop-shadow-sm">Reading Progress</span>
              <span className="text-[10px] md:text-xs font-black text-primary drop-shadow-sm">{progressPercent}%</span>
            </div>
            <div className="h-1.5 md:h-2 w-full bg-background/60 backdrop-blur-sm rounded-full overflow-hidden border border-border/30 shadow-inner">
              <div className="h-full bg-primary transition-all duration-1000 ease-out" style={{ width: `${progressPercent}%` }} />
            </div>
          </div>
        </div>
      </div>
    </div>
  )
})

const ListBookCard = memo(function ListBookCard({
  book,
  isSelected,
  onSelect,
  onOpen,
}: {
  book: Book
  isSelected: boolean
  onSelect: (id: number) => void
  onOpen: (id: number) => void
}) {
  const { coverUrl } = useCoverImage(book.id, book.cover_path);
  const status = getBookReadStatus(book);
  const isRead = status === 'completed';

  return (
    <div 
      className={cn(
        "flex items-center gap-4 p-3 rounded-lg border transition-all cursor-pointer group",
        isSelected ? "bg-primary/5 border-primary shadow-sm" : "bg-card border-border hover:border-primary/50 hover:bg-muted/50"
      )}
      onClick={(e) => {
        if (e.shiftKey || e.ctrlKey || e.metaKey) {
          onSelect(book.id!);
        } else {
          onOpen(book.id!);
        }
      }}
    >
      <div className="w-12 h-16 rounded overflow-hidden bg-muted flex-shrink-0 relative">
        {coverUrl ? (
          <img src={coverUrl} alt={book.title} className="w-full h-full object-cover bg-muted" />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <BookOpen className="w-4 h-4 text-muted-foreground/30" />
          </div>
        )}
        {isRead && (
          <div className="absolute top-1 right-1 bg-green-500 rounded-full p-0.5 shadow-sm">
            <Check className="w-2 h-2 text-white" />
          </div>
        )}
      </div>

      <div className="flex-1 min-w-0">
        <h4 className="text-sm font-semibold text-foreground truncate group-hover:text-primary transition-colors">
          {book.title}
        </h4>
        <div className="flex items-center gap-3 mt-1 text-xs text-muted-foreground">
          {book.series_index !== undefined && (
            <span className="font-medium bg-muted px-1.5 py-0.5 rounded text-foreground/80">Vol. {book.series_index}</span>
          )}
          {book.page_count !== undefined && <span>{book.page_count} pages</span>}
          {status === 'reading' && <span className="text-blue-500 font-medium">Reading</span>}
        </div>
      </div>

      <Button 
        variant="ghost" 
        size="sm" 
        className="opacity-0 group-hover:opacity-100 transition-opacity"
        onClick={(e) => { e.stopPropagation(); onOpen(book.id!); }}
      >
        Read
      </Button>
    </div>
  );
});

export const SeriesView = memo(function SeriesView({
  series,
  isOpen,
  onClose,
  onSelectBook,
  onOpenBook,
  onViewDetailsBook,
  onEditBook,
  onDeleteBook,
  onFavoriteBook,
  selectedBookIds,
  favoritedBookIds,
}: SeriesViewProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'read' | 'unread'>('all');
  const [sortOrder, setSortOrder] = useState<'chapter_asc' | 'chapter_desc' | 'date_added'>('chapter_asc');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [metadataDialogOpen, setMetadataDialogOpen] = useState(false);
  const [metadataSeriesId, setMetadataSeriesId] = useState<number | null>(null);
  const [jumpInput, setJumpInput] = useState('');

  const toast = useToast();
  const bookRefs = useRef<Map<number, HTMLDivElement>>(new Map());

  useEffect(() => {
    if (isOpen) {
      setSearchQuery('');
      setFilterStatus('all');
      setJumpInput('');
      bookRefs.current.clear();
    }
  }, [isOpen, series?.id]);

  useEffect(() => {
    if (!isOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (/^[0-9]$/.test(e.key)) {
        const jumpInputEl = document.getElementById('chapter-jump-input');
        if (jumpInputEl) jumpInputEl.focus();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen]);

  const handleJumpSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!jumpInput) return;
    const targetChapter = parseFloat(jumpInput);
    if (isNaN(targetChapter)) return;

    const targetBook = series?.books.find(b => {
      let idx = b.series_index;
      if (idx == null || isNaN(idx)) {
          const m = b.title.match(/\d+/g);
          if (m) idx = parseFloat(m[m.length - 1]);
      }
      return idx === targetChapter;
    });
    if (targetBook && targetBook.id) {
      const el = bookRefs.current.get(targetBook.id);
      if (el) {
        el.scrollIntoView({ behavior: 'smooth', block: 'center' });
        el.classList.add('ring-2', 'ring-primary', 'ring-offset-2', 'rounded-lg');
        setTimeout(() => {
          el.classList.remove('ring-2', 'ring-primary', 'ring-offset-2', 'rounded-lg');
        }, 2000);
        setJumpInput('');
      } else {
        toast.info('Not Visible', 'The chapter is filtered out.');
      }
    } else {
      toast.error('Not Found', `Volume/Chapter ${targetChapter} is not in this series.`);
    }
  };

  const processedBooks = useMemo(() => {
    if (!series) return [];
    let result = [...series.books];
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(b => 
        b.title.toLowerCase().includes(q) || 
        (b.series_index !== undefined && b.series_index.toString() === q)
      );
    }
    if (filterStatus !== 'all') {
      result = result.filter(b => {
        const status = getBookReadStatus(b);
        return filterStatus === 'read' ? status === 'completed' : status !== 'completed';
      });
    }
    result.sort((a, b) => {
      if (sortOrder === 'chapter_asc') return (a.series_index ?? Infinity) - (b.series_index ?? Infinity);
      if (sortOrder === 'chapter_desc') return (b.series_index ?? -Infinity) - (a.series_index ?? -Infinity);
      if (sortOrder === 'date_added') return new Date(b.added_date).getTime() - new Date(a.added_date).getTime();
      return 0;
    });
    return result;
  }, [series, searchQuery, filterStatus, sortOrder]);

  if (!series) return null;

  const getErrorMessage = (err: unknown) => {
    if (err instanceof Error) return err.message;
    if (typeof err === 'string') return err;
    if (err && typeof err === 'object') {
      const maybe = err as { userMessage?: string; message?: string; technicalDetails?: string };
      return maybe.userMessage || maybe.message || maybe.technicalDetails || JSON.stringify(err);
    }
    return String(err);
  };

  const handleFindSeriesMetadata = async () => {
    if (!series) return;
    try {
      const list = await api.getMangaSeriesList(1000, 0);
      const match = list.find(s => s.title.toLowerCase() === series.title.toLowerCase());
      if (!match?.id) {
        toast.error('Series not found', 'Could not resolve this series in database.');
        return;
      }
      setMetadataSeriesId(match.id);
      setMetadataDialogOpen(true);
    } catch (err) {
      logger.error('Failed to resolve series ID for metadata:', err);
      toast.error('Metadata error', getErrorMessage(err));
    }
  };

  const handleDeleteSeries = async () => {
    try {
      const list = await api.getMangaSeriesList(1000, 0);
      const targetSeries = list.find(s => s.title.toLowerCase() === series.title.toLowerCase());

      if (targetSeries && targetSeries.id !== undefined) {
          await api.deleteMangaSeries(targetSeries.id);
      }

      const bookIds = series.books.map(b => b.id).filter((id): id is number => id !== undefined);
      if (bookIds.length > 0) {
          await api.deleteBooks(bookIds);
      }

      toast.success('Series Deleted', 'Series and all volumes have been deleted.');
      onClose();
     } catch (err) {
       logger.error(err);
       toast.error('Error', 'Failed to delete series.');
    }
  };

  const handleMarkAllRead = async () => {
    try {
      for (const book of series.books) {
        if (book.id && getBookReadStatus(book) !== 'completed') {
          await api.updateBook({ ...book, reading_status: 'completed' });
        }
      }
      toast.success('Updated', 'All volumes marked as read. Note: Refresh required to see changes.');
     } catch (err) {
       logger.error(err);
       toast.error('Error', 'Failed to mark volumes as read.');
    }
  };

  return (
    <Dialog.Root open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content aria-describedby={undefined}
          className={cn(
            'fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2',
            'bg-background border border-border/50 rounded-xl shadow-2xl',
            'w-[95vw] md:w-[90vw] max-w-6xl h-[90vh]',
            'flex flex-col z-50 overflow-hidden',
            'data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95'
          )}
        >
          <Dialog.Close asChild>
            <button className="absolute top-2 right-2 md:top-4 md:right-4 text-foreground/70 hover:text-foreground transition-colors flex-shrink-0 z-[60] bg-background/40 hover:bg-background/60 backdrop-blur-md p-2 rounded-full focus:outline-none focus:ring-2 focus:ring-primary border border-border/20 shadow-md" title="Close series view">
              <X className="h-4 w-4 md:h-5 md:w-5" />
            </button>
          </Dialog.Close>

          <ScrollArea className="flex-1 bg-background/50">
            <SeriesHeader 
              series={series} 
              onFindMetadata={handleFindSeriesMetadata}
              onDelete={handleDeleteSeries}
              onMarkAllRead={handleMarkAllRead}
              onOpenBook={onOpenBook}
            />

          <div className="flex flex-col md:flex-row items-center justify-between gap-4 p-4 border-b border-border bg-card/80 backdrop-blur-md shrink-0 sticky top-0 z-20 shadow-sm">
            <div className="flex items-center gap-2 w-full md:w-auto">
              <div className="relative flex-1 md:w-64 group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                <Input 
                  placeholder="Search volumes..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9 h-10 bg-background/50 border-border/50 focus-visible:ring-primary/20 rounded-full transition-all"
                />
              </div>
              <form onSubmit={handleJumpSubmit} className="relative flex-shrink-0 w-24 md:w-28 group">
                <Input 
                  id="chapter-jump-input"
                  placeholder="Jump..." 
                  value={jumpInput}
                  onChange={(e) => setJumpInput(e.target.value)}
                  className="h-10 bg-background/50 border-border/50 focus-visible:ring-primary/20 rounded-full text-center transition-all"
                />
              </form>
            </div>

            <div className="flex items-center gap-2 w-full md:w-auto justify-between md:justify-end overflow-x-auto pb-2 md:pb-0 scrollbar-none snap-x snap-mandatory">
              <div className="flex items-center bg-background/50 border border-border/50 rounded-full p-1 shadow-inner shrink-0 snap-center">
                <button onClick={() => setFilterStatus('all')} className={cn("px-4 py-1.5 text-xs font-bold rounded-full transition-all duration-200", filterStatus === 'all' ? "bg-primary text-primary-foreground shadow-md" : "text-muted-foreground hover:text-foreground hover:bg-muted/50")}>All</button>
                <button onClick={() => setFilterStatus('unread')} className={cn("px-4 py-1.5 text-xs font-bold rounded-full transition-all duration-200", filterStatus === 'unread' ? "bg-primary text-primary-foreground shadow-md" : "text-muted-foreground hover:text-foreground hover:bg-muted/50")}>Unread</button>
                <button onClick={() => setFilterStatus('read')} className={cn("px-4 py-1.5 text-xs font-bold rounded-full transition-all duration-200", filterStatus === 'read' ? "bg-primary text-primary-foreground shadow-md" : "text-muted-foreground hover:text-foreground hover:bg-muted/50")}>Read</button>
              </div>

              <div className="flex items-center gap-1 bg-background/50 border border-border/50 rounded-full p-1 shadow-inner shrink-0 snap-center">
                <Button variant="ghost" size="icon" className={cn("h-8 w-8 rounded-full hover:bg-muted", sortOrder === 'chapter_asc' && "bg-muted text-foreground")} onClick={() => setSortOrder('chapter_asc')} title="Sort Ascending">
                  <SortAsc className="w-4 h-4" />
                </Button>
                <Button variant="ghost" size="icon" className={cn("h-8 w-8 rounded-full hover:bg-muted", sortOrder === 'chapter_desc' && "bg-muted text-foreground")} onClick={() => setSortOrder('chapter_desc')} title="Sort Descending">
                  <SortDesc className="w-4 h-4" />
                </Button>
                <Button variant="ghost" size="icon" className={cn("h-8 w-8 rounded-full hover:bg-muted", sortOrder === 'date_added' && "bg-muted text-foreground")} onClick={() => setSortOrder('date_added')} title="Sort by Date Added">
                  <Clock className="w-4 h-4" />
                </Button>
              </div>

              <div className="h-6 w-px bg-border/50 mx-1 hidden md:block shrink-0" />

              <div className="flex items-center bg-background/50 border border-border/50 rounded-full p-1 shadow-inner shrink-0 snap-center">
                <button onClick={() => setViewMode('grid')} className={cn("p-2 rounded-full transition-all duration-200", viewMode === 'grid' ? "bg-muted text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground")} title="Grid View">
                  <LayoutGrid className="w-4 h-4" />
                </button>
                <button onClick={() => setViewMode('list')} className={cn("p-2 rounded-full transition-all duration-200", viewMode === 'list' ? "bg-muted text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground")} title="List View">
                  <List className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>

          <div className="p-4 md:p-6 animate-in slide-in-from-bottom-4 fade-in duration-500 ease-out fill-mode-both">
              {processedBooks.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-muted-foreground border-2 border-dashed border-border/50 rounded-xl">
                  <Search className="w-12 h-12 mb-4 opacity-20" />
                  <h3 className="text-lg font-semibold text-foreground/80 mb-1">No volumes found</h3>
                  <p className="text-sm">Try adjusting your search or filters.</p>
                  {(searchQuery || filterStatus !== 'all') && (
                    <Button variant="link" onClick={() => { setSearchQuery(''); setFilterStatus('all'); }} className="mt-4">
                      Clear Filters
                    </Button>
                  )}
                </div>
              ) : (
                viewMode === 'grid' ? (
                  <div className="grid grid-cols-[repeat(auto-fill,minmax(130px,1fr))] sm:grid-cols-[repeat(auto-fill,minmax(160px,1fr))] md:grid-cols-[repeat(auto-fill,minmax(180px,1fr))] gap-3 md:gap-4">
                    {processedBooks.map((book, index) => (
                      <div 
                        key={book.id ?? book.uuid} 
                        ref={(el) => { if (book.id && el) bookRefs.current.set(book.id, el); }}
                        className="relative group transition-all duration-300"
                      >
                        <PremiumBookCard
                          book={book}
                          isSelected={selectedBookIds?.has(book.id!) ?? false}
                          onSelect={onSelectBook}
                          onOpen={onOpenBook}
                          onViewDetails={onViewDetailsBook}
                          onEdit={onEditBook}
                          onDelete={onDeleteBook}
                          isFavorited={favoritedBookIds?.has(book.id!) ?? false}
                          onFavorite={onFavoriteBook}
                          animationDelay={index * 20}
                        />
                        {getBookReadStatus(book) === 'completed' && (
                          <div className="absolute -top-2 -right-2 z-10 bg-green-500 rounded-full p-1 shadow-md shadow-green-500/20 animate-in zoom-in">
                            <Check className="w-3.5 h-3.5 text-white" strokeWidth={3} />
                          </div>
                        )}
                        {book.series_index !== undefined && (
                          <div className="absolute top-2 left-2 z-10 bg-background/90 backdrop-blur-md px-2 py-0.5 rounded text-[10px] font-black border border-border/50 shadow-sm opacity-0 group-hover:opacity-100 transition-opacity">
                            VOL {book.series_index}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col gap-2 max-w-4xl mx-auto">
                    {processedBooks.map((book) => (
                      <div 
                        key={book.id ?? book.uuid}
                        ref={(el) => { if (book.id && el) bookRefs.current.set(book.id, el); }}
                      >
                        <ListBookCard
                          book={book}
                          isSelected={selectedBookIds?.has(book.id!) ?? false}
                          onSelect={onSelectBook}
                          onOpen={onOpenBook}
                        />
                      </div>
                    ))}
                  </div>
                )
              )}
            </div>
          </ScrollArea>

          {metadataSeriesId && (
            <MetadataSearchDialog
              open={metadataDialogOpen}
              onOpenChange={setMetadataDialogOpen}
              bookIds={series.books.map((b) => b.id!).filter(Boolean)}
              bookTitle={series.title}
              isManga={true}
              isbn={null}
              seriesId={metadataSeriesId}
              onMetadataSelected={async () => {
                setMetadataDialogOpen(false);
              }}
            />
          )}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  )
})

import { useState } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { X, Loader2, CheckCircle, FolderPlus } from 'lucide-react';
import { api } from '../../lib/tauri';
import { logger } from '@/lib/logger';
import { useToast } from '../../store/toastStore';
import { useCollectionStore } from '../../store/collectionStore';
import type { CollectionSuggestion } from '../../lib/collectionSuggestions';

interface SmartCollectionSuggestionDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  suggestions: CollectionSuggestion[];
  successfulPaths: string[];
  onComplete?: () => void;
}

type CreationState = 'idle' | 'creating' | 'completed' | 'error';

export const SmartCollectionSuggestionDialog = ({
  open,
  onOpenChange,
  suggestions,
  successfulPaths,
  onComplete,
}: SmartCollectionSuggestionDialogProps) => {
  const [state, setState] = useState<CreationState>('idle');
  const [selectedCollections, setSelectedCollections] = useState<Set<string>>(
    new Set(suggestions.map(s => s.name))
  );
  const toast = useToast();
  const { addCollection } = useCollectionStore();

  const handleToggleCollection = (name: string) => {
    const newSelected = new Set(selectedCollections);
    if (newSelected.has(name)) {
      newSelected.delete(name);
    } else {
      newSelected.add(name);
    }
    setSelectedCollections(newSelected);
  };

  const handleSelectAll = () => {
    setSelectedCollections(new Set(suggestions.map(s => s.name)));
  };

  const handleClearAll = () => {
    setSelectedCollections(new Set());
  };

  const handleCreateCollections = async () => {
    setState('creating');

    try {
      const selectedSuggestions = suggestions.filter(s =>
        selectedCollections.has(s.name)
      );

      for (const suggestion of selectedSuggestions) {
        const collection = await api.createCollection({
          name: suggestion.name,
          description: `Auto-created from folder structure during import`,
          collection_type: 'regular',
        });

        if (collection.id) {
          addCollection(collection);

          const booksForCollection = await api.getBooks();
          const bookIdsToAdd = booksForCollection
            .filter(book =>
              suggestion.filePaths.some(
                path => book.file_path === path || book.file_path.endsWith(path)
              )
            )
            .map(book => book.id)
            .filter((id): id is number => id !== undefined);

          if (bookIdsToAdd.length > 0) {
            await api.addBooksToCollection(collection.id, bookIdsToAdd);
            logger.info(
              `[Collections] Added ${bookIdsToAdd.length} books to collection "${suggestion.name}"`
            );
          }
        }
      }

      setState('completed');
      toast.success(
        `Created ${selectedSuggestions.length} collection${selectedSuggestions.length !== 1 ? 's' : ''}`,
        'Books automatically organized into new collections'
      );

      setTimeout(() => {
        handleClose();
        onComplete?.();
      }, 1500);
    } catch (error) {
      logger.error('Failed to create collections:', error);
      setState('error');
      toast.error(
        'Failed to create collections',
        'An error occurred while creating collections'
      );
    }
  };

  const handleClose = () => {
    setState('idle');
    setSelectedCollections(new Set());
    onOpenChange(false);
  };

  if (suggestions.length === 0) {
    return null;
  }

  return (
    <Dialog.Root open={open} onOpenChange={handleClose}>
      <Dialog.Portal>
        <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-background/80 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content aria-describedby={undefined} className="dialog-content fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-background/80 backdrop-blur-3xl border border-border rounded-[1.5rem] shadow-2xl w-[600px] max-h-[90vh] overflow-y-auto z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 duration-300 custom-scrollbar outline-none">
          <div className="sticky top-0 bg-transparent backdrop-blur-xl border-b border-border px-6 py-5 z-10">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <FolderPlus className="w-6 h-6 text-primary" />
                <Dialog.Title className="text-xl font-bold tracking-tight text-foreground">
                  Smart Collection Suggestions
                </Dialog.Title>
              </div>
              <Dialog.Close asChild>
                <button
                  className="p-2.5 bg-secondary hover:bg-secondary/80 border border-transparent rounded-xl transition-all duration-200 text-muted-foreground hover:text-foreground"
                  title="Close"
                >
                  <X className="w-5 h-5" />
                </button>
              </Dialog.Close>
            </div>
          </div>

          <div className="p-6 space-y-4">
            {state === 'idle' && (
              <>
                <div className="bg-secondary/20 border border-border rounded-xl p-4">
                  <p className="text-sm text-foreground/80">
                    We detected folder patterns in your imported books. Create
                    collections to auto-organize them?
                  </p>
                </div>

                <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar pr-2">
                  {suggestions.map(suggestion => (
                    <label
                      key={suggestion.name}
                      className="flex items-center gap-3 p-3 border border-border rounded-xl bg-card/30 hover:bg-card/60 cursor-pointer transition-colors"
                    >
                      <input
                        type="checkbox"
                        checked={selectedCollections.has(suggestion.name)}
                        onChange={() =>
                          handleToggleCollection(suggestion.name)
                        }
                        className="w-4 h-4 rounded border-border bg-secondary text-primary focus:ring-primary/50"
                      />
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-foreground truncate">
                          {suggestion.name}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          {suggestion.bookCount} book
                          {suggestion.bookCount !== 1 ? 's' : ''}
                        </div>
                      </div>
                    </label>
                  ))}
                </div>

                <div className="flex gap-2 pt-2">
                  <button
                    onClick={handleSelectAll}
                    className="text-sm px-3 py-1 text-muted-foreground hover:text-foreground font-medium transition-colors"
                  >
                    Select All
                  </button>
                  <button
                    onClick={handleClearAll}
                    className="text-sm px-3 py-1 text-muted-foreground hover:text-foreground font-medium transition-colors"
                  >
                    Clear All
                  </button>
                </div>

                <div className="flex gap-3 pt-6 border-t border-border mt-2">
                  <button
                    onClick={handleClose}
                    className="flex-1 px-5 py-2.5 bg-transparent hover:bg-secondary border border-transparent hover:border-border rounded-xl transition-all duration-200 font-medium text-muted-foreground hover:text-foreground"
                  >
                    Skip
                  </button>
                  <button
                    onClick={handleCreateCollections}
                    disabled={selectedCollections.size === 0}
                    className="flex-1 px-6 py-2.5 bg-primary hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed text-primary-foreground rounded-xl shadow-sm transition-all duration-200 flex items-center justify-center gap-2 font-semibold"
                  >
                    <FolderPlus className="w-4 h-4" />
                    Create {selectedCollections.size} Collection
                    {selectedCollections.size !== 1 ? 's' : ''}
                  </button>
                </div>
              </>
            )}

            {state === 'creating' && (
              <div className="flex flex-col items-center justify-center py-12">
                <div className="p-6 bg-card/40 backdrop-blur-md border border-primary/20 rounded-[2rem] shadow-inner shadow-primary/10 mb-6">
                  <Loader2 className="w-12 h-12 text-primary animate-spin" />
                </div>
                <div className="text-xl font-bold tracking-tight text-foreground">
                  Creating collections...
                </div>
                <div className="text-sm text-muted-foreground mt-2">
                  Organizing your books
                </div>
              </div>
            )}

            {state === 'completed' && (
              <div className="flex flex-col items-center justify-center py-12">
                <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-[2rem] shadow-inner shadow-emerald-500/10 mb-6">
                  <CheckCircle className="w-12 h-12 text-emerald-500" />
                </div>
                <div className="text-xl font-bold tracking-tight text-foreground">Collections Created!</div>
                <div className="text-sm text-muted-foreground mt-2">
                  {selectedCollections.size} collection
                  {selectedCollections.size !== 1 ? 's' : ''} ready to use
                </div>
              </div>
            )}

            {state === 'error' && (
              <div className="flex flex-col items-center justify-center py-12">
                <div className="text-xl font-bold tracking-tight text-destructive">
                  Failed to create collections
                </div>
                <button
                  onClick={() => setState('idle')}
                  className="mt-6 px-6 py-2.5 bg-secondary hover:bg-secondary/80 text-secondary-foreground border border-border rounded-xl transition-all duration-200 font-medium"
                >
                  Try Again
                </button>
              </div>
            )}
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
};

import { useLibraryStore } from '@/store/libraryStore'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
  DropdownMenuLabel,
} from '@/components/ui/dropdown-menu'
import { cn } from '@/lib/utils'
import { ArrowDownUp, Check, ChevronDown, ChevronUp } from 'lucide-react'

const SORT_OPTIONS = [
  { id: 'added_date', label: 'Date Added' },
  { id: 'title', label: 'Title' },
  { id: 'author', label: 'Author' },
  { id: 'pubdate', label: 'Release Date' },
  { id: 'rating', label: 'Rating' },
]

export function SortDropdown() {
  const sortBy = useLibraryStore((s) => s.sortBy)
  const sortOrder = useLibraryStore((s) => s.sortOrder)
  const setSort = useLibraryStore((s) => s.setSort)
  const loadInitialBooks = useLibraryStore((s) => s.loadInitialBooks)

  const handleSortChange = (newSortBy: string) => {
    if (sortBy === newSortBy) {
      // Toggle order
      const newOrder = sortOrder === 'asc' ? 'desc' : 'asc'
      setSort(newSortBy, newOrder)
    } else {
      // Set new sort with default descending (except title and author which make more sense ascending)
      const newOrder = (newSortBy === 'title' || newSortBy === 'author') ? 'asc' : 'desc'
      setSort(newSortBy, newOrder)
    }
    // Reload books
    loadInitialBooks()
  }

  const handleOrderToggle = (e: React.MouseEvent) => {
    e.stopPropagation()
    const newOrder = sortOrder === 'asc' ? 'desc' : 'asc'
    setSort(sortBy, newOrder)
    loadInitialBooks()
  }

  const currentLabel = SORT_OPTIONS.find((o) => o.id === sortBy)?.label || 'Sort'

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          type="button"
          className={cn(
            'flex items-center gap-1.5 h-8 px-2.5 rounded-md border border-border',
            'text-xs font-medium text-muted-foreground hover:text-foreground hover:bg-accent',
            'transition-all duration-[120ms]',
            'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring'
          )}
        >
          <ArrowDownUp size={14} />
          <span>{currentLabel}</span>
          {sortOrder === 'asc' ? (
            <ChevronUp size={12} className="opacity-70" />
          ) : (
            <ChevronDown size={12} className="opacity-70" />
          )}
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-48">
        <DropdownMenuLabel className="text-xs text-muted-foreground">Sort By</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {SORT_OPTIONS.map((option) => (
          <DropdownMenuItem
            key={option.id}
            onClick={() => handleSortChange(option.id)}
            className="flex items-center justify-between cursor-pointer"
          >
            <span>{option.label}</span>
            {sortBy === option.id && (
              <span className="flex items-center gap-2">
                <span className="text-[10px] text-muted-foreground uppercase">
                  {sortOrder}
                </span>
                <Check size={14} className="text-primary" />
              </span>
            )}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

import React, { memo, useCallback, useRef, useState } from 'react';
import { useUnifiedImageDecode } from './hooks/useUnifiedImageDecode';
import { useMangaSettingsStore } from '@/store/mangaReaderStore';
import { getEffectiveMaxDimension } from './hooks/useMangaPreloader';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface MangaPageImageProps {
    pageIndex: number;
    maxDimension?: number;
    className?: string;
    style?: React.CSSProperties;
    onLoad?: () => void;
    imageRef?: React.Ref<HTMLImageElement>;
}

/**
 * Core manga page image component.
 * Works with both local (IPC) and online (URL) sources via unified hook.
 * Handles loading states, error states, and fit-mode rendering.
 * Memoized to prevent re-renders when parent state changes.
 */
export const MangaPageImage = memo(function MangaPageImage({
    pageIndex,
    maxDimension,
    className = '',
    style,
    onLoad,
    imageRef,
}: MangaPageImageProps) {
    const fitMode = useMangaSettingsStore(s => s.fitMode);
    const zoomLevel = useMangaSettingsStore(s => s.zoomLevel);

    // Use the centralized maxDimension calculation so cache keys match preloading
    const effectiveMaxDimension = maxDimension ?? getEffectiveMaxDimension();

    // Unified hook handles both local and online sources
    const { url, loading, error, retry } = useUnifiedImageDecode(pageIndex, effectiveMaxDimension);
    const [imgLoaded, setImgLoaded] = useState(false);
    const imgRef = useRef<HTMLImageElement>(null);

    // Combine internal ref (for decode) and external ref (for virtualization)
    const setRefs = useCallback(
        (node: HTMLImageElement | null) => {
            imgRef.current = node;
            if (typeof imageRef === 'function') {
                imageRef(node);
            } else if (imageRef && typeof imageRef === 'object') {
                // Use Object.assign to avoid direct mutation warning
                Object.assign(imageRef, { current: node });
            }
        },
        [imageRef]
    );

    const handleImageLoad = useCallback(() => {
        setImgLoaded(true);
        onLoad?.();

        // Use decode() API for smoother paint
        const img = imgRef.current;
        if (img && 'decode' in img) {
            img.decode?.().catch(() => { });
        }
    }, [onLoad]);

    if (error) {
        return (
            <div className="manga-page-error" style={style}>
                <AlertTriangle />
                <span>Failed to load page {pageIndex + 1}</span>
                <span style={{ fontSize: '11px', opacity: 0.6 }}>{error}</span>
                <button
                    type="button"
                    onClick={retry}
                    className="manga-page-retry-btn"
                    title="Retry loading this page"
                >
                    <RefreshCw size={14} />
                    <span>Retry</span>
                </button>
            </div>
        );
    }

    const fitClass = `manga-page-img--fit-${fitMode}`;
    const loadingClass = imgLoaded ? 'manga-page-img--loaded' : 'manga-page-img--loading';

    return (
        <>
            {(!url || !imgLoaded) && (
                <div
                    className="manga-page-skeleton"
                    style={{
                        width: '100%',
                        maxWidth: '800px',
                        aspectRatio: '2/3',
                        transform: `scale(${zoomLevel})`,
                        transformOrigin: 'top center',
                        transition: 'transform 0.2s ease-in-out',
                        ...style,
                    }}
                />
            )}
            {url && (
                <img
                    ref={setRefs}
                    src={url}
                    alt={`Page ${pageIndex + 1}`}
                    className={`manga-page-img ${fitClass} ${loadingClass} ${className}`}
                    style={{
                        ...style,
                        position: imgLoaded ? 'relative' : 'absolute',
                        top: 0,
                        left: 0,
                        visibility: imgLoaded ? 'visible' : 'hidden',
                        transform: `scale(${zoomLevel})`,
                        transformOrigin: 'top center',
                        transition: 'transform 0.2s ease-in-out',
                    }}
                    onLoad={handleImageLoad}
                    draggable={false}
                    decoding="async"
                />
            )}
        </>
    );
});

import { useEffect, useCallback, useRef } from 'react';
import {
    useMangaContentStore,
    useMangaUIStore,
    useMangaSettingsStore,
    type OnlineSourceConfig,
} from '@/store/mangaReaderStore';
import { api } from '@/lib/tauri';
import { logger } from '@/lib/logger';
import { useToastStore } from '@/store/toastStore';
import { useLibraryStore } from '@/store/libraryStore';
import { MangaCanvas } from './MangaCanvas';
import { MangaSidebar } from './MangaSidebar';
import { AdvancedSettingsPanel } from './AdvancedSettingsPanel';
import { MangaProgressBar } from './MangaProgressBar';
import { NavigationOverlay } from './NavigationOverlay';
import { MangaReaderHeader } from './MangaReaderHeader';
import { useMangaKeyboard } from './hooks/useMangaKeyboard';
import { imageCache } from './hooks/useMangaPreloader';
import { clearOnlineImageCache } from './hooks/useUnifiedImageDecode';

// Import manga reader styles
import '@/styles/manga-reader.css';

const PLACEHOLDER: [number, number] = [800, 1200];

// Props for local manga
interface LocalMangaReaderProps {
    mode: 'local';
    bookId: number;
    bookPath: string;
    title?: string;
    totalPages?: number;
    onClose: () => void;
    onNextChapter?: () => void;
}

// Props for online manga
interface OnlineMangaReaderProps {
    mode: 'online';
    sourceConfig: OnlineSourceConfig;
    onClose: () => void;
    onChapterChange?: (chapterId: string) => Promise<{ pageUrls: string[]; chapterTitle: string }>;
    onNextChapter?: () => void;
}

export type MangaReaderProps = LocalMangaReaderProps | OnlineMangaReaderProps;

/**
 * Root manga reader component.
 * Full-screen overlay orchestrating all sub-components.
 * Supports both local files and online sources.
 */
export function MangaReader(props: MangaReaderProps) {
    const { onClose, onNextChapter } = props;
    const mode = props.mode;

    const openManga = useMangaContentStore(s => s.openManga);
    const openOnlineManga = useMangaContentStore(s => s.openOnlineManga);
    const closeManga = useMangaContentStore(s => s.closeManga);
    const sourceType = useMangaContentStore(s => s.sourceType);
    const currentPage = useMangaContentStore(s => s.currentPage);
    const setCurrentPage = useMangaContentStore(s => s.setCurrentPage);
    const setOnlineChapter = useMangaContentStore(s => s.setOnlineChapter);
    const mangaTotalPages = useMangaContentStore(s => s.totalPages);
    const pageDimensions = useMangaContentStore(s => s.pageDimensions);
    const mergePageDimensions = useMangaContentStore(s => s.mergePageDimensions);
    const isLoading = useMangaContentStore(s => s.isLoading);
    const error = useMangaContentStore(s => s.error);
    const setLoading = useMangaContentStore(s => s.setLoading);
    const setError = useMangaContentStore(s => s.setError);
    const bookId = useMangaContentStore(s => s.bookId);
    const onlineSource = useMangaContentStore(s => s.onlineSource);
    const resetUI = useMangaUIStore(s => s.resetUI);
    const theme = useMangaSettingsStore(s => s.theme);

    // Guard: don't save progress until initialization + resume is complete
    const initCompleteRef = useRef(false);

    // Extract stable values from props for dependencies
    const localBookId = mode === 'local' ? props.bookId : null;
    const localBookPath = mode === 'local' ? props.bookPath : null;
    const localTitle = mode === 'local' ? (props.title ?? '') : '';
    const localTotalPages = mode === 'local' ? (props.totalPages ?? 0) : 0;
    const onlineConfig = mode === 'online' ? props.sourceConfig : null;
    const onlineOnChapterChange = mode === 'online' ? props.onChapterChange : undefined;

    // Always start each reader session with a clean UI state.
    useEffect(() => {
        resetUI();
    }, [resetUI]);

    // Initialize manga state based on mode
    useEffect(() => {
        let cancelled = false;

        const initLocal = async () => {
            if (localBookId === null || localBookPath === null) return;

            setLoading(true);
            setError(null);
            try {
                // Try to open via IPC
                const { invoke } = await import('@tauri-apps/api/core');
                const metadata = await invoke<{
                    title: string;
                    page_count: number;
                    page_dimensions?: [number, number][];
                }>('open_manga', { bookId: localBookId, path: localBookPath });

                if (cancelled) return;

                openManga(
                    localBookId,
                    localBookPath,
                    metadata.title || localTitle,
                    metadata.page_count || localTotalPages,
                    metadata.page_dimensions
                );

                // Load reading progress and resume from last page
                try {
                    const progress = await api.getReadingProgress(localBookId);
                    if (cancelled) return;
                    if (progress && progress.currentPage !== undefined) {
                        logger.debug('[MangaReader] Resuming from page:', progress.currentPage);
                        setCurrentPage(progress.currentPage);
                        if (progress.currentPage > 0) {
                            useToastStore.getState().addToast({
                                title: 'Resuming reading',
                                description: `Page ${progress.currentPage + 1} of ${metadata.page_count}`,
                                variant: 'info',
                                duration: 3000,
                            });
                        }
                    }
                } catch (progressErr) {
                    logger.warn('[MangaReader] Failed to load reading progress:', progressErr);
                }

                if (!cancelled) {
                    initCompleteRef.current = true;
                }
            } catch (err) {
                if (cancelled) return;
                logger.error('[MangaReader] Backend open_manga failed:', err);

                const errorStr = String(err).toLowerCase();
                if (localBookPath?.toLowerCase().endsWith('.cbr') || localBookPath?.toLowerCase().endsWith('.rar')) {
                    setError('CBR/RAR formats are not natively supported by the manga reader. Please convert the book to CBZ format or EPUB.');
                } else if (errorStr.includes('invalid') || errorStr.includes('unsupported')) {
                    setError('Failed to open manga: The archive may be corrupted or in an unsupported format.');
                } else {
                    setError(err instanceof Error ? err.message : String(err));
                }

                initCompleteRef.current = true;
            }
            if (!cancelled) {
                setLoading(false);
            }
        };

        const initOnline = async () => {
            if (!onlineConfig) return;

            setLoading(true);
            setError(null);

            try {
                openOnlineManga(onlineConfig);

                // Try to load saved progress for this online manga
                const progressKey = `online:${onlineConfig.sourceId}:${onlineConfig.contentId}`;
                try {
                    const savedProgress = localStorage.getItem(`shiori-manga-progress:${progressKey}`);
                    if (savedProgress) {
                        const { chapterId, page } = JSON.parse(savedProgress);
                        const savedPage = typeof page === 'number' ? Math.max(0, page) : 0;

                        if (chapterId === onlineConfig.chapterId && savedPage > 0) {
                            const clampedPage = Math.min(savedPage, Math.max(0, onlineConfig.pageUrls.length - 1));
                            setCurrentPage(clampedPage);
                            useToastStore.getState().addToast({
                                title: 'Resuming reading',
                                description: `Page ${clampedPage + 1} of ${onlineConfig.pageUrls.length}`,
                                variant: 'info',
                                duration: 3000,
                            });
                        }
                    }
                } catch {
                    // Ignore progress load errors
                }

                initCompleteRef.current = true;
            } catch (err) {
                if (cancelled) return;
                setError(err instanceof Error ? err.message : 'Failed to load online manga');
            }

            if (!cancelled) {
                setLoading(false);
            }
        };

        if (mode === 'local') {
            initLocal();
        } else {
            initOnline();
        }

        return () => {
            cancelled = true;
            initCompleteRef.current = false;

            // Cleanup based on mode
            if (mode === 'local' && localBookId !== null) {
                // Release the backend ZIP archive to free ~200MB/book
                api.closeManga(localBookId).catch(err =>
                    logger.warn('[MangaReader] Failed to close manga backend:', err)
                );
                imageCache.clear();
            } else {
                // Clear online image cache
                clearOnlineImageCache();
            }

            // Cleanup frontend state
            closeManga();
        };
    }, [mode, localBookId, localBookPath, localTitle, localTotalPages, onlineConfig,
        onlineOnChapterChange, openManga, openOnlineManga, closeManga, setLoading, setError, setCurrentPage, setOnlineChapter]);

    // Apply theme on mount
    useEffect(() => {
        document.documentElement.setAttribute('data-manga-theme', theme);
    }, [theme]);

    // Keep onNextChapter updated in the UI store
    useEffect(() => {
        useMangaUIStore.getState().setOnNextChapter(props.onNextChapter);
        return () => {
            useMangaUIStore.getState().setOnNextChapter(undefined);
        };
    }, [props.onNextChapter]);

    // Progressively fetch real page dimensions (local only)
    const fetchedDimsRef = useRef(new Set<number>());

    useEffect(() => {
        if (sourceType !== 'local' || !bookId || mangaTotalPages === 0 || !initCompleteRef.current) return;

        const start = Math.max(0, currentPage - 10);
        const end = Math.min(mangaTotalPages, currentPage + 20);
        const needed: number[] = [];

        for (let i = start; i < end; i++) {
            if (!fetchedDimsRef.current.has(i)) {
                // Check if still placeholder
                const dim = pageDimensions[i];
                if (!dim || (dim[0] === PLACEHOLDER[0] && dim[1] === PLACEHOLDER[1])) {
                    needed.push(i);
                } else {
                    // Already real, mark as fetched
                    fetchedDimsRef.current.add(i);
                }
            }
        }

        if (needed.length === 0) return;

        let cancelled = false;
        api.getMangaPageDimensions(bookId, needed).then(dims => {
            if (cancelled) return;
            for (const idx of needed) fetchedDimsRef.current.add(idx);
            mergePageDimensions(needed, dims);
        }).catch(err => {
            logger.warn('[MangaReader] Failed to fetch page dimensions:', err);
        });

        return () => { cancelled = true; };
    }, [sourceType, bookId, currentPage, mangaTotalPages, pageDimensions, mergePageDimensions]);

    // Save reading progress when page changes
    useEffect(() => {
        // Skip saving until initialization + resume is complete
        if (!initCompleteRef.current) return;

        if (currentPage === 0 && mangaTotalPages === 0) {
            return;
        }

        const saveProgress = async () => {
            try {
                const progressPercent = mangaTotalPages > 0 
                    ? ((currentPage + 1) / mangaTotalPages) * 100 
                    : 0;

                if (sourceType === 'local' && bookId) {
                    await api.saveReadingProgress(
                        bookId,
                        `page_${currentPage}`,
                        progressPercent,
                        currentPage,
                        mangaTotalPages
                    );
                    logger.debug('[MangaReader] Saved local progress:', { currentPage, total: mangaTotalPages, percent: progressPercent });
                } else if (sourceType === 'online' && onlineSource) {
                    // Save online progress to localStorage
                    const progressKey = `online:${onlineSource.sourceId}:${onlineSource.contentId}`;
                    localStorage.setItem(`shiori-manga-progress:${progressKey}`, JSON.stringify({
                        chapterId: onlineSource.chapterId,
                        page: currentPage,
                        timestamp: Date.now(),
                    }));

                    // Also save to library database if the user added it
                    const expectedPath = `online-manga://${onlineSource.sourceId}/${onlineSource.contentId}`;
                    const libBook = useLibraryStore.getState().books.find(b => b.file_path === expectedPath);
                    if (libBook) {
                        await api.saveReadingProgress(
                            libBook.id!,
                            `${onlineSource.chapterId}|${onlineSource.chapterTitle}|${currentPage}`,
                            progressPercent,
                            currentPage,
                            mangaTotalPages
                        );
                    }

                    logger.debug('[MangaReader] Saved online progress:', { 
                        sourceId: onlineSource.sourceId,
                        contentId: onlineSource.contentId,
                        chapterId: onlineSource.chapterId,
                        currentPage, 
                        total: mangaTotalPages,
                        inLibrary: !!libBook
                    });
                }
            } catch (err) {
                logger.warn('[MangaReader] Failed to save reading progress:', err);
            }
        };

        // Debounce saves to avoid excessive calls
        const timeoutId = setTimeout(saveProgress, 1000);
        return () => clearTimeout(timeoutId);
    }, [sourceType, bookId, onlineSource, currentPage, mangaTotalPages]);

    // Close handler
    const handleClose = useCallback(() => {
        if (sourceType === 'local' && bookId) {
            // Release the backend ZIP archive to free memory
            api.closeManga(bookId).catch(err =>
                logger.warn('[MangaReader] Failed to close manga backend:', err)
            );
            imageCache.clear();
        } else {
            clearOnlineImageCache();
        }
        closeManga();
        onClose();
    }, [sourceType, bookId, closeManga, onClose]);

    const handleDoubleClick = useCallback((e: React.MouseEvent) => {
        const uiStore = useMangaUIStore.getState();
        uiStore.setTopBarVisible(true);
        // Only toggle sidebar if they are actively trying to show UI, or just toggle both
        uiStore.toggleSidebar();
    }, []);

    // Register keyboard shortcuts
    useMangaKeyboard(handleClose);

    if (isLoading) {
        return (
            <div className="manga-reader" data-manga-theme={theme}>
                <div className="manga-loading-screen">
                    <div className="manga-loading-spinner" />
                    <span className="manga-loading-text">Loading manga…</span>
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="manga-reader" data-manga-theme={theme}>
                <div className="manga-loading-screen">
                    <span className="manga-loading-text" style={{ color: 'var(--manga-accent)' }}>
                        Error: {error}
                    </span>
                    <button type="button" className="manga-btn-done" onClick={handleClose}>
                        Close
                    </button>
                </div>
            </div>
        );
    }

    // Get onChapterChange from props if online mode
    const onChapterChange = props.mode === 'online' ? props.onChapterChange : undefined;

    return (
        <div 
            className="manga-reader" 
            data-manga-theme={theme}
            tabIndex={-1}
            onDoubleClick={handleDoubleClick}
        >
            <MangaReaderHeader 
                onClose={handleClose} 
                onChapterChange={onChapterChange}
            />
            <MangaCanvas />
            <NavigationOverlay onNextChapter={onNextChapter} />
            <MangaSidebar />
            <AdvancedSettingsPanel />
            <MangaProgressBar />
        </div>
    );
}

import { useEffect, useRef } from 'react';
import { useFullscreen } from '@/hooks/useFullscreen';
import {
    useMangaContentStore,
    useMangaUIStore,
    useMangaSettingsStore
} from '@/store/mangaReaderStore';
import { X, Settings, ChevronLeft, ChevronRight, Maximize, Minimize, Library, CheckCircle2, List } from 'lucide-react';
import React from 'react';
import { useOnlineMangaReaderStore } from '@/store/onlineMangaReaderStore';
import { useLibraryStore } from '@/store/libraryStore';
import { isAndroid } from '@/lib/tauri';
const TOPBAR_AUTO_HIDE_MS = 3000;

export function MangaReaderHeader({ 
    onClose, 
    onChapterChange 
}: { 
    onClose: () => void;
    onChapterChange?: (chapterId: string) => Promise<{ pageUrls: string[]; chapterTitle: string }>;
}) {
    const title = useMangaContentStore(s => s.title);
    const currentPage = useMangaContentStore(s => s.currentPage);
    const totalPages = useMangaContentStore(s => s.totalPages);
    const sourceType = useMangaContentStore(s => s.sourceType);
    const onlineSource = useMangaContentStore(s => s.onlineSource);
    const setOnlineChapter = useMangaContentStore(s => s.setOnlineChapter);
    const setLoading = useMangaContentStore(s => s.setLoading);
    const setError = useMangaContentStore(s => s.setError);

    const isTopBarVisible = useMangaUIStore(s => s.isTopBarVisible);
    const setTopBarVisible = useMangaUIStore(s => s.setTopBarVisible);
    const lastScrollActivityAt = useMangaUIStore(s => s.lastScrollActivityAt);
    const toggleSidebar = useMangaUIStore(s => s.toggleSidebar);
    const isSidebarOpen = useMangaUIStore(s => s.isSidebarOpen);
    const isSettingsOpen = useMangaUIStore(s => s.isSettingsOpen);

    const stickyHeader = useMangaSettingsStore(s => s.stickyHeader);
    const readingMode = useMangaSettingsStore(s => s.readingMode);
    const isScrollMode = readingMode === 'strip' || readingMode === 'webtoon' || readingMode === 'manhwa';

    const onlineSourceId = useOnlineMangaReaderStore(s => s.sourceId);
    const onlineContentId = useOnlineMangaReaderStore(s => s.contentId);
    const addToLibrary = useOnlineMangaReaderStore(s => s.addToLibrary);
    const libraryBooks = useLibraryStore(s => s.books);

    const isAlreadyInLibrary = React.useMemo(() => {
        if (sourceType !== 'online' || !onlineSourceId || !onlineContentId) return false;
        const expectedPath = `online-manga://${onlineSourceId}/${onlineContentId}`;
        return libraryBooks.some(b => b.file_path === expectedPath);
    }, [sourceType, onlineSourceId, onlineContentId, libraryBooks]);

    const localSource = useMangaContentStore(s => s.localSource);
    const currentLocalBook = React.useMemo(() => 
        localSource ? libraryBooks.find(b => b.id === localSource.bookId) : null
    , [localSource, libraryBooks]);

    const seriesBooks = React.useMemo(() => {
        if (!currentLocalBook?.series) return [];
        return libraryBooks
            .filter(b => b.series === currentLocalBook.series)
            .sort((a, b) => (a.series_index || 0) - (b.series_index || 0));
    }, [currentLocalBook, libraryBooks]);

    const currentLocalIndex = React.useMemo(() => 
        seriesBooks.findIndex(b => b.id === currentLocalBook?.id)
    , [seriesBooks, currentLocalBook]);

    const hasNextLocalVolume = currentLocalIndex !== -1 && currentLocalIndex < seriesBooks.length - 1;
    const hasPrevLocalVolume = currentLocalIndex > 0;

    const { isFullscreen, toggleFullscreen } = useFullscreen();
    const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Keep the top bar visible while sidebar/settings panels are open.
