import { useRef, useState, useCallback, useEffect, memo, type RefObject } from 'react';
import { ChevronLeft, ChevronRight, BookOpen } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { cn } from '@/lib/utils';

export interface CarouselItem {
  id: string;
  title: string;
  coverUrl?: string;
  subtitle?: string;
}

interface ContentCarouselProps {
  title: string;
  items: CarouselItem[];
  loading?: boolean;
  onItemClick?: (item: CarouselItem) => void;
  className?: string;
}

const CarouselCard = memo(function CarouselCard({
  item,
  onClick,
  scrollRoot,
}: {
  item: CarouselItem;
  onClick?: (item: CarouselItem) => void;
  scrollRoot: RefObject<HTMLElement | null>;
}) {
  const [visible, setVisible] = useState(false);
  const cardRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    const el = cardRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { root: scrollRoot.current, rootMargin: '100px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [scrollRoot.current]);

  return (
    <button
      ref={cardRef}
      type="button"
      onClick={() => onClick?.(item)}
      className="flex-shrink-0 w-[140px] text-left group/item focus:outline-none focus-visible:ring-2 focus-visible:ring-primary rounded-lg"
    >
      {/* Cover image */}
      <div className="relative aspect-[2/3] rounded-lg overflow-hidden bg-muted border border-border group-hover/item:border-primary/50 transition-colors">
        {!visible && <div className="absolute inset-0 shimmer" />}
        {visible && item.coverUrl ? (
          <img
            src={item.coverUrl}
            alt={item.title}
            className="w-full h-full object-cover transition-transform duration-300 group-hover/item:scale-105"
            loading="lazy"
          />
        ) : visible && !item.coverUrl ? (
          <div className="w-full h-full flex items-center justify-center">
            <BookOpen className="w-8 h-8 text-muted-foreground opacity-50" />
          </div>
        ) : null}
        {/* Hover overlay */}
        <div className="absolute inset-0 bg-black/0 group-hover/item:bg-black/20 transition-colors" />
      </div>

      {/* Title */}
      <div className="mt-2 space-y-0.5">
        <h3 className="text-sm font-medium line-clamp-2 text-foreground group-hover/item:text-primary transition-colors">
          {item.title}
        </h3>
        {item.subtitle && (
          <p className="text-xs text-muted-foreground line-clamp-1">{item.subtitle}</p>
        )}
      </div>
    </button>
  );
});

export function ContentCarousel({
  title,
  items,
  loading = false,
  onItemClick,
  className,
}: ContentCarouselProps) {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(true);

  const updateScrollButtons = useCallback(() => {
    const container = scrollContainerRef.current;
    if (!container) return;

    const { scrollLeft, scrollWidth, clientWidth } = container;
    setCanScrollLeft(scrollLeft > 0);
    setCanScrollRight(scrollLeft + clientWidth < scrollWidth - 10);
  }, []);

  const scroll = useCallback((direction: 'left' | 'right') => {
    const container = scrollContainerRef.current;
    if (!container) return;

    const scrollAmount = container.clientWidth * 0.8;
    const newScrollLeft = direction === 'left'
      ? container.scrollLeft - scrollAmount
      : container.scrollLeft + scrollAmount;

    container.scrollTo({
      left: newScrollLeft,
      behavior: 'smooth',
    });

    // Update buttons after animation
    setTimeout(updateScrollButtons, 350);
  }, [updateScrollButtons]);

  const handleScroll = useCallback(() => {
    updateScrollButtons();
  }, [updateScrollButtons]);

  // Loading skeleton
  if (loading) {
    return (
      <div className={cn('space-y-3', className)}>
        <div className="flex items-center justify-between px-1">
          <h2 className="text-lg font-semibold text-foreground">{title}</h2>
        </div>
        <div className="flex gap-3 overflow-hidden">
          {['a', 'b', 'c', 'd', 'e', 'f'].map((key) => (
            <div key={`skeleton-${title}-${key}`} className="flex-shrink-0 w-[140px]">
              <Skeleton className="w-full aspect-[2/3] rounded-lg" />
              <Skeleton className="h-4 w-3/4 mt-2" />
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (items.length === 0) {
    return null;
  }

  return (
    <div className={cn('space-y-3', className)}>
      {/* Header with title and navigation */}
      <div className="flex items-center justify-between px-1">
        <h2 className="text-lg font-semibold text-foreground">{title}</h2>
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="sm"
            className="h-8 w-8 p-0"
            onClick={() => scroll('left')}
            disabled={!canScrollLeft}
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="h-8 w-8 p-0"
            onClick={() => scroll('right')}
            disabled={!canScrollRight}
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
        </div>
      </div>

      {/* Scrollable content */}
      <div className="relative group">
        <div
          ref={scrollContainerRef}
          onScroll={handleScroll}
          className="flex gap-3 overflow-x-auto scrollbar-hide pb-2 scroll-smooth"
          style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
          {items.map((item) => (
            <CarouselCard
              key={item.id}
              item={item}
              onClick={onItemClick}
              scrollRoot={scrollContainerRef}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

import * as Dialog from '@radix-ui/react-dialog';
import { Button } from '@/components/ui/button';
import { GutendexBook } from '@/online-books/gutenberg/types';
import { Download, BookOpen, Loader2, X } from 'lucide-react';
import { useState } from 'react';
import { downloadAndImportGutenberg } from '@/online-books/gutenberg/importer';
import { useToast } from '@/store/toastStore';
import { useBookOpen } from '@/hooks/useBookOpen';
import { downloadGutenbergEpub } from '@/online-books/gutenberg/downloads';

interface Props {
  book: GutendexBook | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function GutenbergBookDetails({ book, open, onOpenChange }: Props) {
  const [isDownloading, setIsDownloading] = useState(false);
  const [isReading, setIsReading] = useState(false);
  const { success: showSuccessToast, error: showErrorToast } = useToast();
  const { handleOpenBook } = useBookOpen();

  if (!book) return null;

  const epubFormatUrl = book.formats['application/epub+zip'];
  const hasEpub = !!epubFormatUrl;

  const handleDownload = async () => {
    if (!epubFormatUrl) return;
    setIsDownloading(true);
    try {
      const result = await downloadAndImportGutenberg(epubFormatUrl, book.title);
      if (result.success.length > 0 || result.duplicates.length > 0) {
        showSuccessToast('Added to Library', `${book.title} was added to your library.`);
        onOpenChange(false);
      } else if (result.failed.length > 0) {
        showErrorToast('Import Failed', result.failed[0][1] || 'Unknown error occurred.');
      }
    } catch (err) {
      showErrorToast('Download Failed', err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleReadNow = async () => {
    if (!epubFormatUrl) return;
    setIsReading(true);
    try {
      // 1. Download and import directly
      const result = await downloadAndImportGutenberg(epubFormatUrl, book.title);
      const path = result.success[0] || result.duplicates[0];

      if (!path) {
        throw new Error(result.failed[0]?.[1] || "Failed to download book.");
      }

      // 2. Fetch books to find the newly imported book's ID by its path
      const { api } = await import('@/lib/tauri');
      // We assume the newly imported book is among the most recently added (top 100)
      const recentBooks = await api.getBooks(100, 0);

      // If it was a duplicate, the 'path' is the new temp path which isn't in the DB.
      // So we fallback to matching the title.
      const foundBook = recentBooks.find(b => 
        b.file_path === path || 
        (b.title && book.title && b.title.toLowerCase().trim() === book.title.toLowerCase().trim())
      );

      if (!foundBook?.id) {
        throw new Error(`Could not find imported book ID to open reader. (Path: ${path})`);
      }

      // 3. Open it via Reader integration
      await handleOpenBook(foundBook.id);
      onOpenChange(false);
    } catch (err) {
      showErrorToast('Failed to Open Reader', err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setIsReading(false);
    }
  };

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-background/80 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content aria-describedby={undefined} className="dialog-content fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-card/40 backdrop-blur-2xl border border-border/50 rounded-[2rem] shadow-2xl w-[600px] max-h-[90vh] flex flex-col z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 duration-500 overflow-hidden">

          <div className="flex-none bg-transparent backdrop-blur-xl border-b border-border/50 px-8 py-6 z-10 flex flex-col justify-between relative">
            <Dialog.Title className="text-2xl font-black tracking-tight text-foreground pr-8">
              {book.title}
            </Dialog.Title>
            <Dialog.Description className="text-muted-foreground mt-1">
              {book.authors.map(a => a.name).join(', ') || 'Unknown Author'}
            </Dialog.Description>
            <Dialog.Close asChild>
              <button className="absolute right-6 top-6 p-2.5 bg-card/40 hover:bg-card/80 border border-border/50 rounded-2xl transition-all duration-300 text-muted-foreground hover:text-foreground" title="Close">
                <X className="w-5 h-5" />
              </button>
            </Dialog.Close>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
            {book.subjects.length > 0 && (
              <div>
                <h3 className="font-semibold text-sm text-foreground tracking-tight mb-3">Subjects</h3>
                <div className="flex flex-wrap gap-2">
                  {book.subjects.map(subject => (
                    <span key={subject} className="px-3 py-1.5 rounded-xl bg-primary/10 text-primary border border-primary/20 text-xs font-medium">
                      {subject}
                    </span>
                  ))}
                </div>
              </div>
            )}

            <div>
              <h3 className="font-semibold text-sm text-foreground tracking-tight mb-3">Languages</h3>
              <div className="flex gap-2">
                {book.languages.map(lang => (
                  <span key={lang} className="uppercase text-xs font-bold tracking-wider px-2.5 py-1.5 rounded-lg bg-muted text-muted-foreground">
                    {lang}
                  </span>
                ))}
              </div>
            </div>

            {!hasEpub && (
              <div className="p-4 rounded-2xl bg-destructive/10 border border-destructive/20 text-destructive text-sm font-medium flex items-center gap-3">
                <div className="p-2 bg-destructive/20 rounded-xl">
                  <X className="w-4 h-4" />
                </div>
                This book is not available in EPUB format and cannot be read directly in the app.
              </div>
            )}
          </div>

          <div className="flex-none p-6 border-t border-border/50 bg-muted/30 flex justify-end gap-3 backdrop-blur-md">
            <Dialog.Close asChild>
              <Button variant="outline" className="rounded-2xl px-6">
                Close
              </Button>
            </Dialog.Close>
            {hasEpub && (
              <>
                <Button 
                  variant="default" 
                  onClick={handleDownload}
                  disabled={isDownloading || isReading}
                  className="gap-2 rounded-2xl shadow-primary/20 shadow-lg hover:shadow-primary/30 transition-all"
                >
                  {isDownloading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                  Add to Library
                </Button>
              </>
            )}
          </div>

        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

import * as Dialog from '@radix-ui/react-dialog';
import { Button } from '@/components/ui/button';
import { SearchResult } from '@/lib/pluginSources';
import { Download, BookOpen, Loader2, X, AlertTriangle } from 'lucide-react';
import { useState, useEffect } from 'react';
import { downloadAndImportLibgen } from '@/online-books/libgen/importer';
import { useToast } from '@/store/toastStore';
import { useBookOpen } from '@/hooks/useBookOpen';
import { pluginApi } from '@/lib/pluginSources';
import { logger } from '@/lib/logger';
import { api } from '@/lib/tauri';
import { fetchCoverForBook } from '@/online-books/openlibrary/api';

interface Props {
  book: SearchResult | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function LibgenBookDetails({ book, open, onOpenChange }: Props) {
  const [isDownloading, setIsDownloading] = useState(false);
  const [isReading, setIsReading] = useState(false);
  const [coverUrl, setCoverUrl] = useState<string | null>(null);
  const { success: showSuccessToast, error: showErrorToast } = useToast();
  const { handleOpenBook } = useBookOpen();

  useEffect(() => {
    if (!book || !open) return;

    // Reset cover
    setCoverUrl(null);
    let active = true;
    let objectUrl: string | null = null;

    const fetchCover = async () => {
      try {
        const pages = await pluginApi.getPages('libgen', book.id);
        const coverPage = pages.find(p => p.url.startsWith('cover|'));
        if (coverPage && active) {
          const rawUrl = coverPage.url.replace(/^cover\|/, '');
          if (rawUrl.includes('libgen')) {
            try {
              const arr = await api.proxyMangaImage('libgen', rawUrl);
              if (!active) return;
              if (arr.length < 100) throw new Error('Invalid or empty cover image');
              const u8arr = new Uint8Array(arr as unknown as Iterable<number>);
              const blob = new Blob([u8arr], { type: 'image/jpeg' });
              objectUrl = URL.createObjectURL(blob);
              setCoverUrl(objectUrl);
            } catch (err) {
              logger.error('Failed to proxy LibGen cover:', err);
              if (!active) return;
              const extra = (book.extra || {}) as Record<string, string>;
              const fallbackUrl = await fetchCoverForBook(book.title, extra.author);
              if (active && fallbackUrl) {
                setCoverUrl(fallbackUrl);
              } else if (active) {
                setCoverUrl(null);
              }
            }
          } else {
            setCoverUrl(rawUrl);
          }
        }
      } catch (err) {
        logger.error('Failed to load cover from LibGen detail page:', err);
      }
    };

    void fetchCover();

    return () => {
      active = false;
      if (objectUrl) {
        URL.revokeObjectURL(objectUrl);
      }
    };
  }, [book?.id, open]);

  if (!book) return null;

  const extra = (book.extra || {}) as Record<string, string>;
  const author = extra.author || 'Unknown Author';
  const publisher = extra.publisher;
  const year = extra.year;
  const language = extra.language;
  const format = extra.format || 'EPUB';
  const fileSize = extra.file_size;

  const resolveEpubUrl = async (): Promise<string | null> => {
    try {
      // 1. Fetch pages (which are download links) from libgen backend
      const pages = await pluginApi.getPages('libgen', book.id);

      // 2. Find first direct download link containing get.php
      const directPage = pages.find(p => p.url.startsWith('direct|'));
      if (directPage) {
        // Strip direct| prefix
        return directPage.url.replace(/^direct\|/, '');
      }

      return null;
    } catch (err) {
      logger.error('Failed to resolve LibGen download link:', err);
      return null;
    }
  };

  const handleDownload = async () => {
    setIsDownloading(true);
    try {
      const epubUrl = await resolveEpubUrl();
      if (!epubUrl) {
        throw new Error('No direct download links found for this book on LibGen.');
      }

      const result = await downloadAndImportLibgen(
        epubUrl, 
        book.title, 
        book.extra ? Object.keys(book.extra).filter(k => k.startsWith('mirror_')).map(k => book.extra![k] as string) : [],
        format.toLowerCase()
      );
      if (result.success.length > 0 || result.duplicates.length > 0) {
        showSuccessToast('Added to Library', `${book.title} was added to your library.`);
        onOpenChange(false);
      } else if (result.failed.length > 0) {
        showErrorToast('Import Failed', result.failed[0][1] || 'Unknown error occurred.');
      }
    } catch (err) {
      showErrorToast('Download Failed', err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleReadNow = async () => {
    setIsReading(true);
    try {
      const epubUrl = await resolveEpubUrl();
      if (!epubUrl) {
        throw new Error('No direct download links found for this book on LibGen.');
      }

      // 1. Download and import directly
      const result = await downloadAndImportLibgen(
        epubUrl, 
        book.title, 
        book.extra ? Object.keys(book.extra).filter(k => k.startsWith('mirror_')).map(k => book.extra![k] as string) : [],
        format.toLowerCase()
      );
      const path = result.success[0] || result.duplicates[0];

      if (!path) {
        throw new Error(result.failed[0]?.[1] || "Failed to download book.");
      }

      // 2. Fetch books to find the newly imported book's ID by its path
      const { api } = await import('@/lib/tauri');
      const recentBooks = await api.getBooks(100, 0);

      const foundBook = recentBooks.find(b => 
        b.file_path === path || 
        (b.title && book.title && b.title.toLowerCase().trim() === book.title.toLowerCase().trim())
      );

      if (!foundBook?.id) {
        throw new Error(`Could not find imported book ID to open reader.`);
      }

      // 3. Open it via Reader integration
      await handleOpenBook(foundBook.id);
      onOpenChange(false);
    } catch (err) {
      showErrorToast('Failed to Open Reader', err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setIsReading(false);
    }
  };

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="dialog-overlay fixed inset-0 bg-background/80 backdrop-blur-sm z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content aria-describedby={undefined} className="dialog-content fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-card/40 backdrop-blur-2xl border border-border/50 rounded-[2rem] shadow-2xl w-[600px] max-h-[90vh] flex flex-col z-50 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 duration-500 overflow-hidden">

          <div className="flex-none bg-transparent backdrop-blur-xl border-b border-border/50 px-8 py-6 z-10 flex flex-col justify-between relative">
            <Dialog.Title className="text-2xl font-black tracking-tight text-foreground pr-8">
              {book.title}
            </Dialog.Title>
            <Dialog.Description className="text-muted-foreground mt-1 font-medium">
              {author}
            </Dialog.Description>
            <Dialog.Close asChild>
              <button className="absolute right-6 top-6 p-2.5 bg-card/40 hover:bg-card/80 border border-border/50 rounded-2xl transition-all duration-300 text-muted-foreground hover:text-foreground" title="Close">
