export function OnlineBooksDashboard() {
  const [trending, setTrending] = useState<OpenLibraryWork[]>([]);
  const [scifi, setScifi] = useState<any[]>([]);
  const [classics, setClassics] = useState<any[]>([]);
  const [fantasy, setFantasy] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const setQuery = useOnlineSearchStore(state => state.setQuery);

  useEffect(() => {
    let active = true;

    Promise.allSettled([
      fetchTrendingBooks(),
      fetchSubjectBooks('science_fiction'),
      fetchSubjectBooks('classic_literature'),
      fetchSubjectBooks('fantasy')
    ]).then(([trendRes, scifiRes, classicRes, fantasyRes]) => {
      if (!active) return;

      if (trendRes.status === 'fulfilled') setTrending(trendRes.value.slice(0, 15));
      if (scifiRes.status === 'fulfilled') setScifi(scifiRes.value);
      if (classicRes.status === 'fulfilled') setClassics(classicRes.value);
      if (fantasyRes.status === 'fulfilled') setFantasy(fantasyRes.value);

      setLoading(false);
    });

    return () => { active = false; };
  }, []);

  const handleBookClick = (title: string, author?: string) => {
    // When a user clicks a book from the dashboard, we trigger a global search for it
    // because OpenLibrary doesn't provide direct EPUB downloads, we use Libgen/Gutenberg for that!
    setQuery('online-books', title);
  };

  return (
    <div className="flex-1 overflow-y-auto pt-12 md:pt-16">
      <div className="pb-32 max-w-[1440px] mx-auto mt-6 flex flex-col gap-8 md:gap-16">
        <BookGrid subtitle="01 — Gallery" title="Featured Books" books={trending.slice(0, 4)} isLoading={loading} onBookClick={handleBookClick} />
        <BookRow subtitle="02 — Global" title="Trending Now" books={scifi} isLoading={loading} onBookClick={handleBookClick} />
        <BookRow subtitle="03 — For You" title="Recommended" books={classics} isLoading={loading} onBookClick={handleBookClick} />
        <BookRow subtitle="04 — Explore" title="Epic Fantasy" books={fantasy} isLoading={loading} onBookClick={handleBookClick} />
      </div>
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { useIsMobile } from '@/hooks/useIsMobile';
import { cn } from '@/lib/utils';
import { useOnlineSearchStore } from '@/store/onlineSearchStore';
import { useGlobalSearch } from '@/hooks/useGlobalSearch';
import { OnlineSearchHeader } from './OnlineSearchHeader';
import { Compass } from 'lucide-react';
import { OnlineBooksDashboard } from './OnlineBooksDashboard';
import { ModernBookCard } from './ModernBookCard';
import { SkeletonGrid } from './SkeletonLoaders';
import { OnlineBookSidePanel, type PreviewBook } from './OnlineBookSidePanel';
import { useInView } from 'react-intersection-observer';
import { downloadAndImportGutenberg } from '@/online-books/gutenberg/importer';
import { downloadAndImportLibgen } from '@/online-books/libgen/importer';
import { useLibraryStore } from '@/store/libraryStore';
import { useToast } from '@/store/toastStore';
import { useBookOpen } from '@/hooks/useBookOpen';
import { invoke } from '@tauri-apps/api/core';
import { api } from '@/lib/tauri';

let searchTimeout: number | undefined;

export function OnlineBooksView() {
  const isMobile = useIsMobile();
  const searchQuery = useOnlineSearchStore((state) => state.queries['online-books']);
  const filters = useOnlineSearchStore((state) => state.filters['online-books']);
  const { results, search, loading, error, hasMore } = useGlobalSearch();

  const [page, setPage] = useState(1);
  const [hasSearched, setHasSearched] = useState(false);
  const [previewBook, setPreviewBook] = useState<PreviewBook | null>(null);

  const { success: showSuccessToast, error: showErrorToast } = useToast();
  const { handleOpenBook } = useBookOpen();

  const { ref: loadMoreRef, inView } = useInView({
    threshold: 0.1,
    rootMargin: '400px',
  });

  const doSearch = useCallback((p: number = 1) => {
    if (!searchQuery && Object.keys(filters).length === 0) {
      return;
    }

    setHasSearched(true);
    setPage(p);
    search(searchQuery, p, filters);
  }, [searchQuery, filters, search]);

  useEffect(() => {
    setHasSearched(false);
    setPage(1);

    if (searchTimeout) window.clearTimeout(searchTimeout);

    if (searchQuery || Object.keys(filters).length > 0) {
      searchTimeout = window.setTimeout(() => {
        if (!loading) {
          search(searchQuery, 1, filters);
          setHasSearched(true);
        }
      }, 500);
    }

    return () => {
      if (searchTimeout) window.clearTimeout(searchTimeout);
    };
  }, [searchQuery, filters]);

  // Infinite scroll
  useEffect(() => {
    if (inView && !loading && hasSearched && hasMore) {
      setPage((p) => {
        search(searchQuery, p + 1, filters);
        return p + 1;
      });
    }
  }, [inView, loading, hasSearched, hasMore, search, searchQuery, filters]);

  const handleBookClick = (book: any) => {
    // Determine the source and format
    setPreviewBook({
      title: book.title,
      author: book.author,
      coverUrl: book.coverUrl,
      source: book.source,
      downloadUrl: book.id,
      format: book.format || 'epub',
      language: book.language,
      size: book.size,
      mirrors: book.mirrors,
    });
  };

  const handleDownload = async (book: PreviewBook) => {
    try {
      showSuccessToast('Download Started', `Downloading ${book.title}`);
      let result;
      if (book.source === 'gutenberg') {
        result = await downloadAndImportGutenberg(book.downloadUrl, book.title);
      } else {
        result = await downloadAndImportLibgen(book.downloadUrl, book.title, book.mirrors);
      }
      if (result.success.length > 0) {
        await useLibraryStore.getState().loadInitialBooks();
        showSuccessToast('Download Complete', `${book.title} added to your library`);
      }
      if (result.failed && result.failed.length > 0) {
        showErrorToast('Import Failed', result.failed[0][1] || 'Unknown error occurred during import.');
      }
    } catch (err: any) {
      showErrorToast('Download Failed', err.message);
    }
  };

  // Smart Streaming / Read Now
  const handleReadNow = async (book: PreviewBook) => {
    try {
      showSuccessToast('Buffering...', `Preparing ${book.title} for reading`);
      let bookId: number;
      if (book.source === 'gutenberg') {
        const result = await downloadAndImportGutenberg(book.downloadUrl, book.title);
        if (result.success.length === 0) {
          const errMsg = result.failed && result.failed.length > 0 ? result.failed[0][1] : 'Failed to import book';
          throw new Error(errMsg);
        }
      } else {
        const result = await downloadAndImportLibgen(book.downloadUrl, book.title, book.mirrors);
        if (result.success.length === 0) {
          const errMsg = result.failed && result.failed.length > 0 ? result.failed[0][1] : 'Failed to import book';
          throw new Error(errMsg);
        }
      }

      const searchRes = await api.searchBooks({ query: book.title });
      if (searchRes.books.length > 0) {
        await useLibraryStore.getState().loadInitialBooks();
        handleOpenBook(searchRes.books[0].id!);
      } else {
        throw new Error('Could not find the imported book in library.');
      }
    } catch (err: any) {
      showErrorToast('Read Now Failed', err.message);
    }
  };

  const handleAddToWishlist = async (book: PreviewBook) => {
    try {
      showSuccessToast('Adding...', `Adding ${book.title} to wishlist`);

      const newBook = {
        uuid: crypto.randomUUID(),
        title: book.title,
        authors: book.author ? [{ name: book.author }] : [],
        file_path: `shiori-wishlist://${book.downloadUrl}`,
        file_format: book.format || 'epub',
        is_wishlist: true,
        cover_path: book.coverUrl,
        reading_status: 'planning',
        added_date: new Date().toISOString(),
        modified_date: new Date().toISOString(),
        language: book.language || 'en',
        domain: book.source,
      };

      const result = await invoke('add_book', { book: newBook });
      showSuccessToast('Added to Wishlist', `${book.title} has been added to your reading plan.`);
    } catch (err: any) {
      showErrorToast('Failed to Add', err.message || 'Could not add to wishlist.');
    }
  };

  return (
    <div className="flex flex-col h-full bg-background relative z-10">
      <OnlineSearchHeader 
        kind="books"
        title="Online Library"
        subtitle="Search Libgen & Gutenberg"
        searchValue={searchQuery}
        loading={loading}
        disabled={false}
        onSearchValueChange={(val) => useOnlineSearchStore.getState().setQuery('online-books', val)}
        onSubmit={() => doSearch(1)}
      />

      {!hasSearched ? (
        <OnlineBooksDashboard />
      ) : (
        <div className={cn("flex-1 overflow-y-auto scroll-smooth", isMobile ? "pb-24 p-6" : "p-6")}>
          <div className="max-w-[1600px] mx-auto">
            {error && (
              <div className="bg-red-500/10 text-red-500 p-4 rounded-lg mb-6 border border-red-500/20">
                {error}
              </div>
            )}

            {results.length > 0 ? (
              <div className="grid grid-cols-[repeat(auto-fill,minmax(115px,1fr))] sm:grid-cols-[repeat(auto-fill,minmax(160px,1fr))] md:grid-cols-[repeat(auto-fill,minmax(180px,1fr))] gap-3 md:gap-6">
                {results.map((book) => (
                  <ModernBookCard
                    key={`${book.source}-${book.id}`}
                    id={book.id}
                    title={book.title}
                    author={book.author}
                    coverUrl={book.coverUrl}
                    format={book.format}
                    year={book.year}
                    onClick={() => handleBookClick(book)}
                  />
                ))}
              </div>
            ) : !loading && hasSearched && !error ? (
              <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
                <Compass className="w-12 h-12 mb-4 opacity-20" />
                <p className="text-lg">No books found for this search.</p>
                <p className="text-sm opacity-70">Try using different keywords or removing filters.</p>
              </div>
            ) : null}

            {loading && (
              <div className="mt-8">
                <SkeletonGrid count={12} />
              </div>
            )}

            <div ref={loadMoreRef} className="h-20 w-full" />
          </div>
        </div>
      )}

      {previewBook && (
        <OnlineBookSidePanel
          book={previewBook}
          onClose={() => setPreviewBook(null)}
          onDownload={() => {
            handleDownload(previewBook);
            setPreviewBook(null);
          }}
        />
      )}
    </div>
  );
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Play, Bookmark, BookmarkCheck, ArrowLeft, Search, Star, Info, FileText, Globe, Download } from 'lucide-react';
import DOMPurify from 'dompurify';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useVirtualizer } from '@tanstack/react-virtual';
import { fetchWithRetry } from '@/lib/utils';
import { MangaDownloadDialog } from './MangaDownloadDialog';

export interface UnifiedChapter {
  id: string;
  volume: string;
  chapter: string;
  title: string;
  scanlationGroup?: string;
  pages?: number;
  sourceType: 'mangadex' | 'plugin';
  originalChapter: any;
  date?: string; 
}

interface OnlineMangaDetailViewProps {
  title: string;
  coverUrl?: string;
  description?: string;
  author?: string;
  status?: string;
  year?: number | string;
  genres?: string[];
  rating?: string;

  chaptersLoading: boolean;
  chaptersError: string | null;
  unifiedChapters: UnifiedChapter[];
  sourceId?: string;
  contentId?: string;

  relatedManga?: any[];
  recommendedManga?: any[];

  onBack: () => void;
  onReadChapter: (chapter: UnifiedChapter) => void;
  onSaveToLibrary?: () => Promise<void>;
  isInLibrary?: boolean;
  lastReadChapterId?: string;

  onMangaClick?: (mangaId: string) => void;
  onDownloadChapters?: (chapters: UnifiedChapter[]) => void;
}

export function OnlineMangaDetailView({
  title,
  coverUrl,
  description,
  author,
  status,
  year,
  genres,
  rating,
  chaptersLoading,
  chaptersError,
  unifiedChapters,
  sourceId,
  contentId,
  relatedManga,
  recommendedManga,
  onBack,
  onReadChapter,
  onSaveToLibrary,
  isInLibrary,
  lastReadChapterId,
  onMangaClick,
  onDownloadChapters,
}: OnlineMangaDetailViewProps) {
  const parentRef = useRef<HTMLDivElement>(null);

  const [resumeChapterId, setResumeChapterId] = useState<string | null>(null);

  useEffect(() => {
    if (sourceId && contentId) {
      const progressKey = `online:${sourceId}:${contentId}`;
      const savedProgressStr = localStorage.getItem(`shiori-manga-progress:${progressKey}`);
      if (savedProgressStr) {
        try {
          const savedProgress = JSON.parse(savedProgressStr);
          if (savedProgress?.chapterId) {
            setResumeChapterId(savedProgress.chapterId);
          }
        } catch (e) {
          console.error('Failed to parse manga progress', e);
        }
      }
    }
  }, [sourceId, contentId]);

  const resumeChapter = useMemo(() => {
    if (!resumeChapterId) return null;
    return unifiedChapters.find(c => c.id === resumeChapterId) || null;
  }, [resumeChapterId, unifiedChapters]);

  const [expandedVolume, setExpandedVolume] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'CHAPTER' | 'VOLUME'>('CHAPTER');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortAscending, setSortAscending] = useState(false);
  const [isDescriptionExpanded, setIsDescriptionExpanded] = useState(false);
  const [anilistData, setAnilistData] = useState<any>(null);
  const [downloadDialogOpen, setDownloadDialogOpen] = useState(false);

  useEffect(() => {
    if (title) {
      const fetchAnilist = async () => {
        try {
          const query = `
            query ($search: String) {
              Media(search: $search, type: MANGA) {
                id
                title {
                  english
                  romaji
                  native
                }
                averageScore
                stats {
                  scoreDistribution {
                    score
                    amount
                  }
                }
                source
                format
              }
            }
          `;
          const res = await fetchWithRetry('https://graphql.anilist.co', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query, variables: { search: title } })
          });
          const data = await res.json();
          if (data.data?.Media) {
            const media = data.data.Media;
            const totalReviews = media.stats?.scoreDistribution?.reduce((acc: number, cur: any) => acc + cur.amount, 0) || 0;
            setAnilistData({ ...media, totalReviews });
          }
        } catch (e) {
          console.error("Anilist fetch error:", e);
        }
      };
      fetchAnilist();
    }
  }, [title]);

  const displayDescription = useMemo(() => {
    if (!description) return '';
    if (isDescriptionExpanded) return description;
    return description.length > 250 ? description.slice(0, 250) + '...' : description;
  }, [description, isDescriptionExpanded]);

  const filteredAndSortedChapters = useMemo(() => {
    let list = [...unifiedChapters];

    if (searchQuery.trim()) {
      const q = searchQuery.trim().toLowerCase();
      list = list.filter(
        (ch) =>
          ch.chapter.includes(q) ||
          ch.title.toLowerCase().includes(q) ||
          ch.volume.includes(q)
      );
    }

    list.sort((a, b) => {
      const aVol = a.volume === 'None' ? 0 : Number(a.volume) || 0;
      const bVol = b.volume === 'None' ? 0 : Number(b.volume) || 0;
      const aChap = Number(a.chapter) || 0;
      const bChap = Number(b.chapter) || 0;

      if (aVol !== bVol) {
        return sortAscending ? aVol - bVol : bVol - aVol;
      }
      return sortAscending ? aChap - bChap : bChap - aChap;
    });

    return list;
  }, [unifiedChapters, searchQuery, sortAscending]);

  const volumes = useMemo(() => {
    if (activeTab !== 'VOLUME') return [];
    const vols = new Set(filteredAndSortedChapters.map((c) => c.volume));
    return Array.from(vols);
  }, [filteredAndSortedChapters, activeTab]);

  const rowVirtualizer = useVirtualizer({
    count: filteredAndSortedChapters.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 57, 
    overscan: 5,
  });

  const ratingScore = anilistData?.averageScore ? (anilistData.averageScore / 10).toFixed(2) : rating ? rating : '?';
  const totalReviews = anilistData?.totalReviews ? anilistData.totalReviews.toLocaleString() : '0';
  const alternateTitles = anilistData?.title ? [anilistData.title.english, anilistData.title.romaji, anilistData.title.native].filter(Boolean).join('; ') : title;
  const formatText = anilistData?.format || 'Manga';

  return (
    <div className="flex flex-col h-full bg-background text-foreground overflow-y-auto overflow-x-hidden relative font-sans">
      {/* Background Gradient / Blur */}
      <div
        className="absolute top-0 left-0 right-0 h-[65vh] opacity-30 pointer-events-none transition-all duration-1000"
        style={{
          backgroundImage: `url(${coverUrl})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'blur(60px) saturate(2)',
          WebkitMaskImage: 'linear-gradient(to bottom, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)',
          maskImage: 'linear-gradient(to bottom, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)',
        }}
      />
      <div className="absolute top-0 left-0 right-0 h-[65vh] bg-gradient-to-b from-background/20 via-background/60 to-background pointer-events-none" />

      {/* Main Content Area */}
      <div className="relative z-10 p-6 md:p-10 max-w-[1400px] mx-auto w-full">
        {/* Back Button */}
        <button
          onClick={onBack}
          className="flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors mb-6 font-medium text-sm"
        >
          <ArrowLeft className="w-4 h-4" /> Back to browse
        </button>

        {/* Hero Section */}
        <div className="grid grid-cols-1 md:grid-cols-[260px_1fr] gap-10 mb-12">

          {/* Left Column (Cover) */}
          <div className="w-full shrink-0 flex flex-col items-center md:items-start relative z-20">
            <div className="w-[220px] md:w-full aspect-[2/3] rounded-xl overflow-hidden shadow-[0_20px_40px_-15px_rgba(0,0,0,0.5)] border border-white/10 bg-card/50 backdrop-blur-sm relative group">
            {coverUrl ? (
              <>
                <img src={coverUrl} alt={title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" loading="lazy" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
              </>
            ) : (
              <div className="w-full h-full flex items-center justify-center text-muted-foreground/80 font-medium">No Cover</div>
            )}
            </div>
          </div>

          {/* Right/Middle Column (Title, Description, Details) */}
          <div className="flex flex-col min-w-0 pt-2 md:pt-4 relative z-20">
            <div className="flex items-center gap-3 mb-3">
              <span className="px-3 py-1 bg-primary/10 text-primary border border-primary/20 rounded-full text-xs font-bold tracking-widest uppercase">
                {status || 'RELEASING'}
              </span>
              <span className="px-3 py-1 bg-white/5 border border-white/10 text-foreground/80 rounded-full text-xs font-medium">
                {formatText}
              </span>
            </div>

            <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold text-foreground mb-3 leading-tight tracking-tight drop-shadow-md">
