            </div>
          )}
        </div>
      </div>

    </div>
  );
}

import { useState, useEffect, useRef, memo } from 'react';
import { api } from '@/lib/tauri';
import { fetchCoverForBook } from "@/online-books/openlibrary/api";
import { BookOpen, User, Calendar, ExternalLink, Download, Loader2, Info } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

interface OnlineResultCardProps {
  id: string;
  title: string;
  coverUrl?: string;
  author?: string;
  description?: string;
  format?: string;
  fileSize?: string;
  language?: string;
  year?: number;
  editionCount?: number;

  // Actions
  onReadOnline?: () => void;
  onViewDetails?: () => void;
  onDownload?: () => void;
  onTorbox?: () => void;

  // State
  isDownloading?: string | boolean;
  torboxAvailable?: boolean;

  // Animation/View
  scrollRoot?: HTMLElement | null;
}

export const OnlineResultCard = memo(function OnlineResultCard({
  title,
  coverUrl,
  author,
  description,
  format,
  fileSize,
  language,
  year,
  editionCount,
  onReadOnline,
  onViewDetails,
  onDownload,
  onTorbox,
  isDownloading,
  torboxAvailable,
  scrollRoot,
}: OnlineResultCardProps) {
  const [visible, setVisible] = useState(false);
  const [imgLoaded, setImgLoaded] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [proxyUrl, setProxyUrl] = useState<string | null>(null);
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!visible || !coverUrl || imgError) return;

    let active = true;
    if (coverUrl.includes('libgen.li')) {
      setProxyUrl(`shiori-proxy://localhost?source=libgen&url=${encodeURIComponent(coverUrl)}`);
    } else {
      setProxyUrl(coverUrl);
    }

    return () => {
      active = false;
      if (proxyUrl && proxyUrl.startsWith('blob:')) {
        URL.revokeObjectURL(proxyUrl);
      }
    };
  }, [visible, coverUrl, imgError]);

  useEffect(() => {
    const el = cardRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { root: scrollRoot ?? null, threshold: 0.05 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [scrollRoot]);
  useEffect(() => {
    if (!visible || !coverUrl || !imgError) return;
    let active = true;

    // If the primary image errors out (e.g., shiori-proxy fails), try the fallback
    import('@/online-books/openlibrary/api').then(({ fetchCoverForBook }) => {
      fetchCoverForBook(title, author).then(fallbackUrl => {
        if (!active) return;
        if (fallbackUrl) {
          setProxyUrl(fallbackUrl);
          setImgError(false); // allow the img tag to try rendering again
        }
      });
    });

    return () => { active = false; };
  }, [visible, coverUrl, imgError, title, author]);


  return (
    <div
      ref={cardRef}
      onClick={onReadOnline || onViewDetails}
      className={cn(
        'group relative flex rounded-2xl border border-border/60 bg-card/60 backdrop-blur-md',
        'hover:bg-accent/40 hover:border-border/80 transition-all duration-300',
        'shadow-sm hover:shadow-md cursor-pointer',
        'md:gap-4 md:p-4',
        'max-md:flex-col max-md:p-0 max-md:overflow-hidden',
        !visible && 'opacity-0 translate-y-4',
        visible && 'animate-in fade-in slide-in-from-bottom-4 duration-500 fill-mode-forwards'
      )}
    >
      {/* Cover */}
      <div className={cn(
        "flex-shrink-0 bg-muted/50 overflow-hidden relative shadow-sm border",
        "w-24 h-36 sm:w-28 sm:h-40 rounded-lg border-border/40",
        "max-md:w-full max-md:aspect-[2/3] max-md:rounded-none max-md:border-none"
      )}>
        {!visible && <div className="absolute inset-0 bg-muted animate-pulse" />}
        {visible && proxyUrl && !imgError && (
          <>
            {!imgLoaded && (
              <div className="absolute inset-0 bg-muted animate-pulse z-0" />
            )}
            <img
              src={proxyUrl}
              alt={title}
              className={cn(
                'w-full h-full object-cover transition-all duration-500 relative z-10',
                imgLoaded ? 'opacity-100 scale-100' : 'opacity-0 scale-105'
              )}
              loading="lazy"
              onLoad={() => setImgLoaded(true)}
              onError={() => setImgError(true)}
            />
          </>
        )}
        {(!coverUrl || imgError) && visible && (
          <div className="w-full h-full p-2.5 flex flex-col justify-between text-center select-none bg-gradient-to-br from-indigo-950 via-slate-900 to-blue-950 text-slate-200 border border-indigo-500/20 shadow-inner relative overflow-hidden">
            {/* Elegant corner patterns or glows */}
            <div className="absolute top-0 right-0 w-12 h-12 bg-primary/20 rounded-full blur-xl pointer-events-none" />
            <div className="absolute bottom-0 left-0 w-12 h-12 bg-violet-500/20 rounded-full blur-xl pointer-events-none" />

            <div className="text-[9px] uppercase tracking-wider font-semibold text-indigo-400/80 mb-1 border-b border-indigo-500/10 pb-0.5 truncate">
              {format || 'BOOK'}
            </div>

            <div className="flex-1 flex items-center justify-center py-1">
              <span className="font-serif font-bold text-[10px] leading-snug line-clamp-4 tracking-tight drop-shadow-sm px-0.5">
                {title}
              </span>
            </div>

            {author && (
              <div className="text-[8px] font-medium text-slate-400 border-t border-indigo-500/10 pt-1 truncate max-w-full">
                {author}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Content */}
      <div className={cn(
        "flex-1 min-w-0 flex flex-col",
        "max-md:absolute max-md:bottom-0 max-md:left-0 max-md:right-0 max-md:bg-background/60 max-md:backdrop-blur-md max-md:border-t max-md:border-white/10 max-md:p-2 max-md:z-10"
      )}>
        <div className="mb-2 max-md:mb-0">
          <h3 className="font-semibold text-base sm:text-lg text-foreground max-md:text-[14px] max-md:leading-tight line-clamp-2 leading-tight group-hover:text-primary transition-colors max-md:text-foreground/95">
            {title}
          </h3>
          {author && (
            <div className="flex items-center gap-1.5 mt-1.5 text-sm text-muted-foreground">
              <User className="w-3.5 h-3.5 max-md:hidden" />
              <span className="line-clamp-1 max-md:text-[11px] max-md:font-medium">{author}</span>
            </div>
          )}
        </div>

        {description && (
          <p className="text-xs sm:text-sm text-muted-foreground line-clamp-2 mb-3 max-md:hidden">
            {description}
          </p>
        )}

        {/* Badges */}
        <div className="flex flex-wrap items-center gap-2 mt-auto pb-3 max-md:hidden">
          {format && (
            <span className="inline-flex items-center px-2 py-0.5 rounded text-[11px] font-medium bg-primary/10 text-primary border border-primary/20">
              {format}
            </span>
          )}
          {fileSize && (
            <span className="text-[11px] text-muted-foreground bg-muted px-2 py-0.5 rounded">
              {fileSize}
            </span>
          )}
          {year && (
            <span className="flex items-center gap-1 text-[11px] text-muted-foreground bg-muted px-2 py-0.5 rounded">
              <Calendar className="w-3 h-3" />
              {year}
            </span>
          )}
          {language && (
            <span className="text-[11px] text-muted-foreground bg-muted px-2 py-0.5 rounded">
              {language}
            </span>
          )}
          {editionCount !== undefined && editionCount > 0 && (
            <span className="text-[11px] text-muted-foreground bg-muted px-2 py-0.5 rounded">
              {editionCount} {editionCount === 1 ? 'edition' : 'editions'}
            </span>
          )}
        </div>

        {/* Actions */}
        <div className="flex items-center justify-end w-full sm:w-auto mt-auto gap-2 p-1.5 bg-background/50 backdrop-blur-sm rounded-lg border border-border/40 shadow-sm self-end max-md:hidden">
          {onReadOnline && (
            <Button size="sm" onClick={(e) => { e.stopPropagation(); onReadOnline(); }} className="gap-1.5 h-8 text-xs bg-primary/90 hover:bg-primary">
              <BookOpen className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">Read Online</span>
              <span className="sm:hidden">Read</span>
            </Button>
          )}

          {onViewDetails && (
            <Button variant="outline" size="sm" onClick={(e) => { e.stopPropagation(); onViewDetails(); }} className="gap-1.5 h-8 text-xs border-border/50 hover:bg-accent">
              <Info className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">Details</span>
              <span className="sm:hidden">Info</span>
            </Button>
          )}

          {onDownload && (
            <Button 
              variant="secondary" 
              size="sm" 
              onClick={(e) => { e.stopPropagation(); onDownload(); }}
              disabled={Boolean(isDownloading)}
              className="gap-1.5 h-8 text-xs font-medium"
            >
              {isDownloading ? (
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
              ) : (
                <Download className="w-3.5 h-3.5" />
              )}
              <span className="hidden sm:inline">
                {isDownloading ? (typeof isDownloading === 'string' ? isDownloading : 'Downloading...') : 'Download'}
              </span>
            </Button>
          )}

          {onTorbox && torboxAvailable && (
            <Button variant="outline" size="sm" onClick={(e) => { e.stopPropagation(); onTorbox(); }} className="gap-1.5 h-8 text-xs border-border/50 hover:bg-accent">
              <Download className="w-3.5 h-3.5" />
              Torbox
            </Button>
          )}
          {torboxAvailable === false && (
            <p className="text-[10px] text-muted-foreground/60 flex items-center ml-1">
              Torbox unavailable
            </p>
          )}
        </div>
      </div>
    </div>
  );
});

import { cn } from '@/lib/utils';
import { Compass, Filter, Globe, BookOpen, Search } from 'lucide-react';
import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { OnlineSourceSelector } from './OnlineSourceSelector';
import { AdvancedOnlineSearchDialog } from './AdvancedOnlineSearchDialog';

import { useOnlineSearchStore } from '@/store/onlineSearchStore';
import { usePreferencesStore } from '@/store/preferencesStore';
import { useUIStore } from '@/store/uiStore';
import { useIsMobile } from '@/hooks/useIsMobile';
import type { SourceKind } from '@/store/sourceStore';

interface OnlineSearchHeaderProps {
  kind: SourceKind;
  title: string;
  subtitle: string;
  searchValue: string;
  loading: boolean;
  disabled: boolean;
  disabledMessage?: string;
  onSearchValueChange: (value: string) => void;
  onSubmit: () => void;
  onMobileFilterClick?: () => void;
}

export function OnlineSearchHeader({
  kind,
  title,
  subtitle,
  searchValue,
  loading,
  disabled,
  disabledMessage,
  onSearchValueChange,
  onSubmit,
  onMobileFilterClick,
}: OnlineSearchHeaderProps) {
  const [advancedOpen, setAdvancedOpen] = useState(false);
  const filters = useOnlineSearchStore(state => state.filters[kind === 'books' ? 'online-books' : 'online-manga']);
  const hasFilters = Object.keys(filters || {}).length > 0;
  const preferences = usePreferencesStore(state => state.preferences);
  const updateGeneralSettings = usePreferencesStore(state => state.updateGeneralSettings);
  const isMobile = useIsMobile();
  const setCurrentView = useUIStore(state => state.setCurrentView);

  return (
    <div className={cn(
      "flex-shrink-0 relative overflow-hidden z-10 transition-colors duration-500",
      isMobile ? "pt-12 pb-2 px-3 bg-background" : "bg-background/60 backdrop-blur-3xl border-b border-border pt-16 pb-8 px-8"
    )}>
      {/* Subtle ambient glass glow */}
      {!isMobile && <div className="absolute top-0 right-1/4 w-[500px] h-[500px] bg-primary/5 rounded-full blur-[120px] -z-10 pointer-events-none" />}

      <div className="max-w-7xl mx-auto relative z-10">
        <div className="flex flex-col gap-3 md:gap-6">
          <div className="hidden md:flex items-center justify-between">
            <h1 className="text-5xl font-semibold tracking-tight text-foreground drop-shadow-sm">
              {title}
            </h1>
            <OnlineSourceSelector kind={kind} variant="secondary" className="h-10 px-4 bg-secondary/80 hover:bg-secondary text-secondary-foreground border border-border rounded-md shadow-sm backdrop-blur-md" />
          </div>

          <div className="relative group">
            {isMobile ? (
              // Mobile Premium Search Bar (Precision Noir)
              <div className="flex items-center bg-background/60 backdrop-blur-xl border border-border/50 rounded-full p-1.5 focus-within:border-primary/50 focus-within:bg-background transition-all duration-300 shadow-sm">

                {/* Left side actions */}
                <div className="flex items-center gap-1 pl-1 shrink-0">
                  <Search className="w-4 h-4 text-muted-foreground ml-2 mr-1 hidden sm:block" />

                  {/* Filter Option */}
                  {(kind === 'books' || kind === 'manga') && (
                    <button 
                      onClick={() => kind === 'books' ? setAdvancedOpen(true) : onMobileFilterClick?.()}
                      className={cn(
                        "w-9 h-9 rounded-full flex items-center justify-center transition-all shrink-0",
                        (kind === 'books' && hasFilters) || kind === 'manga'
                          ? "bg-primary text-primary-foreground shadow-md" 
                          : "text-muted-foreground hover:text-foreground hover:bg-secondary/80 bg-background/50"
                      )}
                      disabled={disabled}
                      title="Filters"
                    >
                      <Filter className="w-4 h-4" />
                    </button>
                  )}

                  {/* Sources Option */}
                  <OnlineSourceSelector 
                    kind={kind} 
                    variant="ghost" 
                    className="w-9 h-9 p-0 rounded-full flex items-center justify-center transition-all hover:bg-secondary/80 text-muted-foreground shrink-0 max-md:[&>span]:hidden" 
                  />
                </div>

                {/* Input */}
                <input
                  value={searchValue}
                  onChange={(e) => onSearchValueChange(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') onSubmit();
                  }}
                  placeholder={kind === 'books' ? 'Search books...' : 'Search manga...'}
                  className="flex-1 bg-transparent border-none outline-none text-[15px] font-medium text-foreground placeholder:text-muted-foreground/60 focus:ring-0 py-2 px-3 min-w-0"
                  disabled={disabled}
                />

                {/* Right side actions */}
                <div className="flex items-center pr-1 shrink-0">
                  {searchValue.trim() && (
                    <button 
                      onClick={onSubmit} 
                      disabled={loading || disabled}
                      className="px-4 py-1.5 rounded-full bg-foreground text-background text-sm font-semibold hover:bg-foreground/90 disabled:opacity-50 transition-all shadow-md active:scale-95"
                    >
                      Go
                    </button>
                  )}
                </div>
              </div>
            ) : (
              // Desktop Search Bar
              <div className="flex items-end border-b border-border focus-within:border-primary transition-colors duration-300 pb-2">
                <Compass className="w-6 h-6 text-muted-foreground mb-4 mr-4" />
                <input
                  value={searchValue}
                  onChange={(e) => onSearchValueChange(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') onSubmit();
                  }}
                  placeholder={kind === 'books' ? 'Search your library...' : 'Search manga by title...'}
                  className="w-full bg-transparent border-none outline-none text-2xl font-medium text-foreground placeholder:text-muted-foreground/50 focus:ring-0 py-4 px-0"
                  disabled={disabled}
                />
                <div className="flex items-center gap-3 mb-0.5 ml-4">
                  {(kind === 'books' || kind === 'manga') && (
                    <button 
                      onClick={() => kind === 'books' ? setAdvancedOpen(true) : onMobileFilterClick?.()}
                      className={`p-3 rounded-xl transition-all ${hasFilters || kind === 'manga' ? 'bg-primary text-primary-foreground shadow-md' : 'text-muted-foreground hover:text-foreground hover:bg-secondary/80'}`}
                      disabled={disabled}
                      title="Filters"
                    >
                      <Filter className="w-5 h-5" />
                    </button>
                  )}
                  <button 
                    onClick={onSubmit} 
                    disabled={loading || (!searchValue.trim() && !hasFilters) || disabled}
                    className="px-6 py-3 text-base rounded-xl bg-foreground text-background font-semibold hover:bg-foreground/90 disabled:opacity-50 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 active:translate-y-0"
                  >
                    Search
                  </button>
                </div>
              </div>
            )}
          </div>

          {isMobile && preferences?.preferredContentType === 'both' && (
            <div className="flex px-2 gap-2 mt-2">
              <button
                onClick={() => setCurrentView('online-books')}
                className={cn(
                  "flex-1 flex items-center justify-center gap-2 py-3 text-[14px] font-semibold rounded-full transition-all relative overflow-hidden",
                  kind === 'books'
                    ? "text-foreground bg-secondary/40 shadow-sm"
                    : "text-muted-foreground hover:text-foreground hover:bg-secondary/10"
                )}
              >
                <Globe className="w-4 h-4" /> Books
              </button>
              <button
                onClick={() => setCurrentView('online-manga')}
                className={cn(
                  "flex-1 flex items-center justify-center gap-2 py-3 text-[14px] font-semibold rounded-full transition-all relative overflow-hidden",
                  kind === 'manga'
                    ? "text-foreground bg-secondary/40 shadow-sm"
                    : "text-muted-foreground hover:text-foreground hover:bg-secondary/10"
                )}
              >
                <BookOpen className="w-4 h-4" /> Manga
              </button>
            </div>
          )}
        </div>

        {kind === 'books' && (
          <AdvancedOnlineSearchDialog 
            open={advancedOpen}
            onOpenChange={setAdvancedOpen}
            onSearch={onSubmit}
          />
        )}

        {disabled && disabledMessage && (
          <div className="mt-4 p-4 rounded-xl bg-destructive/10 border border-destructive/20 text-sm font-medium text-destructive shadow-inner">
            {disabledMessage}
          </div>
        )}
      </div>
    </div>
  );
}

