                      <p
                        className="premium-search-result-snippet"
                        dangerouslySetInnerHTML={{
                          __html: DOMPurify.sanitize(highlightMatches(result.snippet, searchQuery)),
                        }}
                      />
                      <span className="premium-search-result-matches">
                        {result.match_count} match{result.match_count !== 1 ? 'es' : ''}
                      </span>
                    </motion.div>
                  ))}
                </motion.div>
              )}

              {!isSearching && searchQuery.trim().length >= 2 && searchResults.length === 0 && (
                <p className="premium-sidebar-empty">No results found</p>
              )}

              {searchQuery.trim().length > 0 && searchQuery.trim().length < 2 && (
                <p className="premium-sidebar-empty" style={{ fontSize: 12 }}>Type at least 2 characters</p>
              )}
            </div>
          )}
          </div>
        </motion.div>
      </>
      )}
    </AnimatePresence>
  );
}

// Helper component for rendering TOC items recursively
interface TocItemProps {
  entry: TocEntry;
  onClick: (entry: TocEntry) => void;
  currentIndex: number;
}

function TocItem({ entry, onClick, currentIndex }: TocItemProps) {
  const chapterMatch = entry.location.match(/(?:^|[^\w])(?:chapter[_:-]?|generic-chapter-|mobi-chapter-|[a-z0-9]+-chapter-)(\d+)/i);
  const pageMatch = entry.location.match(/^page[:-](\d+)/i);
  const cfiNestedMatch = entry.location.match(/epubcfi\(\/\d+\/(\d+)\b/i);
  const cfiSimpleMatch = entry.location.match(/epubcfi\(\/(\d+)\b/i);
  const chapterIndex = chapterMatch
    ? parseInt(chapterMatch[1], 10)
    : pageMatch
      ? parseInt(pageMatch[1], 10)
      : cfiNestedMatch
        ? parseInt(cfiNestedMatch[1], 10)
        : cfiSimpleMatch
          ? parseInt(cfiSimpleMatch[1], 10)
          : -1;
  const isCurrent = chapterIndex === currentIndex;

  return (
    <div className="premium-toc-item" style={{ paddingLeft: `${entry.level * 16}px` }}>
      <button
        onClick={() => onClick(entry)}
        className={`premium-toc-button ${isCurrent ? 'premium-toc-button--current' : ''}`}
      >
        <BookOpen size={14} className="premium-toc-icon" />
        <span className="premium-toc-label" style={{ flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{entry.label}</span>
      </button>
      {entry.children && entry.children.length > 0 && (
        <div className="premium-toc-children">
          {entry.children.map((child, index) => (
            <TocItem
              key={index}
              entry={child}
              onClick={onClick}
              currentIndex={currentIndex}
            />
          ))}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { useReaderStore } from '@/store/readerStore';
import { api } from '@/lib/tauri';
import { invoke } from '@tauri-apps/api/core';
import { logger } from '@/lib/logger';
import { PremiumEpubReader } from './PremiumEpubReader';
import { PdfReader } from './PdfReader';
import { GenericHtmlReader } from './GenericHtmlReader';
import { MangaReader } from '@/components/manga/MangaReader';
import { ReaderErrorBoundary, parseReaderError } from './ReaderErrorBoundary';
import { ConversionProgress } from './ConversionProgress';
import type { ReaderFormat } from './ReaderSettings';
import type { ReaderContent } from './readerContent';

interface ReaderLayoutProps {
  bookId: number;
  onClose: () => void;
}

type LoadingStage =
  | 'idle'
  | 'fetching-path'
  | 'detecting-format'
  | 'converting'
  | 'validating-file'
  | 'loading-metadata'
  | 'complete';

// Formats handled as-is by their native readers (no conversion needed)
const NATIVE_FORMATS = ['epub', 'pdf', 'cbz', 'cbr'];

export function ReaderLayout({ bookId, onClose }: ReaderLayoutProps) {
  const {
    currentBookPath,
    currentBookFormat,
    openBook,
    setProgress,
    setAnnotations,
    setSettings,
    closeBook,
    currentContent,
  } = useReaderStore();

  const [loadingStage, setLoadingStage] = useState<LoadingStage>('idle');
  const [error, setError] = useState<ReturnType<typeof parseReaderError> | null>(null);
  const [retryCount, setRetryCount] = useState(0);
  const [bookTitle, setBookTitle] = useState<string | undefined>(undefined);

  useEffect(() => {
    let currentStage: LoadingStage = 'idle';
    const updateStage = (stage: LoadingStage) => {
      currentStage = stage;
      setLoadingStage(stage);
    };

    const loadBookData = async () => {
      try {
        updateStage('fetching-path');
        setError(null);

        logger.debug('[ReaderLayout] Step 1: Getting file path for bookId:', bookId);
        const filePath = await api.getBookFilePath(bookId);
        logger.debug('[ReaderLayout] Step 1 ✓ Got file path:', filePath);

        // Step 2: Detect format
        updateStage('detecting-format');
        let detectedFormat: string;
        try {
          detectedFormat = await api.detectBookFormat(filePath);
        } catch {
          detectedFormat = filePath.split('.').pop()?.toLowerCase() || 'epub';
        }
        const finalFormat = detectedFormat.toLowerCase();
        logger.debug('[ReaderLayout] Detected format:', finalFormat);

        // Step 3: Convert if not a natively handled format
        let finalFilePath = filePath;

        if (!NATIVE_FORMATS.includes(finalFormat)) {
          logger.debug('[ReaderLayout] Format', finalFormat, 'needs conversion → running open_book_for_reading');
          updateStage('converting');

          try {
            // open_book_for_reading handles: MOBI, AZW3, DOCX, FB2, TXT, CBZ, CBR, PDF
            // It emits conversion-progress events → picked up by <ConversionProgress>
            const convertedPath = await api.openBookForReading(bookId);
            logger.info('[ReaderLayout] ✓ Converted/opened:', convertedPath);
            finalFilePath = convertedPath;
            // format is now epub (the command outputs EPUB for all non-native types)
          } catch (convErr) {
            logger.warn('[ReaderLayout] openBookForReading failed, falling back to convertAndReplaceBook:', convErr);
            try {
              const result = await api.convertAndReplaceBook(bookId);
              finalFilePath = result.new_path;
              logger.info('[ReaderLayout] ✓ Fallback conversion succeeded:', finalFilePath);
            } catch (fallbackErr) {
              logger.warn('[ReaderLayout] Fallback also failed, using original file:', fallbackErr);
              // Continue with the original — GenericHtmlReader will do its best
            }
          }
        }

        // Determine effective format from the (possibly converted) file path
        const effectiveFormat = finalFilePath.endsWith('.epub')
          ? 'epub'
          : finalFormat;

        // Step 4: Validate file
        updateStage('validating-file');
        try {
          await api.validateBookFile(finalFilePath, effectiveFormat);
        } catch {
          // Non-fatal — let the reader attempt to open it
        }

        // Step 5: Fetch book metadata + open in store
        updateStage('loading-metadata');
        const startupData = await invoke<{
          book: any;
          progress: any;
          annotations: any;
          settings: any;
        }>('get_reader_startup_data', { bookId });

        const { book, progress, annotations, settings } = startupData;

        setBookTitle(book.title);

        const content: ReaderContent = {
          title: book.title,
          author: book.authors?.[0]?.name,
          cover: book.cover_path,
          isbn: book.isbn13 || book.isbn,
          format: effectiveFormat,
        };
        if (effectiveFormat === 'pdf' && typeof book.page_count === 'number') {
          content.pages = book.page_count;
        }

        openBook(bookId, finalFilePath, effectiveFormat, content);

        if (progress) setProgress(progress);
        setAnnotations(annotations);
        setSettings(settings);

        updateStage('complete');
        logger.debug('[ReaderLayout] ✅ All steps complete!');
      } catch (err) {
        logger.error('[ReaderLayout] ❌ Error at stage:', currentStage, err);
        setError(parseReaderError(err));
        updateStage('idle');
      }
    };

    // 90 s timeout — long enough for large MOBI/CBR files
    const timeoutId = setTimeout(() => {
      if (currentStage !== 'complete' && currentStage !== 'idle') {
        setError({
          title: 'Loading Timeout',
          message: currentStage === 'converting'
            ? 'Conversion is taking too long. The file may be very large or corrupted.'
            : 'The book is taking too long to load.',
          suggestions: [
            'Try closing and reopening the book',
            'Restart the application',
            'Check if the file is very large (>200MB)',
          ],
          technicalDetails: `Timeout at stage: ${currentStage}`,
        });
        updateStage('idle');
      }
    }, 90_000);

    loadBookData();

    return () => {
      clearTimeout(timeoutId);
    };
  }, [bookId, retryCount, openBook, setAnnotations, setProgress, setSettings]);

  const handleClose = () => { closeBook(); onClose(); };
  const handleRetry = () => { setRetryCount(p => p + 1); setError(null); setLoadingStage('idle'); };

  const handleNextChapter = useCallback(async () => {
    try {
      const nextBook: any = await invoke('get_next_book_in_series', { bookId });
      if (nextBook && nextBook.id) {
        import('@/store/toastStore').then(({ useToastStore }) => {
          useToastStore.getState().addToast({
            title: `Continuing to ${nextBook.title}`,
            variant: 'success',
            duration: 3000,
          });
        });
        // Use the app-wide event to switch the active book in the reader
        window.dispatchEvent(new CustomEvent('open-book', { detail: { bookId: nextBook.id } }));
      } else {
        import('@/store/toastStore').then(({ useToastStore }) => {
          useToastStore.getState().addToast({
            title: 'You have finished the series!',
            variant: 'info',
            duration: 3000,
          });
        });
      }
    } catch (e) {
      logger.error('Failed to get next book in series', e);
    }
  }, [bookId]);

  // ── CONVERSION OVERLAY ─────────────────────────────────────────────────
  // Shown during 'converting' stage — replaces the generic spinner with the
  // animated ConversionProgress component that listens to Tauri events.
  if (loadingStage === 'converting') {
    return (
      <ConversionProgress
        visible
        bookTitle={bookTitle}
        onComplete={() => {/* conversion-progress events control this; stage updates complete it */}}
      />
    );
  }

  // ── GENERIC LOADING SPINNER ────────────────────────────────────────────
  if (loadingStage !== 'complete' && loadingStage !== 'idle' && !error) {
    const stageMessages: Record<LoadingStage, string> = {
      idle: 'Preparing...',
      'fetching-path': 'Locating book file...',
      'detecting-format': 'Detecting file format...',
      converting: 'Converting...',
      'validating-file': 'Validating file...',
      'loading-metadata': 'Loading book data...',
      complete: 'Complete',
    };
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center" style={{ backgroundColor: 'var(--reader-bg)' }}>
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 mb-4 mx-auto" style={{ borderColor: 'var(--loading-spinner)' }} />
          <p style={{ color: 'var(--text-secondary)' }}>{stageMessages[loadingStage]}</p>
        </div>
      </div>
    );
  }

  // ── ERROR STATE ────────────────────────────────────────────────────────
  if (error) {
    return (
      <div className="fixed inset-0 z-50">
        <ReaderErrorBoundary error={error} onRetry={handleRetry} onClose={handleClose} />
      </div>
    );
  }



  // ── READER ─────────────────────────────────────────────────────────────
  return (
    <div className="fixed inset-0 z-50 flex flex-col" style={{ backgroundColor: 'var(--reader-bg)' }}>
      {currentBookPath && currentBookFormat === 'epub' && (
        <PremiumEpubReader bookPath={currentBookPath} bookId={bookId} readerContent={currentContent} onClose={handleClose} />
      )}
      {currentBookPath && currentBookFormat === 'pdf' && (
        <PdfReader bookPath={currentBookPath} bookId={bookId} readerContent={currentContent} onClose={handleClose} />
      )}
      {currentBookPath && (['cbz', 'cbr', 'zip', 'rar'].includes(currentBookFormat || '')) && (
        <MangaReader mode="local" bookId={bookId} bookPath={currentBookPath} onClose={handleClose} onNextChapter={handleNextChapter} />
      )}
      {currentBookPath && !['epub', 'pdf', 'cbz', 'cbr', 'zip', 'rar'].includes(currentBookFormat || '') && (
        <GenericHtmlReader
          bookPath={currentBookPath}
          bookId={bookId}
          format={currentBookFormat as ReaderFormat}
          readerContent={currentContent}
          onClose={handleClose}
        />
      )}
      {!currentBookPath && (
        <div className="flex items-center justify-center h-full">
          <p style={{ color: 'var(--text-secondary)' }}>No book loaded</p>
        </div>
      )}
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useIsMobile } from '@/hooks/useIsMobile';
import { useReadingSettings, BG_COLOR_PRESETS, TEXT_COLOR_PRESETS, type ReaderTheme, applyReaderThemeToElement } from '@/store/premiumReaderStore';
import { Settings, Columns, ChevronDown, ChevronUp } from '@/components/icons';
import { READING_FONTS, normalizeLegacyFontPreference } from '@/lib/readingFonts';

export type ReaderFormat = 'epub' | 'pdf' | 'mobi' | 'azw' | 'azw3' | 'manga' | 'fb2' | 'docx' | 'html' | 'htm' | 'txt' | 'md' | 'markdown';

interface ReaderSettingsProps {
  /** Current book format — controls which settings are visible */
  format?: ReaderFormat;
}

const PortalWrapper = ({ children, usePortal }: { children: React.ReactNode, usePortal: boolean }) => {
  if (!usePortal) return <>{children}</>;
  return createPortal(children, document.body);
};

export function ReaderSettings({ format = 'epub' }: ReaderSettingsProps) {
  const [isOpen, setIsOpen] = useState(false);
  const panelRef = useRef<HTMLDivElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const isMobile = useIsMobile();

  const {
    theme,
    fontFamily,
    fontSize,
    lineHeight,
    paragraphSpacing,
    letterSpacing,
    backgroundColor,
    textColor,
    margin,
    brightness,
    width,
    twoPageView,
    pageFlipEnabled,
    pageFlipSpeed,
    animationStyle,
    paperTextureIntensity,
    uiScale,
    textAlign,
    setTheme,
    setFontFamily,
    setFontSize,
    setLineHeight,
    setParagraphSpacing,
    setLetterSpacing,
    setBackgroundColor,
    setTextColor,
    setMargin,
    setBrightness,
    setWidth,
    toggleTwoPageView,
    setPageFlipEnabled,
    setPageFlipSpeed,
    setAnimationStyle,
    setPaperTextureIntensity,
    setUiScale,
    setTextAlign,
  } = useReadingSettings();

  useEffect(() => {
    if (panelRef.current) {
      applyReaderThemeToElement(panelRef.current, theme);
    }
  }, [theme, isOpen, isMobile]);

  const showTypography = format === 'epub' || format === 'mobi' || format === 'azw' || format === 'azw3';
  const showLayout = format === 'epub';
  const showPageTransition = format === 'epub';
  const isTextFormat = !['pdf', 'manga'].includes(format);
  const isPdf = format === 'pdf';
  const showWidthControls = showTypography || isPdf;
  const showSpacingControls = isTextFormat || isPdf;

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (
        panelRef.current &&
        buttonRef.current &&
        !panelRef.current.contains(e.target as Node) &&
        !buttonRef.current.contains(e.target as Node)
      ) {
        setIsOpen(false);
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [isOpen]);

  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        setIsOpen(false);
      }
    };

    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, [isOpen]);

  const normalizedFontFamily = normalizeLegacyFontPreference(fontFamily);

  const letterSpacingOptions = [
    { id: 'tight', label: 'Tight' },
    { id: 'normal', label: 'Normal' },
    { id: 'relaxed', label: 'Relax' },
    { id: 'wide', label: 'Wide' },
  ];

  const paragraphSpacingOptions = [
    { id: '0.5em', label: 'Small' },
    { id: '1em', label: 'Medium' },
    { id: '1.5em', label: 'Large' },
    { id: '2em', label: 'Extra' },
  ];

  const widthOptions: Array<{ id: 'narrow' | 'medium' | 'wide' | 'full'; label: string; chars: string }> = [
    { id: 'narrow', label: 'Narrow', chars: '45ch' },
    { id: 'medium', label: 'Medium', chars: '60ch' },
    { id: 'wide', label: 'Wide', chars: '75ch' },
    { id: 'full', label: 'Full', chars: '100%' },
  ];

  return (
    <div className="premium-settings-container">
      <button
        ref={buttonRef}
        onClick={() => setIsOpen(!isOpen)}
        className={`premium-control-button ${isOpen ? 'premium-control-button--active' : ''}`}
        aria-label="Settings"
        title="Reading settings"
      >
        <Settings className="premium-control-icon" />
      </button>

      {isOpen && (
        <PortalWrapper usePortal={isMobile}>
          <div className="md:hidden fixed inset-0 bg-black/40 z-[105]" onClick={() => setIsOpen(false)} />
          <div ref={panelRef} className="premium-settings-panel z-[110]">
            <div className="premium-settings-section">
            <label className="premium-settings-label">View Mode</label>
            <div className="premium-settings-width-grid">
              {[
                {
                  id: 'light' as ReaderTheme,
                  label: 'Light',
                  icon: (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <circle cx="12" cy="12" r="5" />
                      <line x1="12" y1="1" x2="12" y2="3" />
                      <line x1="12" y1="21" x2="12" y2="23" />
                      <line x1="4.22" y1="4.22" x2="5.64" y2="5.64" />
                      <line x1="18.36" y1="18.36" x2="19.78" y2="19.78" />
                      <line x1="1" y1="12" x2="3" y2="12" />
                      <line x1="21" y1="12" x2="23" y2="12" />
                      <line x1="4.22" y1="19.78" x2="5.64" y2="18.36" />
                      <line x1="18.36" y1="5.64" x2="19.78" y2="4.22" />
                    </svg>
                  ),
                },
                {
                  id: 'black' as ReaderTheme,
                  label: 'Black',
                  icon: (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" />
                      <circle cx="12" cy="12" r="3" />
                    </svg>
                  ),
                },
                {
                  id: 'paper' as ReaderTheme,
                  label: 'Paper',
                  icon: (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
                      <polyline points="14 2 14 8 20 8" />
                    </svg>
                  ),
                },
                {
                  id: 'paper-dark' as ReaderTheme,
                  label: 'Paper Dark',
                  icon: (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z" />
                      <path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z" />
                    </svg>
                  ),
                },
              ].map((opt) => (
                <button
                  key={opt.id}
                  onClick={() => setTheme(opt.id)}
                  className={`premium-settings-width-option ${theme === opt.id ? 'premium-settings-width-option--active' : ''}`}
                >
                  {opt.icon}
                  <span className="premium-settings-option-label">{opt.label}</span>
                </button>
              ))}
            </div>
          </div>


          {showTypography && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">
                Font Size
                <span className="premium-settings-value">{fontSize}px</span>
              </label>
              <div className="premium-settings-slider-container">
                <button
                  onClick={() => setFontSize(fontSize - 1)}
                  className="premium-settings-slider-button"
                  disabled={fontSize <= 12}
                >
                  <ChevronDown className="premium-settings-slider-icon" />
                </button>
                <input
                  type="range"
                  min="12"
                  max="32"
                  value={fontSize}
                  onChange={(e) => setFontSize(Number(e.target.value))}
                  className="premium-settings-slider"
                />
                <button
                  onClick={() => setFontSize(fontSize + 1)}
                  className="premium-settings-slider-button"
                  disabled={fontSize >= 32}
                >
                  <ChevronUp className="premium-settings-slider-icon" />
                </button>
              </div>
            </div>
          )}

          {showSpacingControls && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">
                Margin
                <span className="premium-settings-value">{margin}px</span>
              </label>
              <div className="premium-settings-slider-container">
                <input
                  type="range"
                  min="0"
                  max="80"
                  step="4"
                  value={margin}
                  onChange={(e) => setMargin(Number(e.target.value))}
                  className="premium-settings-slider"
                />
              </div>
            </div>
          )}

          {isTextFormat && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Letter Spacing</label>
              <div className="premium-settings-segment-group">
                {letterSpacingOptions.map((opt) => (
                  <button
                    key={opt.id}
                    onClick={() => setLetterSpacing(opt.id)}
                    className={`premium-settings-segment-button ${letterSpacing === opt.id ? 'premium-settings-segment-button--active' : ''}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {isTextFormat && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Paragraph Spacing</label>
              <div className="premium-settings-segment-group">
                {paragraphSpacingOptions.map((opt) => (
                  <button
                    key={opt.id}
                    onClick={() => setParagraphSpacing(opt.id)}
                    className={`premium-settings-segment-button ${paragraphSpacing === opt.id ? 'premium-settings-segment-button--active' : ''}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {showTypography && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">
                Line Height
                <span className="premium-settings-value">{lineHeight.toFixed(1)}</span>
              </label>
              <div className="premium-settings-slider-container">
                <button
                  onClick={() => setLineHeight(Math.max(1.2, lineHeight - 0.1))}
                  className="premium-settings-slider-button"
                  disabled={lineHeight <= 1.2}
                >
                  <ChevronDown className="premium-settings-slider-icon" />
                </button>
                <input
                  type="range"
                  min="1.2"
                  max="2.0"
                  step="0.1"
                  value={lineHeight}
                  onChange={(e) => setLineHeight(Number(e.target.value))}
                  className="premium-settings-slider"
                />
                <button
                  onClick={() => setLineHeight(Math.min(2.0, lineHeight + 0.1))}
                  className="premium-settings-slider-button"
                  disabled={lineHeight >= 2.0}
                >
                  <ChevronUp className="premium-settings-slider-icon" />
                </button>
              </div>
            </div>
          )}

          {showWidthControls && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Reading Width</label>
              <div className="premium-settings-segment-group">
                {widthOptions.map((option) => (
                  <button
                    key={option.id}
                    onClick={() => setWidth(option.id)}
                    className={`premium-settings-segment-button ${width === option.id ? 'premium-settings-segment-button--active' : ''}`}
                    title={option.chars}
                  >
                    {option.label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {(isTextFormat || isPdf) && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">
                Brightness
                <span className="premium-settings-value">{Math.round(brightness * 100)}%</span>
              </label>
              <div className="premium-settings-slider-container">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="premium-settings-slider-icon">
                  <circle cx="12" cy="12" r="4"/>
                  <path d="M12 2v2"/><path d="M12 20v2"/><path d="m4.93 4.93 1.41 1.41"/><path d="m17.66 17.66 1.41 1.41"/><path d="M2 12h2"/><path d="M20 12h2"/><path d="m6.34 17.66-1.41 1.41"/><path d="m19.07 4.93-1.41 1.41"/>
                </svg>
                <input
                  type="range"
                  min="0.5"
                  max="1.5"
                  step="0.05"
                  value={brightness}
                  onChange={(e) => setBrightness(Number(e.target.value))}
                  className="premium-settings-slider"
                />
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="premium-settings-slider-icon">
                  <circle cx="12" cy="12" r="5"/>
                  <path d="M12 1v2"/><path d="M12 21v2"/><path d="M4.22 4.22l1.42 1.42"/><path d="M18.36 18.36l1.42 1.42"/><path d="M1 12h2"/><path d="M21 12h2"/><path d="M4.22 19.78l1.42-1.42"/><path d="M18.36 5.64l1.42-1.42"/>
                </svg>
              </div>
            </div>
          )}

          {isTextFormat && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Font Family</label>
              <div className="premium-settings-font-grid">
                {READING_FONTS.map((font) => (
                  <button
                    key={font.id}
                    onClick={() => setFontFamily(font.id)}
                    className={`premium-settings-font-option ${normalizedFontFamily === font.id ? 'premium-settings-font-option--active' : ''}`}
                    style={{ fontFamily: font.previewFamily }}
                  >
                    {font.label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {showTypography && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Text Alignment</label>
              <div className="premium-settings-segment-group">
                {([
                  {
                    id: 'left' as const,
                    label: 'Left',
                    icon: (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="17" y1="10" x2="3" y2="10" />
                        <line x1="21" y1="6" x2="3" y2="6" />
                        <line x1="21" y1="14" x2="3" y2="14" />
                        <line x1="17" y1="18" x2="3" y2="18" />
                      </svg>
                    ),
                  },
                  {
                    id: 'justify' as const,
                    label: 'Justify',
                    icon: (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="21" y1="10" x2="3" y2="10" />
                        <line x1="21" y1="6" x2="3" y2="6" />
                        <line x1="21" y1="14" x2="3" y2="14" />
                        <line x1="21" y1="18" x2="3" y2="18" />
                      </svg>
                    ),
                  },
                ]).map((opt) => (
                  <button
                    key={opt.id}
                    onClick={() => setTextAlign(opt.id)}
                    className={`premium-settings-segment-button ${textAlign === opt.id ? 'premium-settings-segment-button--active' : ''}`}
                  >
                    {opt.icon}
                    <span>{opt.label}</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {showLayout && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Layout Mode</label>

              <button
                onClick={toggleTwoPageView}
                className={`premium-settings-toggle ${twoPageView ? 'premium-settings-toggle--active' : ''}`}
              >
                <Columns className="premium-settings-icon" />
                <span>Two-Page View</span>
              </button>
            </div>
          )}

          {showPageTransition && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">Page Transition</label>
              <button
                onClick={() => setPageFlipEnabled(!pageFlipEnabled)}
                className={`premium-settings-toggle ${pageFlipEnabled ? 'premium-settings-toggle--active' : ''}`}
              >
                <svg className="premium-settings-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z" />
                  <path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z" />
                </svg>
                <span>Enable Page Transition</span>
              </button>
              {pageFlipEnabled && (
                <>
                  <div className="premium-settings-segment-group" style={{ marginTop: 8 }}>
                    {([
                      { id: 'slide' as const, label: 'Slide' },
                      { id: 'fade' as const, label: 'Fade' },
                      { id: 'none' as const, label: 'Instant' },
                    ]).map((opt) => (
                      <button
                        key={opt.id}
                        onClick={() => setAnimationStyle(opt.id)}
                        className={`premium-settings-segment-button ${animationStyle === opt.id ? 'premium-settings-segment-button--active' : ''}`}
                      >
                        {opt.label}
                      </button>
                    ))}
                  </div>
                  {animationStyle !== 'none' && (
                    <div className="premium-settings-slider-container" style={{ marginTop: 8 }}>
                      <span style={{ fontSize: 12, color: 'var(--text-tertiary)', whiteSpace: 'nowrap' }}>Speed</span>
                      <input
                        type="range"
                        min="100"
                        max="800"
                        step="50"
                        value={pageFlipSpeed}
                        onChange={(e) => setPageFlipSpeed(Number(e.target.value))}
                        className="premium-settings-slider"
                      />
                      <span style={{ fontSize: 12, color: 'var(--text-tertiary)', whiteSpace: 'nowrap' }}>{pageFlipSpeed}ms</span>
                    </div>
                  )}
                </>
              )}
            </div>
          )}

          {(theme === 'paper' || theme === 'paper-dark') && (
            <div className="premium-settings-section">
              <label className="premium-settings-label">
                Texture Intensity
                <span className="premium-settings-value">{(paperTextureIntensity * 100).toFixed(0)}%</span>
              </label>
              <div className="premium-settings-slider-container">
                <input
                  type="range"
                  min="0"
                  max="0.20"
                  step="0.01"
                  value={paperTextureIntensity}
                  onChange={(e) => setPaperTextureIntensity(Number(e.target.value))}
                  className="premium-settings-slider"
                />
              </div>
            </div>
          )}

          <div className="premium-settings-section">
            <label className="premium-settings-label">
              UI Scale
              <span className="premium-settings-value">{uiScale.toFixed(1)}x</span>
            </label>
            <div className="premium-settings-slider-container">
              <input
                type="range"
                min="0.8"
                max="1.4"
                step="0.05"
                value={uiScale}
                onChange={(e) => setUiScale(Number(e.target.value))}
                className="premium-settings-slider"
              />
            </div>
          </div>
        </div>
        </PortalWrapper>
      )}
    </div>
  );
}

import { logger } from '@/lib/logger';
import React from 'react';
import { useReaderUIStore } from '@/store/premiumReaderStore';
import { useBookReadingTime } from '@/hooks/useBookReadingTime';
import { ArrowLeft, Clock, Maximize2, Minimize2, Bookmark, ZoomIn, ZoomOut, MoreVertical } from '@/components/icons';
// Removed DropdownMenu imports
import { ReaderSettings, type ReaderFormat } from './ReaderSettings';
import { WindowControls } from '../layout/WindowControls';
import { useFullscreen } from '@/hooks/useFullscreen';
import { useReadingSettings } from '@/store/premiumReaderStore';

interface ReaderTopBarProps {
  bookId: number;
  title: string;
  subtitle: string;
  progress: number;
  format: ReaderFormat;
  onClose: () => void;
  centerExtra?: React.ReactNode;
  rightExtra?: React.ReactNode;
}

export function ReaderTopBar({
  bookId,
  title,
  subtitle,
  progress,
  format,
  onClose,
  centerExtra,
  rightExtra,
}: ReaderTopBarProps) {
  const isTopBarVisible = useReaderUIStore(state => state.isTopBarVisible);
  const toggleSidebar = useReaderUIStore(state => state.toggleSidebar);
  const { formattedTime } = useBookReadingTime(bookId);
  const { isFullscreen, toggleFullscreen } = useFullscreen();
  const increaseFontSize = useReadingSettings(state => state.increaseFontSize);
  const decreaseFontSize = useReadingSettings(state => state.decreaseFontSize);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = React.useState(false);

  return (
    <div className={`premium-top-bar ${!isTopBarVisible ? 'premium-top-bar--hidden' : ''}`} data-tauri-drag-region>
      <div className="premium-top-bar-content">
        <div className="premium-top-bar-left max-w-[60%] flex-1">
          <button
            onClick={onClose}
            className="premium-control-button shrink-0"
            aria-label="Back to library"
            title="Back to library"
          >
            <ArrowLeft className="premium-control-icon" />
          </button>
          <div className="flex flex-col min-w-0 overflow-hidden text-left">
            <span className="premium-book-title truncate block w-full">{title}</span>
            <span className="premium-chapter-indicator truncate block w-full">{subtitle}</span>
          </div>
        </div>

        <div className="premium-top-bar-center !hidden md:!flex">
          <div className="premium-reading-time" title="Reading time">
            <Clock />
            <span>{formattedTime}</span>
          </div>
          <div className="premium-top-bar-separator" />
          <span className="premium-progress-text">{Math.round(progress)}%</span>
          {centerExtra}
        </div>

        <div className="premium-top-bar-right">
          <div className="md:hidden flex items-center relative">
            <button
              className={`premium-control-button ${isMoreMenuOpen ? 'premium-control-button--active' : ''}`}
              aria-label="More options"
              title="More options"
              onClick={() => setIsMoreMenuOpen(!isMoreMenuOpen)}
            >
              <MoreVertical className="premium-control-icon" />
            </button>

            {isMoreMenuOpen && (
              <>
                <div 
                  className="fixed inset-0 z-[95]" 
                  onClick={() => setIsMoreMenuOpen(false)} 
                />
                <div className="absolute top-full right-0 mt-2 w-56 flex flex-col p-2 bg-[var(--bg-elevated)] border-[var(--ui-border)] shadow-lg rounded-[var(--radius-lg)] z-[100]">
                  <div className="w-full flex flex-wrap gap-2 pb-2" onClick={() => setIsMoreMenuOpen(false)}>
                    {rightExtra}
                    <button
                      onClick={toggleFullscreen}
                      className="premium-control-button premium-fullscreen-button"
                      aria-label={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
                      title={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
                    >
                      {isFullscreen ? (
                        <Minimize2 className="premium-control-icon" />
                      ) : (
                        <Maximize2 className="premium-control-icon" />
                      )}
                    </button>
                  </div>
                  <div className="w-full border-t border-[var(--ui-border)] pt-2 flex flex-wrap gap-2">
                    <ReaderSettings format={format} />
                  </div>
                </div>
              </>
            )}
          </div>

          <div className="hidden md:flex items-center gap-2">
            {rightExtra}
            <ReaderSettings format={format} />
            <button
              onClick={toggleFullscreen}
              className="premium-control-button premium-fullscreen-button"
              aria-label={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
              title={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
            >
              {isFullscreen ? (
                <Minimize2 className="premium-control-icon" />
              ) : (
                <Maximize2 className="premium-control-icon" />
              )}
            </button>
            <div className="ml-2 pl-2 border-l border-[var(--ui-divider)] h-6 flex items-center">
              <WindowControls />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useLayoutEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Highlighter, StickyNote, Bookmark, X, Volume2 } from '@/components/icons';
import { api, isAndroid } from '@/lib/tauri';
import type { AnnotationCategory, DictionaryResponse, TranslationResponse } from '@/lib/tauri';
import { logger } from '@/lib/logger';
import { useToastStore } from '@/store/toastStore';
import { usePreferencesStore } from '@/store/preferencesStore';
import { ttsEngine, TTSEngine } from '@/lib/ttsEngine';
import { TranslationPopup } from './TranslationPopup';

interface TextSelectionToolbarProps {
  bookId: number;
  /** Current reading location string (e.g. "chapter_3:scroll_0.5") for annotation storage */
  currentLocation: string;
}

interface ToolbarPosition {
  x: number;
  y: number;
}

const HIGHLIGHT_COLORS = [
  { name: 'Yellow', value: '#fbbf24' },
  { name: 'Green', value: '#34d399' },
  { name: 'Blue', value: '#60a5fa' },
  { name: 'Pink', value: '#f472b6' },
  { name: 'Purple', value: '#a78bfa' },
  { name: 'Orange', value: '#fb923c' },
  { name: 'Red', value: '#f87171' },
  { name: 'Teal', value: '#2dd4bf' },
];

/**
 * Floating toolbar that appears when the user selects text inside the reader.
 * Provides: Copy, Highlight, Add Note, Bookmark actions.
 */
export function TextSelectionToolbar({ bookId, currentLocation }: TextSelectionToolbarProps) {
  const [isVisible, setIsVisible] = useState(false);
  const [position, setPosition] = useState<ToolbarPosition>({ x: 0, y: 0 });
  const [selectedText, setSelectedText] = useState('');
  const [showColorPicker, setShowColorPicker] = useState(false);
  const [showNoteInput, setShowNoteInput] = useState(false);
  const [noteText, setNoteText] = useState('');
  const [selectedCategoryId, setSelectedCategoryId] = useState<number | undefined>(undefined);
  const [categories, setCategories] = useState<AnnotationCategory[]>([]);
  const [showTranslation, setShowTranslation] = useState(false);
  const [translationMode, setTranslationMode] = useState<'translate' | 'define'>('translate');
  const [translationLoading, setTranslationLoading] = useState(false);
  const [dictionaryResult, setDictionaryResult] = useState<DictionaryResponse | null>(null);
  const [translationResult, setTranslationResult] = useState<TranslationResponse | null>(null);
  const [translationError, setTranslationError] = useState<string | null>(null);
  const toolbarRef = useRef<HTMLDivElement>(null);
  const noteInputRef = useRef<HTMLTextAreaElement>(null);

  const hideToolbar = useCallback(() => {
    setIsVisible(false);
    setShowColorPicker(false);
    setShowNoteInput(false);
    setNoteText('');
    setSelectedCategoryId(undefined);
    setShowTranslation(false);
    setDictionaryResult(null);
    setTranslationResult(null);
    setTranslationError(null);
  }, []);

  // Prevent native context menu from overriding custom toolbar, especially on Android WebViews
  useEffect(() => {
    const preventNativeContextMenu = (e: MouseEvent) => {
      // Only prevent if we have a selection (so regular long-presses for other things might still work if needed, though typically we want it off while reading)
      const selection = window.getSelection();
      if (selection && !selection.isCollapsed) {
        e.preventDefault();
      }
    };

    // Some Android devices need it on the document level, capturing phase helps ensure it runs first
    document.addEventListener('contextmenu', preventNativeContextMenu, { capture: true });
    return () => document.removeEventListener('contextmenu', preventNativeContextMenu, { capture: true });
  }, []);

  // Listen for text selection changes
  useEffect(() => {
    const handleSelectionChange = () => {
      const selection = window.getSelection();

      // If selection is happening inside the toolbar itself, don't hide it
      if (selection && selection.anchorNode && toolbarRef.current?.contains(selection.anchorNode)) {
        return;
      }

      if (!selection || selection.isCollapsed || !selection.toString().trim()) {
        // Delay hiding to allow clicking toolbar buttons
        setTimeout(() => {
          const active = document.activeElement;
          if (toolbarRef.current && toolbarRef.current.contains(active)) return;

          // Re-check if we have an active selection inside the toolbar before hiding
          const currentSelection = window.getSelection();
          if (currentSelection && currentSelection.anchorNode && toolbarRef.current?.contains(currentSelection.anchorNode)) {
            return;
          }

          if (!currentSelection?.toString().trim()) {
            hideToolbar();
          }
        }, 200);
        return;
      }

      const text = selection.toString().trim();
      if (!text) return;

      setSelectedText(text);

      // Calculate position above the selection
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      // Position the toolbar centered above the selection
      const toolbarWidth = toolbarRef.current?.offsetWidth || 550;
      let x = rect.left + rect.width / 2 - toolbarWidth / 2;
      const y = rect.top - 50;

      // Keep within viewport
      x = Math.max(8, Math.min(x, window.innerWidth - toolbarWidth - 8));

      setPosition({ x, y: Math.max(8, y) });
      setIsVisible(true);
    };

    document.addEventListener('selectionchange', handleSelectionChange);
    return () => document.removeEventListener('selectionchange', handleSelectionChange);
  }, [hideToolbar]);

  // Ensure toolbar stays within bounds after it mounts and its true size is known
  useLayoutEffect(() => {
    if (isVisible && toolbarRef.current) {
      const actualWidth = toolbarRef.current.offsetWidth;
      const actualHeight = toolbarRef.current.offsetHeight;

      let newX = position.x;
      let newY = position.y;

      if (position.x + actualWidth + 8 > window.innerWidth) {
        newX = Math.max(8, window.innerWidth - actualWidth - 8);
      }

      if (position.y + actualHeight + 8 > window.innerHeight) {
        newY = Math.max(8, window.innerHeight - actualHeight - 8);
      }

      if (newX !== position.x || newY !== position.y) {
        setPosition({ x: newX, y: newY });
      }
    }
  }, [isVisible, position.x, position.y, showNoteInput, showTranslation]);

  // Focus note input when shown
  useEffect(() => {
    if (showNoteInput && noteInputRef.current) {
      noteInputRef.current.focus();
    }
    if (showNoteInput && categories.length === 0) {
      api.getAnnotationCategories().then(setCategories).catch(logger.error);
    }
  }, [showNoteInput, categories.length]);

  const handleCopy = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(selectedText);
      useToastStore.getState().addToast({
        title: 'Copied to clipboard',
        variant: 'success',
        duration: 2000,
      });
    } catch {
      useToastStore.getState().addToast({
        title: 'Failed to copy',
        variant: 'error',
        duration: 2000,
      });
    }
    hideToolbar();
    window.getSelection()?.removeAllRanges();
  }, [selectedText, hideToolbar]);

  const handleHighlight = useCallback(async (color: string) => {
    try {
      await api.createAnnotation(
        bookId,
        'highlight',
        currentLocation,
        undefined,
        selectedText,
        undefined,
        color
      );
      useToastStore.getState().addToast({
        title: 'Highlight saved',
        variant: 'success',
        duration: 2000,
      });
      // Notify readers to re-render highlights
      window.dispatchEvent(new CustomEvent('annotation-changed'));
    } catch (err) {
      useToastStore.getState().addToast({
        title: 'Failed to save highlight',
        description: String(err),
        variant: 'error',
      });
    }
    hideToolbar();
    window.getSelection()?.removeAllRanges();
  }, [bookId, currentLocation, selectedText, hideToolbar]);

  const handleAddNote = useCallback(async () => {
    try {
      await api.createAnnotation(
        bookId,
        'note',
        currentLocation,
        undefined,
        selectedText,
        noteText.trim() || undefined,
        '#fbbf24',
        selectedCategoryId
      );
      useToastStore.getState().addToast({
        title: 'Note saved',
        variant: 'success',
        duration: 2000,
      });
      window.dispatchEvent(new CustomEvent('annotation-changed'));
    } catch (err) {
      useToastStore.getState().addToast({
        title: 'Failed to save note',
        description: String(err),
        variant: 'error',
      });
    }
    hideToolbar();
    window.getSelection()?.removeAllRanges();
  }, [bookId, currentLocation, selectedText, noteText, selectedCategoryId, hideToolbar]);



  const handleSpeak = useCallback(() => {
    if (!TTSEngine.isAvailable()) {
      useToastStore.getState().addToast({
        title: 'Text-to-Speech not available',
        description: 'Your platform does not support speech synthesis',
        variant: 'error',
        duration: 3000,
      });
      return;
    }
    ttsEngine.speak(selectedText, { rate: 1.0 });
    hideToolbar();
    window.getSelection()?.removeAllRanges();
  }, [selectedText, hideToolbar]);

  const handleTranslate = useCallback(async () => {
    setShowTranslation(true);
    setTranslationMode('translate');
    setTranslationLoading(true);
    setTranslationError(null);
    setDictionaryResult(null);
    setTranslationResult(null);
    try {
      const targetLang = usePreferencesStore.getState().preferences?.translationTargetLanguage ?? 'en';
      const result = await api.translateText(selectedText, targetLang);
      setTranslationResult(result);
    } catch (err: any) {
      setTranslationError(
        typeof err === 'object' && err !== null && 'userMessage' in err
          ? String(err.userMessage)
          : String(err)
      );
    } finally {
      setTranslationLoading(false);
    }
  }, [selectedText]);

  const handleDefine = useCallback(async () => {
    setShowTranslation(true);
    setTranslationMode('define');
    setTranslationLoading(true);
    setTranslationError(null);
    setDictionaryResult(null);
    setTranslationResult(null);
    try {
      const cleanText = selectedText.replace(/[[\](){}0-9]/g, '').trim();
      const word = cleanText.split(/\s+/).find(w => /^[a-zA-Z\u00C0-\u024F]+$/.test(w)) || cleanText.split(/\s+/)[0] || '';
      if (!word || word.length < 2) {
          setTranslationError('Please select a valid word to define');
          setTranslationLoading(false);
          return;
      }
      const result = await api.dictionaryLookup(word);
      setDictionaryResult(result);
    } catch (err: any) {
      setTranslationError(
        typeof err === 'object' && err !== null && 'userMessage' in err
          ? String(err.userMessage)
          : String(err)
      );
    } finally {
      setTranslationLoading(false);
    }
  }, [selectedText]);

  const handleAddVocabulary = useCallback(async () => {
    try {
      let currentCategories = categories;

      // If categories haven't been loaded yet, fetch them now
      if (currentCategories.length === 0) {
        currentCategories = await api.getAnnotationCategories();
        setCategories(currentCategories);
      }

      // Find or create Vocabulary category
      let vocabCategory = currentCategories.find(c => c.name.toLowerCase() === 'vocabulary');
      if (!vocabCategory) {
        try {
          vocabCategory = await api.createAnnotationCategory('Vocabulary', '#8b5cf6', 'BookmarkPlus');
          setCategories(prev => [...prev, vocabCategory!]);
        } catch (catErr: any) {
          // If creation fails due to unique constraint, try fetching again
          if (String(catErr?.userMessage || catErr).includes('UNIQUE constraint')) {
            currentCategories = await api.getAnnotationCategories();
            setCategories(currentCategories);
            vocabCategory = currentCategories.find(c => c.name.toLowerCase() === 'vocabulary');
          }

          if (!vocabCategory) throw catErr;
        }
      }

      const vocabData = translationMode === 'define' && dictionaryResult
        ? JSON.stringify({ type: 'define', data: dictionaryResult })
        : JSON.stringify({ type: 'translate', data: translationResult });

      await api.createAnnotation(
        bookId,
        'note', // Use note type to comply with DB constraints
        currentLocation,
        undefined,
        selectedText,
        vocabData,
        '#8b5cf6', // Purple color for vocabulary
        vocabCategory.id
      );
      useToastStore.getState().addToast({
        title: 'Added to vocabulary',
        variant: 'success',
        duration: 2000,
      });
      window.dispatchEvent(new CustomEvent('annotation-changed'));
    } catch (err) {
      console.error('Failed to add vocabulary annotation:', err);
      useToastStore.getState().addToast({
        title: 'Failed to add vocabulary',
        description: err && typeof err === 'object' ? JSON.stringify(err) : String(err),
        variant: 'error',
      });
    }
  }, [bookId, currentLocation, selectedText, translationMode, dictionaryResult, translationResult]);

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          ref={toolbarRef}
          className={`text-selection-toolbar ${isAndroid ? 'text-selection-toolbar--android' : ''}`}
          style={isAndroid ? undefined : { left: position.x, top: position.y }}
          initial={isAndroid ? { opacity: 0, y: 20 } : { opacity: 0, y: 10, scale: 0.95 }}
          animate={isAndroid ? { opacity: 1, y: 0 } : { opacity: 1, y: 0, scale: 1 }}
          exit={isAndroid ? { opacity: 0, y: 20 } : { opacity: 0, y: 8, scale: 0.95 }}
          transition={{ duration: 0.15 }}
          onMouseDown={(e) => e.stopPropagation()}
        >
          {/* Main action buttons */}
          {!showNoteInput && !showTranslation && (
            <div className="text-selection-toolbar-actions">
              {/* Copy */}
              <button
                className="text-selection-toolbar-btn"
                onClick={handleCopy}
                title="Copy text"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
                  <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
                </svg>
                <span>Copy</span>
              </button>

              {/* Highlight */}
              <button
                className="text-selection-toolbar-btn"
                onClick={() => setShowColorPicker(!showColorPicker)}
                title="Highlight text"
              >
                <Highlighter size={14} />
                <span>Highlight</span>
              </button>

              {/* Note */}
              <button
                className="text-selection-toolbar-btn"
                onClick={() => setShowNoteInput(true)}
                title="Add a note"
              >
                <StickyNote size={14} />
                <span>Note</span>
              </button>




              <button
                className="text-selection-toolbar-btn"
                onClick={handleTranslate}
                title="Translate selected text"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="m5 8 6 6" /><path d="m4 14 6-6 2-3" /><path d="M2 5h12" /><path d="M7 2h1" /><path d="m22 22-5-10-5 10" /><path d="M14 18h6" />
                </svg>
                <span>Translate</span>
              </button>

              <button
                className="text-selection-toolbar-btn"
                onClick={handleDefine}
                title="Look up definition"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1 0-5H20" />
                </svg>
                <span>Define</span>
              </button>
            </div>
          )}

          {/* Color picker for highlight */}
          {showColorPicker && !showNoteInput && !showTranslation && (
            <motion.div
              className="text-selection-toolbar-colors"
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
            >
              {HIGHLIGHT_COLORS.map((c) => (
                <button
                  key={c.value}
                  className="text-selection-color-swatch"
                  style={{ backgroundColor: c.value }}
                  onClick={() => handleHighlight(c.value)}
                  title={c.name}
                />
              ))}
            </motion.div>
          )}

          {/* Note input */}
          {showNoteInput && (
            <motion.div
              className="text-selection-toolbar-note"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
            >
              <textarea
                ref={noteInputRef}
                className="text-selection-note-input"
                placeholder="Add a note..."
                value={noteText}
                onChange={(e) => setNoteText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleAddNote();
                  }
                  if (e.key === 'Escape') {
                    setShowNoteInput(false);
                    setNoteText('');
                  }
                }}
                rows={3}
              />
              {categories.length > 0 && (
                <select
                  className="text-selection-category-select"
                  value={selectedCategoryId ?? ''}
                  onChange={(e) => setSelectedCategoryId(e.target.value ? Number(e.target.value) : undefined)}
                  onClick={(e) => e.stopPropagation()}
                >
                  <option value="">No category</option>
                  {categories.map((c) => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
              )}
              <div className="text-selection-note-actions">
                <button
                  className="text-selection-toolbar-btn text-selection-toolbar-btn--cancel"
                  onClick={() => { setShowNoteInput(false); setNoteText(''); }}
                >
                  <X size={12} />
                  <span>Cancel</span>
                </button>
                <button
                  className="text-selection-toolbar-btn text-selection-toolbar-btn--save"
                  onClick={handleAddNote}
                >
                  <span>Save</span>
                </button>
              </div>
            </motion.div>
          )}

          {showTranslation && (
            <TranslationPopup
              mode={translationMode}
              loading={translationLoading}
              dictionaryResult={dictionaryResult}
              translationResult={translationResult}
              error={translationError}
              onClose={() => setShowTranslation(false)}
              onAddVocabulary={handleAddVocabulary}
              onSwitchMode={(mode) => {
                if (mode === 'define') handleDefine();
                else handleTranslate();
              }}
            />
          )}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

