                  type="range"
                  min="75"
                  max="150"
                  step="5"
                  value={scalePercent}
                  onChange={(e) => updateGeneralSettings({ uiScale: Number(e.target.value) / 100 })}
                  className="flex-1 md:w-40"
                  aria-label="UI scale"
                />
                <span className="text-xs text-muted-foreground w-10 shrink-0">150%</span>
              </div>
