import { Switch } from '@/components/ui/switch'
import { useState, useEffect, useCallback } from 'react';
import { api, isTauri } from '@/lib/tauri';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useToast } from '@/store/toastStore';
import { logger } from '@/lib/logger';
import { CheckCircle2, AlertCircle, Eye, EyeOff } from 'lucide-react';

export function TorboxSettings() {
  const [apiKey, setApiKey] = useState<string>('');
  const [savedApiKey, setSavedApiKey] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isTesting, setIsTesting] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [testResult, setTestResult] = useState<{ success: boolean; message: string } | null>(null);
  const toast = useToast();

  const loadApiKey = useCallback(async () => {
    if (!isTauri) return;

    try {
      const key = await api.getTorboxKey();
      setSavedApiKey(key);
      if (key) {
        setApiKey(key);
      }
    } catch (err) {
      logger.error('Failed to load Torbox API key:', err);
    }
  }, []);

  useEffect(() => {
    loadApiKey();
  }, [loadApiKey]);

  const handleSave = async () => {
    if (!isTauri) {
      toast.warning('Torbox settings only work in Tauri environment');
      return;
    }

    try {
      setIsLoading(true);
      setTestResult(null);

      const keyToSave = apiKey.trim();
      await api.saveTorboxKey(keyToSave);
      setSavedApiKey(keyToSave || null);

      if (keyToSave) {
        toast.success('Torbox API key saved successfully');
      } else {
        toast.success('Torbox API key removed');
      }
    } catch (err) {
      logger.error('Failed to save Torbox API key:', err);
      toast.error('Failed to save API key');
    } finally {
      setIsLoading(false);
    }
  };

  const handleTest = async () => {
    if (!isTauri) {
      toast.warning('Torbox settings only work in Tauri environment');
      return;
    }

    if (!apiKey.trim()) {
      setTestResult({ success: false, message: 'Please enter an API key first' });
      return;
    }

    try {
      setIsTesting(true);
      setTestResult(null);

      const verify = await api.verifyTorboxKey(apiKey.trim());
      setSavedApiKey(apiKey.trim());
      setTestResult({ 
        success: verify.valid,
        message: verify.message,
      });
      toast.success('API key verified and configured');
    } catch (err) {
      logger.error('Failed to test Torbox API key:', err);
      setTestResult({ 
        success: false, 
        message: err instanceof Error ? err.message : 'Failed to connect to Torbox' 
      });
    } finally {
      setIsTesting(false);
    }
  };

  const handleClear = async () => {
    if (!isTauri) return;

    try {
      setIsLoading(true);
      await api.saveTorboxKey('');
      setApiKey('');
      setSavedApiKey(null);
      setTestResult(null);
      toast.success('Torbox API key cleared');
    } catch (err) {
      logger.error('Failed to clear Torbox API key:', err);
      toast.error('Failed to clear API key');
    } finally {
      setIsLoading(false);
    }
  };

  const hasChanges = apiKey !== (savedApiKey || '');

  return (
    <div className="space-y-4">
      <div>
        <p className="text-sm text-muted-foreground mb-2">
          Torbox is a cloud torrent service that allows you to download torrents and import them directly into Shiori.
        </p>
        <a
          href="https://torbox.app"
          target="_blank"
          rel="noopener noreferrer"
          className="text-xs text-primary hover:underline inline-flex items-center gap-1"
        >
          Get your API key from Torbox.app →
        </a>
      </div>

      <div className="space-y-3">
        <div>
          <label htmlFor="torbox-api-key" className="text-sm font-medium mb-2 block">API Key</label>
          <div className="flex gap-2">
            <div className="flex-1 relative">
              <Input
                id="torbox-api-key"
                type={showApiKey ? 'text' : 'password'}
                value={apiKey}
                onChange={(e) => setApiKey(e.target.value)}
                placeholder="Enter your Torbox API key"
                className="font-mono text-sm pr-10"
                disabled={isLoading || isTesting}
              />
              <button
                type="button"
                onClick={() => setShowApiKey(!showApiKey)}
                className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                aria-label={showApiKey ? 'Hide API key' : 'Show API key'}
              >
                {showApiKey ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
          <Button
            variant="default"
            onClick={handleSave}
            disabled={isLoading || isTesting || !hasChanges}
            className="gap-2"
          >
            {isLoading ? 'Saving...' : 'Save'}
          </Button>
          <Button
            variant="outline"
            onClick={handleTest}
            disabled={isLoading || isTesting || !apiKey.trim()}
            className="gap-2"
          >
            {isTesting ? 'Testing...' : 'Test Connection'}
          </Button>
          {savedApiKey && (
            <Button
              variant="destructive"
              onClick={handleClear}
              disabled={isLoading || isTesting}
            >
              Clear
            </Button>
          )}
        </div>

        {testResult && (
          <div
            className={`p-3 rounded-lg border flex items-start gap-2 ${
              testResult.success
                ? 'bg-green-500/10 border-green-500/30'
                : 'bg-red-500/10 border-red-500/30'
            }`}
          >
            {testResult.success ? (
              <CheckCircle2 className="w-4 h-4 text-green-600 dark:text-green-400 mt-0.5 shrink-0" />
            ) : (
              <AlertCircle className="w-4 h-4 text-red-600 dark:text-red-400 mt-0.5 shrink-0" />
            )}
            <p
              className={`text-sm ${
                testResult.success
                  ? 'text-green-700 dark:text-green-300'
                  : 'text-red-700 dark:text-red-300'
              }`}
            >
              {testResult.message}
            </p>
          </div>
        )}

        {savedApiKey && !testResult && (
          <div className="p-3 rounded-lg bg-blue-500/10 border border-blue-500/30">
            <p className="text-xs text-blue-700 dark:text-blue-300">
              API key is configured. You can now use Torbox for downloading torrents in the online manga/books section.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { api, isTauri } from '@/lib/tauri';
import type { DailyReadingStats, ReadingStreak, ReadingGoal } from '@/lib/tauri';
import { Loader2, X, RotateCw, BarChart2, CalendarDays, Flame, Trophy, Clock } from 'lucide-react';
import { cn } from '@/lib/utils';
import { ActivityHeatmap } from './ActivityHeatmap';
import { ReadingCalendar } from './ReadingCalendar';
import { Button } from '../ui/button';

interface StatisticsViewProps {
  onClose: () => void;
}

export function StatisticsView({ onClose }: StatisticsViewProps) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [yearlyStats, setYearlyStats] = useState<DailyReadingStats[]>([]);
  const [streak, setStreak] = useState<ReadingStreak | null>(null);
  const [goal, setGoal] = useState<ReadingGoal | null>(null);
  const [todaySeconds, setTodaySeconds] = useState(0);

  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      if (!isTauri) {
        const dummyStats = [
          { date: '2023-10-01', total_seconds: 1200, books_count: 1, sessions_count: 1 },
          { date: '2023-10-02', total_seconds: 2400, books_count: 1, sessions_count: 2 },
          { date: '2023-10-03', total_seconds: 0, books_count: 0, sessions_count: 0 },
          { date: '2023-10-04', total_seconds: 3600, books_count: 2, sessions_count: 3 },
          { date: '2023-10-05', total_seconds: 1800, books_count: 1, sessions_count: 1 },
          { date: '2023-10-06', total_seconds: 4200, books_count: 1, sessions_count: 4 },
          { date: '2023-10-07', total_seconds: 900, books_count: 1, sessions_count: 1 },
        ];
        setYearlyStats(dummyStats);
        setStreak({ current_streak: 4, longest_streak: 12, total_reading_days: 45 });
        setGoal({ daily_minutes_target: 30, is_active: true, created_at: '', updated_at: '' });
        setTodaySeconds(900);
        setLoading(false);
        return;
      }

      const [stats, currentStreak, currentGoal, todayTime] = await Promise.all([
        api.getDailyReadingStats(365),
        api.getReadingStreak(),
        api.getReadingGoal(),
        api.getTodayReadingTime()
      ]);

      setYearlyStats(stats);
      setStreak(currentStreak);
      setGoal(currentGoal);
      setTodaySeconds(todayTime);
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const formatHoursMinutes = (totalSeconds: number) => {
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
  };

  return (
    <div className="flex flex-col h-full bg-background text-foreground overflow-hidden">
      {/* Sticky Header matching the dialog vibe */}
      <div className="flex-none sticky top-0 z-10 bg-muted/20 border-b border-border backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between p-6">
          <div className="flex items-center gap-4">
            <div className="flex items-center justify-center w-12 h-12 rounded-xl bg-primary/10 shadow-sm border border-primary/20">
              <BarChart2 className="w-6 h-6 text-primary" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-foreground">Reading Statistics</h1>
              <p className="text-sm text-muted-foreground mt-0.5">
                Track your reading progress and habits
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="icon"
              onClick={loadData}
              disabled={loading}
              title="Refresh statistics"
              className="bg-background"
            >
              <RotateCw size={18} className={cn(loading && "animate-spin")} />
            </Button>
            <Button
              variant="outline"
              size="icon"
              onClick={onClose}
              title="Close statistics"
              className="bg-background"
            >
              <X size={18} />
            </Button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-6 bg-background">
        <div className="max-w-6xl mx-auto space-y-6 pb-20">
          {error ? (
            <div className="flex flex-col items-center justify-center py-20 bg-card rounded-xl border border-destructive/50 p-6 shadow-sm">
              <p className="text-destructive mb-4 font-medium">{error}</p>
              <Button onClick={loadData} variant="destructive">
                Retry
              </Button>
            </div>
          ) : loading ? (
            <div className="flex items-center justify-center py-32 text-muted-foreground">
              <div className="flex flex-col items-center gap-3">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
                <p className="text-sm font-medium">Loading statistics...</p>
              </div>
            </div>
          ) : (
            <>
              {/* Stat Cards */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-card/50 hover:bg-card border border-border rounded-xl p-5 transition-colors shadow-sm relative overflow-hidden group">
                  <div className="flex items-center justify-between mb-4">
                    <p className="text-sm font-medium text-muted-foreground group-hover:text-foreground transition-colors">Today's Reading</p>
                    <Clock className="w-4 h-4 text-muted-foreground group-hover:text-primary transition-colors" />
                  </div>
                  <p className="text-3xl font-bold text-foreground tracking-tight">
                    {formatHoursMinutes(todaySeconds)}
                  </p>
                </div>

                <div className="bg-card border-2 border-primary/20 rounded-xl p-5 shadow-md relative overflow-hidden group">
                  <div className="absolute -right-6 -top-6 w-24 h-24 bg-primary/10 rounded-full blur-2xl pointer-events-none group-hover:bg-primary/20 transition-colors" />
                  <div className="flex items-center justify-between mb-4 relative z-10">
                    <p className="text-sm font-medium text-foreground">Current Streak</p>
                    <Flame className="w-4 h-4 text-primary animate-pulse" />
                  </div>
                  <div className="flex items-baseline gap-1.5 relative z-10">
