import { useCallback, useState, useEffect } from 'react';
import { useReaderStore } from '@/store/readerStore';
import { useLibraryStore } from '@/store/libraryStore';
import { useToastStore } from '@/store/toastStore';
import { useBookOpen } from '@/hooks/useBookOpen';
import { api, type Book } from '@/lib/tauri';
import { logger } from '@/lib/logger';

/**
 * Encapsulates all book-level action handlers that were inlined in App.tsx:
 * open, close, edit, delete, download, convert, view details, etc.
 *
 * Now uses `useBookOpen` for automatic EPUB conversion on open.
 */
export function useBookActions(books: Book[]) {
  const closeBook = useReaderStore(state => state.closeBook);
  const loadInitialBooks = useLibraryStore(state => state.loadInitialBooks);
  const [selectedBookId, setSelectedBookId] = useState<number | null>(null);

  // Use the new auto-convert hook for book opening
  const bookOpen = useBookOpen();

  const handleOpenBook = useCallback(async (bookId: number) => {
    logger.debug('[App] Opening book:', bookId);
    const result = await bookOpen.handleOpenBook(bookId);
    if (result !== null) {
      setSelectedBookId(result);
    }
  }, [bookOpen.handleOpenBook]);

  // Listen for the custom 'open-book' event dispatched by other components
  useEffect(() => {
    const handler = (e: Event) => {
      const bookId = (e as CustomEvent<{ bookId: number }>).detail?.bookId;
      if (bookId) handleOpenBook(bookId);
    };
    window.addEventListener('open-book', handler);
    return () => window.removeEventListener('open-book', handler);
  }, [handleOpenBook]);

  const handleCloseReader = useCallback(() => {
    closeBook();
    setSelectedBookId(null);
  }, [closeBook]);

  const handleDownloadBook = useCallback((bookId: number) => {
    const book = books.find(b => b.id === bookId);
    if (book) {
      navigator.clipboard.writeText(book.file_path).then(
        () => {
          useToastStore.getState().addToast({
            title: 'File path copied',
            description: book.file_path,
            variant: 'info',
          });
        },
        () => {
          useToastStore.getState().addToast({
            title: 'Book file location',
            description: book.file_path,
            variant: 'info',
          });
        }
      );
    }
  }, [books]);

  const handleAutoGroupManga = useCallback(async () => {
    try {
      const count = await api.autoGroupMangaVolumes();
      if (count > 0) {
        useToastStore.getState().addToast({
          title: 'Auto-grouping complete',
          description: `Grouped ${count} manga volume${count > 1 ? 's' : ''} into series`,
          variant: 'success',
        });
        await loadInitialBooks();
      } else {
        useToastStore.getState().addToast({
          title: 'No volumes grouped',
          description: 'No manga volumes matched the auto-grouping pattern',
          variant: 'info',
        });
      }
    } catch (error) {
      logger.error('Auto-grouping failed:', error);
      useToastStore.getState().addToast({
        title: 'Auto-grouping failed',
        description: String(error),
        variant: 'error',
      });
    }
  }, [loadInitialBooks]);

  return {
    selectedBookId,
    handleOpenBook,
    handleCloseReader,
    handleDownloadBook,
    handleAutoGroupManga,
    // Expose auto-convert dialog state
    autoConvert: {
      showDialog: bookOpen.showConvertDialog,
      isConverting: bookOpen.isConverting,
      pendingBook: bookOpen.pendingBook,
      onConfirm: bookOpen.onConfirm,
      onDialogOpenChange: bookOpen.onDialogOpenChange,
    },
    // Expose resume-reading dialog state
    resumeReading: {
      showDialog: bookOpen.showResumeDialog,
      pendingResume: bookOpen.pendingResume,
      buildLocationLabel: bookOpen.buildLocationLabel,
      onResume: bookOpen.handleResume,
      onStartOver: bookOpen.handleStartOver,
      onDialogOpenChange: bookOpen.handleResumeDialogOpenChange,
    },
  };

}

import { useEffect, useState, useCallback, useRef } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { usePreferencesStore } from '../store/preferencesStore';
import { logger } from '../lib/logger';

interface ActivityProps {
  details?: string;
  state?: string;
  largeImageKey?: string;
  largeImageText?: string;
  smallImageKey?: string;
  smallImageText?: string;
}

const MAX_RETRY_ATTEMPTS = 5;
const RETRY_BASE_DELAY_MS = 3000;

export function useDiscordPresence() {
  const preferences = usePreferencesStore(state => state.preferences);
  const isEnabled = preferences?.discordRpcEnabled ?? true;
  const [isConnected, setIsConnected] = useState(false);
  const connectingRef = useRef(false);
  const retryCountRef = useRef(0);
  const retryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const mountedRef = useRef(true);

  // Connect or disconnect based on preference, with retry logic
  useEffect(() => {
    mountedRef.current = true;

    function clearRetryTimer() {
      if (retryTimerRef.current !== null) {
        clearTimeout(retryTimerRef.current);
        retryTimerRef.current = null;
      }
    }

    async function attemptConnect() {
      if (!mountedRef.current || connectingRef.current) return;

      connectingRef.current = true;
      try {
        await invoke('discord_connect');
        if (mountedRef.current) {
          setIsConnected(true);
          retryCountRef.current = 0;
          logger.info('Connected to Discord RPC');
        }
      } catch (e: any) {
        const errorMessage = typeof e === 'string' ? e : (e.message || JSON.stringify(e));
        if (errorMessage.includes('IPC socket') || errorMessage.includes('failed to find IPC socket')) {
          logger.debug('Discord RPC: Discord not running (no IPC socket found).');
          connectingRef.current = false;
          return;
        }

        logger.error('Failed to connect to Discord RPC:', e);
        if (mountedRef.current && retryCountRef.current < MAX_RETRY_ATTEMPTS) {
          retryCountRef.current += 1;
          const delay = RETRY_BASE_DELAY_MS * Math.pow(2, retryCountRef.current - 1);
          logger.info(`Discord RPC: retrying connection in ${delay}ms (attempt ${retryCountRef.current}/${MAX_RETRY_ATTEMPTS})`);
          retryTimerRef.current = setTimeout(() => {
            if (mountedRef.current) {
              attemptConnect();
            }
          }, delay);
        } else if (mountedRef.current) {
          logger.warn(`Discord RPC: giving up after ${MAX_RETRY_ATTEMPTS} attempts`);
        }
      } finally {
        connectingRef.current = false;
      }
    }

    async function toggleConnection() {
      if (!isEnabled) {
        clearRetryTimer();
        retryCountRef.current = 0;
        if (isConnected) {
          try {
            await invoke('discord_disconnect');
            if (mountedRef.current) {
              setIsConnected(false);
              logger.info('Disconnected from Discord RPC');
            }
          } catch (e) {
            logger.error('Failed to disconnect from Discord RPC:', e);
          }
        }
        return;
      }

      if (!isConnected) {
        attemptConnect();
      }
    }

    toggleConnection();

    return () => {
      mountedRef.current = false;
      clearRetryTimer();
    };
  }, [isEnabled, isConnected]);

  const setActivity = useCallback(async (activity: ActivityProps) => {
    if (!isEnabled || !isConnected) return;
    try {
      await invoke('discord_set_activity', { presence: activity });
    } catch (e) {
      logger.error('Failed to set Discord activity:', e);
      // If setting activity fails, the connection may be stale — reset so we reconnect
      setIsConnected(false);
    }
  }, [isEnabled, isConnected]);

  const clearActivity = useCallback(async () => {
    if (!isEnabled || !isConnected) return;
    try {
      await invoke('discord_clear_activity');
    } catch (e) {
      logger.error('Failed to clear Discord activity:', e);
      setIsConnected(false);
    }
  }, [isEnabled, isConnected]);

  return { setActivity, clearActivity, isConnected };
}

/**
 * useFullscreen — shared hook for toggling OS-level fullscreen.
 *
 * Desktop (Tauri): Uses the Rust `toggle_fullscreen` IPC command which calls
 * `set_always_on_top(true)` BEFORE `set_fullscreen(true)` so that on Windows
 * the window is promoted above the HWND_TOPMOST taskbar.
 *
 * Mobile / Browser: Falls back to the standard browser Fullscreen API
 * (`document.documentElement.requestFullscreen`) with vendor-prefix support
 * for older iOS WebKit.
 */
import { useState, useEffect, useCallback } from 'react'
import { invoke } from '@tauri-apps/api/core'
import { getCurrentWindow } from '@tauri-apps/api/window'

declare global {
  interface Window {
    __TAURI_INTERNALS__?: unknown
  }
  interface Document {
    webkitFullscreenElement?: Element | null
    webkitExitFullscreen?: () => Promise<void>
  }
  interface HTMLElement {
    webkitRequestFullscreen?: () => Promise<void>
  }
}

/** True when the browser Fullscreen API is available (not Tauri). */
function browserFullscreenAvailable() {
  return !window.__TAURI_INTERNALS__ && (
    document.documentElement.requestFullscreen !== undefined ||
    document.documentElement.webkitRequestFullscreen !== undefined
  )
}

function isBrowserFullscreen() {
  return !!(document.fullscreenElement || document.webkitFullscreenElement)
}

export function useFullscreen() {
  const [isFullscreen, setIsFullscreen] = useState(false)

  // ── Tauri: sync state from OS window ──────────────────────────────────
  useEffect(() => {
    if (!window.__TAURI_INTERNALS__) return

    const appWindow = getCurrentWindow()
    let unlisten: (() => void) | undefined

    const sync = async () => {
      try {
        const full = await appWindow.isFullscreen()
        setIsFullscreen(full)
      } catch { /* ignore */ }
    }

    sync()

    appWindow.onResized(sync)
      .then(u => { unlisten = u })
      .catch(() => { /* ignore */ })

    return () => { unlisten?.() }
  }, [])

  // ── Browser: sync state from Fullscreen API events ─────────────────────
  useEffect(() => {
    if (!browserFullscreenAvailable()) return

    const onFSChange = () => setIsFullscreen(isBrowserFullscreen())
    document.addEventListener('fullscreenchange', onFSChange)
    document.addEventListener('webkitfullscreenchange', onFSChange)

    // Sync initial state
    setIsFullscreen(isBrowserFullscreen())

    return () => {
      document.removeEventListener('fullscreenchange', onFSChange)
      document.removeEventListener('webkitfullscreenchange', onFSChange)
    }
  }, [])

  const toggleFullscreen = useCallback(async () => {
    // ── Tauri path ──────────────────────────────────────────────────────
    if (window.__TAURI_INTERNALS__) {
      try {
        const nowFull = await invoke<boolean>('toggle_fullscreen')
        setIsFullscreen(nowFull)
      } catch (err) {
        console.error('toggle_fullscreen failed:', err)
      }
      return
    }

    // ── Browser / Mobile path ───────────────────────────────────────────
    if (!browserFullscreenAvailable()) return

    try {
      if (isBrowserFullscreen()) {
        if (document.exitFullscreen) {
          await document.exitFullscreen()
        } else if (document.webkitExitFullscreen) {
          await document.webkitExitFullscreen()
        }
        setIsFullscreen(false)
      } else {
        const el = document.documentElement
        if (el.requestFullscreen) {
          await el.requestFullscreen()
        } else if (el.webkitRequestFullscreen) {
          await el.webkitRequestFullscreen()
        }
        setIsFullscreen(true)
      }
    } catch (err) {
      console.error('browser fullscreen failed:', err)
    }
  }, [])

  return { isFullscreen, toggleFullscreen }
}

import { useState, useCallback } from 'react';
import { fetchLibgenBooks } from '@/online-books/libgen/api';
import { fetchGutenbergBooks } from '@/online-books/gutenberg/api';
import type { OnlineAdvancedFilters } from '@/store/onlineSearchStore';
import { fetchCoverForBook } from '@/online-books/openlibrary/api';

export interface UnifiedSearchResult {
  id: string; // The URL to download
  source: 'libgen' | 'gutenberg';
  title: string;
  author: string;
  coverUrl?: string;
  format?: string;
  year?: number;
  language?: string;
  downloadUrl: string;
  mirrors?: string[];
  size?: string;
  publisher?: string;
  extra?: Record<string, any>;
}

export function useGlobalSearch() {
  const [results, setResults] = useState<UnifiedSearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(true);

  const search = useCallback(async (query: string, page: number = 1, filters?: OnlineAdvancedFilters) => {
    setLoading(true);
    setError(null);

    try {
      let libgenQuery = query;
      if (!libgenQuery && filters) {
        if (filters.title) libgenQuery = filters.title;
        else if (filters.author) libgenQuery = filters.author;
        else if (filters.series) libgenQuery = filters.series;
      }

      // Execute both searches concurrently
      const [libgenRes, gutenbergRes] = await Promise.allSettled([
        fetchLibgenBooks(libgenQuery, page, 50),
        fetchGutenbergBooks(query, page, filters)
      ]);

      const unified: UnifiedSearchResult[] = [];

      // Process Gutenberg results
      if (gutenbergRes.status === 'fulfilled' && gutenbergRes.value.results) {
        gutenbergRes.value.results.forEach((book) => {
          const epubFormat = book.formats['application/epub+zip'];
          const downloadUrl = epubFormat || book.formats['application/x-mobipocket-ebook'];

          if (!downloadUrl) return; // Only show downloadable books

          unified.push({
            id: downloadUrl,
            source: 'gutenberg',
            title: book.title,
            author: book.authors.map(a => a.name).join(', '),
            coverUrl: book.formats['image/jpeg'],
            format: epubFormat ? 'epub' : 'mobi',
            language: book.languages[0],
            year: book.authors[0]?.birth_year || undefined,
            downloadUrl: downloadUrl,
          });
        });
      }

      // Process Libgen results
      if (libgenRes.status === 'fulfilled' && libgenRes.value.items) {
        libgenRes.value.items.forEach((book: any) => {
          unified.push({
            id: book.extra?.url || book.id,
            source: 'libgen',
            title: book.title,
            author: book.extra?.author || 'Unknown',
            coverUrl: book.coverUrl || book.cover_url,
            format: (book.extra?.format || '').toLowerCase(),
            year: book.extra?.year ? parseInt(book.extra.year) : undefined,
            language: book.extra?.language,
            size: book.extra?.file_size,
            downloadUrl: book.extra?.url || book.id,
            mirrors: [
              book.extra?.url,
              book.extra?.mirror_1,
              book.extra?.mirror_2,
              book.extra?.mirror_3,
              book.extra?.mirror_4,
            ].filter(Boolean) as string[],
            extra: book.extra,
          });
        });
      }

      // Apply Advanced Filters (since Libgen API doesn't support them natively, we filter frontend)
      let filtered = unified;
      if (filters) {
        if (filters.title) {
          filtered = filtered.filter(b => b.title.toLowerCase().includes(filters.title!.toLowerCase()));
        }
        if (filters.series) {
          // Series might be in title, e.g., "Harry Potter (Book 1)"
          filtered = filtered.filter(b => b.title.toLowerCase().includes(filters.series!.toLowerCase()));
        }
        if (filters.author) {
          filtered = filtered.filter(b => b.author?.toLowerCase().includes(filters.author!.toLowerCase()));
        }
        if (filters.publisher) {
          filtered = filtered.filter(b => b.publisher?.toLowerCase().includes(filters.publisher!.toLowerCase()));
        }
        if (filters.format && filters.format !== 'any') {
          filtered = filtered.filter(b => b.format?.toLowerCase() === filters.format);
        }
        if (filters.language) {
          filtered = filtered.filter(b => b.language?.toLowerCase().includes(filters.language!.toLowerCase()));
        }
        if (filters.yearStart) {
          filtered = filtered.filter(b => b.year && b.year >= filters.yearStart!);
        }
        if (filters.yearEnd) {
          filtered = filtered.filter(b => b.year && b.year <= filters.yearEnd!);
        }
      }

      // Sort or blend results (e.g., prioritize EPUBs)
      filtered.sort((a, b) => {
        if (a.format === 'epub' && b.format !== 'epub') return -1;
        if (a.format !== 'epub' && b.format === 'epub') return 1;
        return 0;
      });

      setHasMore(filtered.length > 0);
      setResults(prev => page === 1 ? filtered : [...prev, ...filtered]);
    } catch (err: any) {
      setError(err.message || 'An error occurred during search');
    } finally {
      setLoading(false);
    }
  }, []);

  const clear = useCallback(() => {
    setResults([]);
    setError(null);
    setHasMore(true);
  }, []);

  return { results, loading, error, hasMore, search, clear };
}

