  // File dialogs
  async openFileDialog(): Promise<string[] | null> {
    if (!isTauri) {
      logger.warn("File dialogs only work in Tauri environment. Please run: npm run tauri dev")
      return Promise.resolve(null)
    }

    if (isAndroid) {
      try {
        logger.debug('[API] Opening Android SAF file dialog')
        const result = await invoke<{uris: string[]}>("plugin:android-saf|select_files")
        return result.uris
      } catch (error) {
        logger.error('[API] SAF file selection error:', error)
        return null
      }
    }

    try {
      logger.debug('[API] Opening file dialog')
      const result = await open({
        multiple: true,
        filters: [
          {
            name: "eBooks",
            extensions: ["epub", "pdf", "mobi", "azw", "azw3", "txt", "cbz", "cbr", "fb2", "docx", "html", "htm", "md"],
          },
        ],
      }) as string[] | null
      logger.debug('[API] File dialog result:', result)
      return result
    } catch (error) {
      logger.error('[API] File dialog error:', error)
      throw error
    }
  },

