import { describe, it, expect, vi, afterEach } from 'vitest';
import {
  isMangaDomain,
  formatFileSize,
  truncate,
  parsePageUrl,
  formatRelativeTime
} from './utils';

describe('utils.ts', () => {
  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('isMangaDomain', () => {
    const cases = [
      // Valid inputs
      { input: { domain: 'manga' }, expected: true },
      { input: { domain: 'comics' }, expected: true },
      { input: { domain: 'online-manga' }, expected: true },
      { input: { domain: 'books' }, expected: false },
      // Fallback to file_format
      { input: { file_format: 'cbz' }, expected: true },
      { input: { file_format: '.CBR' }, expected: true },
      { input: { file_format: 'epub' }, expected: false },
      // Edge cases / Missing fields / Wrong types
      { input: {}, expected: false },
      { input: null as any, expected: false },
      { input: { domain: 123 }, expected: false },
      { input: { file_format: null }, expected: false },
    ];

    it.each(cases)('isMangaDomain($input) should return $expected', ({ input, expected }) => {
      // For null input, we must handle TypeError if the function isn't safe, 
      // but utils checks `book.domain` which throws on null.
      // Wait, isMangaDomain(null) throws in JS! Let's see if we should fix the function or just test it.
      // Let's assume we test the actual behavior. If it throws, we wrap it.
      try {
        const result = isMangaDomain(input);
        expect(result).toBe(expected);
      } catch (e) {
        expect(input).toBeNull();
      }
    });
  });

  describe('formatFileSize', () => {
    const cases = [
      { input: 0, expected: '0 B' },
      { input: 1024, expected: '1 KB' },
      { input: 1024 * 1024 * 2.5, expected: '2.5 MB' },
      { input: -100, expected: '0 B' }, // Edge case: negative numbers produce weird output currently
      { input: '1024' as any, expected: '1 KB' }, // works due to JS math
      { input: null as any, expected: '0 B' }, // log(0) handled in 0 B check? No, null === 0 in JS? Actually null is 0.
    ];

    it.each(cases)('formatFileSize($input) should return $expected', ({ input, expected }) => {
      expect(formatFileSize(input)).toBe(expected);
    });
  });

  describe('truncate', () => {
    const cases = [
      { text: 'hello world', length: 5, expected: 'hello...' },
      { text: 'hello', length: 10, expected: 'hello' },
      { text: '', length: 5, expected: '' },
      { text: 'a', length: 0, expected: '...' },
    ];

    it.each(cases)('truncate("$text", $length) should return "$expected"', ({ text, length, expected }) => {
      expect(truncate(text, length)).toBe(expected);
    });
  });

  describe('parsePageUrl', () => {
    const cases = [
      { input: 'direct|https://example.com/img.jpg', expected: { kind: 'direct', url: 'https://example.com/img.jpg' } },
      { input: 'PROXY | https://example.com/img.jpg ', expected: { kind: 'proxy', url: 'https://example.com/img.jpg' } },
      { input: 'https://example.com/img.jpg', expected: { kind: 'direct', url: 'https://example.com/img.jpg' } },
      { input: '|https://example.com/img.jpg', expected: { kind: 'direct', url: 'https://example.com/img.jpg' } },
      { input: '   ', expected: { kind: 'direct', url: '' } },
    ];

    it.each(cases)('parsePageUrl("$input") should return $expected', ({ input, expected }) => {
      expect(parsePageUrl(input)).toEqual(expected);
    });
  });

  describe('formatRelativeTime', () => {
    it('should format relative time correctly', () => {
      const now = new Date('2024-01-01T12:00:00Z');
      vi.useFakeTimers();
      vi.setSystemTime(now);

      const cases = [
        { input: new Date('2024-01-01T11:59:30Z'), expected: 'just now' }, // 30 sec
        { input: new Date('2024-01-01T11:58:00Z'), expected: '2 minutes ago' }, // 2 min
        { input: new Date('2024-01-01T10:00:00Z'), expected: '2 hours ago' }, // 2 hr
        { input: new Date('2023-12-30T12:00:00Z'), expected: '2 days ago' }, // 2 days
        { input: new Date('2023-12-18T12:00:00Z'), expected: '2 weeks ago' }, // 2 weeks (14 days)
        { input: new Date('2023-11-01T12:00:00Z'), expected: '2 months ago' }, // ~61 days
      ];

      for (const { input, expected } of cases) {
        expect(formatRelativeTime(input)).toBe(expected);
      }

      vi.useRealTimers();
    });
  });
});

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

/**
 * Merge Tailwind CSS classes with proper precedence
 * @param inputs - Class values to merge
 * @returns Merged class string
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

/**
 * Check if a book belongs to the manga/comics domain
 */
export function isMangaDomain(book: any): boolean {
  if (book.domain) {
    return ['manga', 'comics', 'manga_comics', 'online-manga'].includes(book.domain);
  }
  const fmt = book.file_format?.toLowerCase() || '';
  // Support both "cbz" and ".cbz"
  return ['cbz', 'cbr', 'zip', '.cbz', '.cbr', '.zip', 'online-manga'].includes(fmt);
}

/**
 * Format file size to human readable format
 * @param bytes - File size in bytes
 * @returns Formatted string (e.g., "2.3 MB")
 */
export function formatFileSize(bytes: number): string {
  if (!bytes || isNaN(bytes) || bytes < 0) return '0 B'
  if (bytes === 0) return '0 B'
  const k = 1024
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`
}

/**
 * Format date to a readable string
 * @param date - Date string or Date object
 * @returns Formatted date string (e.g., "Jan 15, 2024")
 */
export function formatDate(date: string | Date): string {
  const d = new Date(date)
  return d.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric'
  })
}

/**
 * Format date to relative time (e.g., "2 days ago")
 * @param date - Date string or Date object
 * @returns Relative time string
 */
export function formatRelativeTime(date: string | Date): string {
  const now = new Date()
  const then = new Date(date)
  const diffMs = now.getTime() - then.getTime()
  const diffSec = Math.floor(diffMs / 1000)
  const diffMin = Math.floor(diffSec / 60)
  const diffHour = Math.floor(diffMin / 60)
  const diffDay = Math.floor(diffHour / 24)
  const diffWeek = Math.floor(diffDay / 7)
  const diffMonth = Math.floor(diffDay / 30)
  const diffYear = Math.floor(diffDay / 365)

  if (diffSec < 60) return 'just now'
  if (diffMin < 60) return `${diffMin} minute${diffMin > 1 ? 's' : ''} ago`
  if (diffHour < 24) return `${diffHour} hour${diffHour > 1 ? 's' : ''} ago`
  if (diffDay < 7) return `${diffDay} day${diffDay > 1 ? 's' : ''} ago`
  if (diffWeek < 4) return `${diffWeek} week${diffWeek > 1 ? 's' : ''} ago`
  if (diffMonth < 12) return `${diffMonth} month${diffMonth > 1 ? 's' : ''} ago`
  return `${diffYear} year${diffYear > 1 ? 's' : ''} ago`
}

/**
 * Debounce function execution
 * @param func - Function to debounce
 * @param wait - Wait time in milliseconds
 * @returns Debounced function
 */
export function debounce<T extends (...args: unknown[]) => void>(func: T, wait: number): T {
  let timeout: ReturnType<typeof setTimeout> | null = null

  return function executedFunction(...args: Parameters<T>) {
    const later = () => {
      timeout = null
      func(...args)
    }

    if (timeout !== null) {
      clearTimeout(timeout)
    }
    timeout = setTimeout(later, wait)
  } as T
}

/**
 * Truncate text to specified length
 * @param text - Text to truncate
 * @param length - Maximum length
 * @returns Truncated text with ellipsis
 */
export function truncate(text: string, length: number): string {
  if (text.length <= length) return text
  return text.slice(0, length) + '...'
}

/**
 * Check if running on macOS
 * @returns True if macOS
 */
export function isMac(): boolean {
  return typeof window !== 'undefined' && navigator.platform.toUpperCase().indexOf('MAC') >= 0
}

/**
 * Get keyboard shortcut display text
 * @param shortcut - Shortcut string (e.g., "cmd+k")
 * @returns Display text for current platform
 */
export function getShortcutDisplay(shortcut: string): string {
  const mac = isMac()
  return shortcut
    .replace('cmd', mac ? '⌘' : 'Ctrl')
    .replace('shift', mac ? '⇧' : 'Shift')
    .replace('alt', mac ? '⌥' : 'Alt')
    .replace('ctrl', mac ? '⌃' : 'Ctrl')
    .toUpperCase()
}

/**
 * Parse prefixed page URL payloads in the format "kind|url".
 * Defaults to kind "direct" when no prefix is present.
 */
export function parsePageUrl(raw: string): { kind: string; url: string } {
  const value = raw.trim()
  const delimiterIndex = value.indexOf('|')

  if (delimiterIndex === -1) {
    return { kind: 'direct', url: value }
  }

  const kind = value.slice(0, delimiterIndex).trim().toLowerCase() || 'direct'
  const url = value.slice(delimiterIndex + 1).trim()
  return { kind, url }
}

/**
 * Fetch wrapper with exponential backoff for rate limits and CORS errors (which often mask 429s)
 */
export async function fetchWithRetry(url: string, options: RequestInit = {}, retries = 3, backoff = 1000): Promise<Response> {
  try {
    const res = await fetch(url, options)
    if (res.status === 429 && retries > 0) {
      console.warn(`Rate limited (429) fetching ${url}. Retrying in ${backoff}ms...`)
      await new Promise(r => setTimeout(r, backoff))
      return fetchWithRetry(url, options, retries - 1, backoff * 2)
    }
    return res
  } catch (err) {
    if (retries > 0) {
      console.warn(`Fetch error (possibly CORS masking a 429) for ${url}. Retrying in ${backoff}ms...`, err)
      await new Promise(r => setTimeout(r, backoff))
      return fetchWithRetry(url, options, retries - 1, backoff * 2)
    }
    throw err
  }
}

import { create } from "zustand";
import { api, isTauri } from "../lib/tauri";
import { invoke } from "@tauri-apps/api/core";

import { logger } from "../lib/logger";
import type {
  UserPreferences,
  BookPreferences,
  MangaPreferences,
  TtsPreferences,
  Theme,
} from "../types/preferences";
import { DEFAULT_USER_PREFERENCES } from "../types/preferences";

const themeMap: Record<string, string> = { light: 'white', dark: 'black' };

interface PreferencesStore {
  // State
  preferences: UserPreferences | null;
  bookOverrides: Map<number, Partial<BookPreferences>>;
  mangaOverrides: Map<number, Partial<MangaPreferences>>;
  isLoaded: boolean;
  isLoading: boolean;
  _cachedOnboardingCompleted?: boolean;

  // Actions
  loadPreferences: () => Promise<void>;
  updateTheme: (theme: Theme) => Promise<void>;
  updateBookDefaults: (updates: Partial<BookPreferences>) => Promise<void>;
  updateMangaDefaults: (updates: Partial<MangaPreferences>) => Promise<void>;
  updateTtsDefaults: (updates: Partial<TtsPreferences>) => Promise<void>;
  updateGeneralSettings: (updates: Partial<UserPreferences>) => Promise<void>;

  // Per-book overrides
  setBookOverride: (
    bookId: number,
    overrides: Partial<BookPreferences>
  ) => Promise<void>;
  clearBookOverride: (bookId: number) => Promise<void>;
  getBookPreferences: (bookId: number) => BookPreferences;

  // Per-manga overrides
  setMangaOverride: (
    bookId: number,
    overrides: Partial<MangaPreferences>
  ) => Promise<void>;
  clearMangaOverride: (bookId: number) => Promise<void>;
  getMangaPreferences: (bookId: number) => MangaPreferences;

  // Reset
  reset: () => void;
}

export const usePreferencesStore = create<PreferencesStore>((set, get) => ({
  // Initial state
  preferences: null,
  bookOverrides: new Map(),
  mangaOverrides: new Map(),
  isLoaded: false,
  isLoading: false,

  // Load all preferences from backend — single IPC call returns everything
  loadPreferences: async () => {
    set({ isLoading: true });
    try {
      // One IPC call returns preferences + both override tables + onboarding + reading goal.
      // Previously this was 4 separate invoke() calls run sequentially in onboardingStore.
      let startup;
      if (!isTauri) {
        logger.warn("Running in browser mode - using mock startup data");
        startup = {
          preferences: { ...DEFAULT_USER_PREFERENCES },
          bookOverrides: [],
          mangaOverrides: [],
          onboarding: { completed: true },
          readingGoalMinutes: null
        };
      } else {
        startup = await invoke<{
          preferences: UserPreferences & { dailyReadingGoalMinutes?: number }
          bookOverrides: Array<{ bookId: number; preferences: Record<string, unknown> }>
          mangaOverrides: Array<{ bookId: number; preferences: Record<string, unknown> }>
          onboarding: { completed: boolean }
          readingGoalMinutes: number | null
        }>('get_startup_data');
      }

      const preferences = startup.preferences;

      // Merge reading goal
      if (startup.readingGoalMinutes != null) {
        preferences.dailyReadingGoalMinutes = startup.readingGoalMinutes;
      }

      const bookOverrideMap = new Map(
        startup.bookOverrides.map((o) => [o.bookId, o.preferences as Partial<BookPreferences>])
      );

      const mangaOverrideMap = new Map(
        startup.mangaOverrides.map((o) => [o.bookId, o.preferences as Partial<MangaPreferences>])
      );

      set({
        preferences,
        bookOverrides: bookOverrideMap,
        mangaOverrides: mangaOverrideMap,
        isLoaded: true,
        isLoading: false,
        // Cache onboarding result so onboardingStore can read it without a second IPC call
        _cachedOnboardingCompleted: startup.onboarding.completed,
      });

      // Apply theme and scale to DOM
      document.documentElement.setAttribute("data-theme", themeMap[preferences.theme] ?? preferences.theme);
      if (preferences.theme === 'dark') {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      const scale = preferences.uiScale ?? 1.0;
      document.documentElement.style.setProperty('--ui-scale', String(scale));
    } catch (error) {
      logger.error("Failed to load preferences:", error);
      set({ isLoading: false });
    }
  },


  // Update theme (with optimistic update)
  updateTheme: async (theme: Theme) => {
    const previousTheme = get().preferences?.theme;

    // Optimistic update
    set((state) => ({
      preferences: state.preferences
        ? { ...state.preferences, theme }
        : DEFAULT_USER_PREFERENCES,
    }));
    document.documentElement.setAttribute("data-theme", themeMap[theme] ?? theme);
    // Also toggle 'dark' class for Tailwind dark: variants
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }

    try {
      await api.updateUserPreferences({ theme });
    } catch (error) {
      logger.error("Failed to update theme:", error);
      // Rollback
      if (previousTheme) {
        set((state) => ({
          preferences: state.preferences
            ? { ...state.preferences, theme: previousTheme }
            : DEFAULT_USER_PREFERENCES,
        }));
        document.documentElement.setAttribute("data-theme", themeMap[previousTheme] ?? previousTheme);
        // Also rollback 'dark' class
        if (previousTheme === 'dark') {
          document.documentElement.classList.add('dark');
        } else {
          document.documentElement.classList.remove('dark');
        }
      }
    }
  },

  // Update book defaults
  updateBookDefaults: async (updates: Partial<BookPreferences>) => {
    const previous = get().preferences?.book;

    // Optimistic update
    set((state) => ({
      preferences: state.preferences
        ? {
          ...state.preferences,
          book: { ...state.preferences.book, ...updates },
        }
        : DEFAULT_USER_PREFERENCES,
    }));

    try {
      await api.updateUserPreferences({
        book: { ...get().preferences!.book, ...updates },
      });
    } catch (error) {
      logger.error("Failed to update book preferences:", error);
      // Rollback
      if (previous) {
        set((state) => ({
          preferences: state.preferences
            ? { ...state.preferences, book: previous }
            : DEFAULT_USER_PREFERENCES,
        }));
      }
    }
  },

  // Update manga defaults
  updateMangaDefaults: async (updates: Partial<MangaPreferences>) => {
    const previous = get().preferences?.manga;

    // Optimistic update
    set((state) => ({
      preferences: state.preferences
        ? {
          ...state.preferences,
          manga: { ...state.preferences.manga, ...updates },
        }
        : DEFAULT_USER_PREFERENCES,
    }));

    try {
      await api.updateUserPreferences({
        manga: { ...get().preferences!.manga, ...updates },
      });
    } catch (error) {
      logger.error("Failed to update manga preferences:", error);
      // Rollback
      if (previous) {
        set((state) => ({
          preferences: state.preferences
            ? { ...state.preferences, manga: previous }
            : DEFAULT_USER_PREFERENCES,
        }));
      }
    }
  },

  updateTtsDefaults: async (updates: Partial<TtsPreferences>) => {
    const previous = get().preferences?.tts;

    set((state) => ({
      preferences: state.preferences
        ? {
          ...state.preferences,
          tts: { ...state.preferences.tts, ...updates },
        }
        : DEFAULT_USER_PREFERENCES,
    }));

    try {
      await api.updateUserPreferences({
        tts: { ...get().preferences!.tts, ...updates },
      });
    } catch (error) {
      logger.error("Failed to update TTS preferences:", error);
      if (previous) {
        set((state) => ({
          preferences: state.preferences
            ? { ...state.preferences, tts: previous }
            : DEFAULT_USER_PREFERENCES,
        }));
      }
    }
  },

  // Update general settings
  updateGeneralSettings: async (updates) => {
    const previous = get().preferences;

    // Optimistic update
    set((state) => ({
      preferences: state.preferences
        ? { ...state.preferences, ...updates }
        : DEFAULT_USER_PREFERENCES,
    }));

    // Immediately apply ui_scale to CSS if provided (real-time preview)
    if ('uiScale' in updates && updates.uiScale !== undefined) {
      const scale = updates.uiScale;
      document.documentElement.style.setProperty('--ui-scale', String(scale));
    }

    try {
      await api.updateUserPreferences(updates);
    } catch (error) {
      logger.error("Failed to update general settings:", error);
      // Rollback
      if (previous) {
        set({ preferences: previous });
        const prevScale = previous.uiScale ?? 1.0;
        document.documentElement.style.setProperty('--ui-scale', String(prevScale));
      }
    }
  },

  // Set book-specific override
  setBookOverride: async (bookId: number, overrides: Partial<BookPreferences>) => {
    const previous = get().bookOverrides.get(bookId);

    // Optimistic update
    set((state) => {
      const newOverrides = new Map(state.bookOverrides);
      newOverrides.set(bookId, overrides);
      return { bookOverrides: newOverrides };
    });

    try {
      await api.setBookPreferenceOverride(bookId, overrides);
    } catch (error) {
      logger.error("Failed to set book override:", error);
      // Rollback
      set((state) => {
        const newOverrides = new Map(state.bookOverrides);
        if (previous) {
          newOverrides.set(bookId, previous);
        } else {
          newOverrides.delete(bookId);
        }
        return { bookOverrides: newOverrides };
      });
    }
  },

  // Clear book-specific override
  clearBookOverride: async (bookId: number) => {
    const previous = get().bookOverrides.get(bookId);

    // Optimistic update
    set((state) => {
      const newOverrides = new Map(state.bookOverrides);
      newOverrides.delete(bookId);
      return { bookOverrides: newOverrides };
    });

    try {
      await api.clearBookPreferenceOverride(bookId);
    } catch (error) {
      logger.error("Failed to clear book override:", error);
      // Rollback
      if (previous) {
        set((state) => {
          const newOverrides = new Map(state.bookOverrides);
          newOverrides.set(bookId, previous);
          return { bookOverrides: newOverrides };
        });
      }
    }
  },

  // Get merged book preferences (defaults + overrides)
  getBookPreferences: (bookId: number): BookPreferences => {
    const defaults = get().preferences?.book ?? DEFAULT_USER_PREFERENCES.book;
    const overrides = get().bookOverrides.get(bookId) ?? {};
    return { ...defaults, ...overrides };
  },

  // Set manga-specific override
  setMangaOverride: async (bookId: number, overrides: Partial<MangaPreferences>) => {
    const previous = get().mangaOverrides.get(bookId);

    // Optimistic update
    set((state) => {
      const newOverrides = new Map(state.mangaOverrides);
      newOverrides.set(bookId, overrides);
      return { mangaOverrides: newOverrides };
    });

    try {
      await api.setMangaPreferenceOverride(bookId, overrides);
    } catch (error) {
      logger.error("Failed to set manga override:", error);
      // Rollback
      set((state) => {
        const newOverrides = new Map(state.mangaOverrides);
        if (previous) {
          newOverrides.set(bookId, previous);
        } else {
          newOverrides.delete(bookId);
        }
        return { mangaOverrides: newOverrides };
      });
    }
  },

  // Clear manga-specific override
  clearMangaOverride: async (bookId: number) => {
    const previous = get().mangaOverrides.get(bookId);

    // Optimistic update
    set((state) => {
      const newOverrides = new Map(state.mangaOverrides);
      newOverrides.delete(bookId);
      return { mangaOverrides: newOverrides };
    });

    try {
      await api.clearMangaPreferenceOverride(bookId);
    } catch (error) {
      logger.error("Failed to clear manga override:", error);
      // Rollback
      if (previous) {
        set((state) => {
          const newOverrides = new Map(state.mangaOverrides);
          newOverrides.set(bookId, previous);
          return { mangaOverrides: newOverrides };
        });
      }
    }
  },

  // Get merged manga preferences (defaults + overrides)
  getMangaPreferences: (bookId: number): MangaPreferences => {
    const defaults = get().preferences?.manga ?? DEFAULT_USER_PREFERENCES.manga;
    const overrides = get().mangaOverrides.get(bookId) ?? {};
    return { ...defaults, ...overrides };
  },

  // Reset to defaults
  reset: () => {
    set({
      preferences: null,
      bookOverrides: new Map(),
      mangaOverrides: new Map(),
      isLoaded: false,
      isLoading: false,
    });
  },
}));

